export default (ctx) => ({
    plugins: {
        ...(ctx.file && ctx.file.endsWith('.module.css') ? {} : { '@tailwindcss/postcss': {} }),
    },
});

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const searchPatterns = [
    'skeleton-highlight',
    '120deg',
    '-:|',
    'bg-[',
    'linear-gradient'
];

function searchFile(filePath) {
    if (filePath.includes('scan_error.mjs') || filePath.includes('scan_error.js')) return;
    try {
        const content = fs.readFileSync(filePath, 'utf8');
        for (const pattern of searchPatterns) {
            if (content.includes(pattern)) {
                // Log match
                console.log(`MATCH: "${filePath}" contains "${pattern}"`);
                // If exact match of weird char
                if (pattern === '-:|') {
                    console.log('!!! CRITICAL MATCH !!!');
                }
            }
        }
    } catch (e) { }
}

function walkDir(dir) {
    try {
        const files = fs.readdirSync(dir);
        for (const file of files) {
            const filePath = path.join(dir, file);
            const stat = fs.statSync(filePath);
            if (stat.isDirectory()) {
                if (file !== 'node_modules' && file !== '.next' && file !== '.git') {
                    walkDir(filePath);
                }
            } else {
                if (['.tsx', '.ts', '.css', '.jsx', '.js', '.mjs'].includes(path.extname(file))) {
                    searchFile(filePath);
                }
            }
        }
    } catch (e) { }
}

console.log('--- START SCAN ---');
walkDir('.');
// Explicitly check .temp_ag_kit if it exists at root or wherever
if (fs.existsSync('.temp_ag_kit')) {
    walkDir('.temp_ag_kit');
}
console.log('--- END SCAN ---');

const path = require('path');
const dotenv = require('dotenv');

const envPath = path.join(__dirname, '..', '.env.local');
dotenv.config({ path: envPath });

console.log('APP_URL:', process.env.NEXT_PUBLIC_APP_URL);

const fs = require('fs');
const path = require('path');

async function checkSetup() {
    console.log('\x1b[36m%s\x1b[0m', '🔍 Verificando configuração do ambiente...\n');

    // 1. Check .env.local
    const envPath = path.join(__dirname, '..', '.env.local');
    if (!fs.existsSync(envPath)) {
        console.error('\x1b[31m%s\x1b[0m', '❌ Arquivo .env.local não encontrado!');
        return;
    }

    const envContent = fs.readFileSync(envPath, 'utf8');
    const getEnv = (key) => {
        const match = envContent.match(new RegExp(`^${key}=(.*)`, 'm'));
        return match ? match[1].trim() : null;
    };

    const requiredVars = [
        'NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY',
        'STRIPE_SECRET_KEY',
        'STRIPE_WEBHOOK_SECRET',
        'NEXT_PUBLIC_STRIPE_PRICE_BASIC',
        'NEXT_PUBLIC_STRIPE_PRICE_PROFESSIONAL',
        'NEXT_PUBLIC_STRIPE_PRICE_ENTERPRISE',
        'NEXT_PUBLIC_SUPABASE_URL',
        'NEXT_PUBLIC_SUPABASE_ANON_KEY',
        'SUPABASE_SERVICE_ROLE_KEY'
    ];

    let hasErrors = false;

    requiredVars.forEach(key => {
        const value = getEnv(key);
        if (!value) {
            console.error('\x1b[31m%s\x1b[0m', `❌ ${key} está faltando`);
            hasErrors = true;
        } else {
            // Basic validation
            if (key.includes('PRICE') && !value.startsWith('price_')) {
                console.warn('\x1b[33m%s\x1b[0m', `⚠️ ${key} parece inválido (deveria começar com 'price_')`);
            }
            if (key.includes('SECRET_KEY') && !value.startsWith('sk_')) {
                console.warn('\x1b[33m%s\x1b[0m', `⚠️ ${key} parece inválido (deveria começar com 'sk_')`);
            }
            console.log('\x1b[32m%s\x1b[0m', `✅ ${key} encontrado`);
        }
    });

    if (hasErrors) {
        console.log('\n\x1b[31m%s\x1b[0m', '⚠️  Por favor, corrija as variáveis faltando no arquivo .env.local');
    } else {
        console.log('\n\x1b[32m%s\x1b[0m', '✅ Todas as variáveis necessárias estão presentes!');
    }

    console.log('\n\x1b[36m%s\x1b[0m', '📝 Para sincronizar o Stripe localmente (Webhooks):');
    console.log('1. Abra um novo terminal');
    console.log('2. Execute: stripe login');
    console.log('3. Execute: stripe listen --forward-to localhost:3000/api/stripe/webhook');
    console.log('4. Copie a chave de assinatura (whsec_...) exibida');
    console.log('5. Atualize STRIPE_WEBHOOK_SECRET no seu .env.local com essa chave');
    console.log('6. Reinicie o servidor do projeto (npm run dev)');
}

checkSetup();

const fs = require('fs');
const path = require('path');

const envPath = path.join(__dirname, '../.env.local');

try {
    const envContent = fs.readFileSync(envPath, 'utf8');
    const lines = envContent.split('\n');

    console.log('--- Stripe Configuration Check ---');
    let webhookSecretFound = false;

    lines.forEach(line => {
        if (line.includes('STRIPE_WEBHOOK_SECRET')) {
            webhookSecretFound = true;
            const parts = line.split('=');
            if (parts.length > 1) {
                const val = parts[1].trim();
                console.log(`STRIPE_WEBHOOK_SECRET=${val.substring(0, 5)}...`);
            }
        }
    });

    if (!webhookSecretFound) {
        console.log('❌ STRIPE_WEBHOOK_SECRET missing in .env.local');
    } else {
        console.log('✅ STRIPE_WEBHOOK_SECRET is present');
    }

} catch (error) {
    console.error('Error reading .env.local:', error.message);
}

const fs = require('fs');
const path = require('path');

const envPath = path.join(__dirname, '..', '.env.local');

try {
    let content = fs.readFileSync(envPath, 'utf8');

    console.log('Checking .env.local for corruption...');

    // Check if NEXT_PUBLIC_APP_URL follows another variable without a newline
    // Regex looks for a character that is not a newline, followed immediately by NEXT_PUBLIC_APP_URL
    const corruptionRegex = /([^\r\n])(NEXT_PUBLIC_APP_URL=)/;

    if (corruptionRegex.test(content)) {
        console.log('Corruption detected! Fixing...');

        // Add a newline before NEXT_PUBLIC_APP_URL
        const fixedContent = content.replace(corruptionRegex, '$1\n$2');

        fs.writeFileSync(envPath, fixedContent);
        console.log('✅ File repaired successfully.');
        console.log('New content snippet:');
        const match = fixedContent.match(/.*NEXT_PUBLIC_APP_URL=.*/);
        if (match) console.log(match[0]);

    } else {
        console.log('No specific corruption pattern detected. The file might be okay or corrupted differently.');
    }

} catch (err) {
    console.error('Error processing file:', err);
}

const Stripe = require('stripe');
const path = require('path');
const dotenv = require('dotenv');

// Load .env.local
const envPath = path.join(__dirname, '..', '.env.local');
dotenv.config({ path: envPath });

const STRIPE_SECRET_KEY = process.env.STRIPE_SECRET_KEY;

if (!STRIPE_SECRET_KEY) {
    console.error('❌ STRIPE_SECRET_KEY not found in .env.local');
    process.exit(1);
}

const stripe = new Stripe(STRIPE_SECRET_KEY);

const PLANS = [
    {
        name: 'Basic', // Try to match existing names if possible, but these seem standard
        id_keyword: 'basic',
        amount: 4990, // R$ 49,90
    },
    {
        name: 'Professional',
        id_keyword: 'professional',
        amount: 7990, // R$ 79,90
    },
    {
        name: 'Enterprise',
        id_keyword: 'enterprise',
        amount: 14990, // R$ 149,90
    }
];

async function main() {
    console.log('Starting Stripe Product/Price Setup...');

    const results = {};

    for (const plan of PLANS) {
        console.log(`\nProcessing ${plan.name}...`);

        // 1. Search for existing Product
        let product;
        const products = await stripe.products.search({
            query: `name~'${plan.name}' AND active:'true'`,
        });

        if (products.data.length > 0) {
            product = products.data[0];
            console.log(`Found existing product: ${product.name} (${product.id})`);
        } else {
            product = await stripe.products.create({
                name: plan.name,
                description: `Plano ${plan.name} - Ligeirinho Hotdog`,
            });
            console.log(`Created new product: ${product.name} (${product.id})`);
        }

        // 2. Search for existing Recurring Price
        let price;
        const prices = await stripe.prices.list({
            product: product.id,
            active: true,
            type: 'recurring',
            limit: 100,
        });

        // specific amount matching
        price = prices.data.find(p => p.unit_amount === plan.amount && p.currency === 'brl' && p.recurring.interval === 'month');

        if (price) {
            console.log(`Found existing price: ${price.id} (R$ ${price.unit_amount / 100})`);
        } else {
            price = await stripe.prices.create({
                product: product.id,
                unit_amount: plan.amount,
                currency: 'brl',
                recurring: {
                    interval: 'month',
                },
                nickname: plan.name,
            });
            console.log(`Created new price: ${price.id} (R$ ${price.unit_amount / 100})`);
        }

        results[plan.id_keyword] = price.id;
    }

    console.log('\n\n==================================================');
    console.log('COPY THESE LINES TO YOUR .env.local FILE:');
    console.log('==================================================');
    console.log(`NEXT_PUBLIC_STRIPE_PRICE_BASIC=${results.basic}`);
    console.log(`NEXT_PUBLIC_STRIPE_PRICE_PROFESSIONAL=${results.professional}`);
    console.log(`NEXT_PUBLIC_STRIPE_PRICE_ENTERPRISE=${results.enterprise}`);
    console.log('==================================================');
}

main().catch(console.error);

const fs = require('fs');
const path = require('path');
const dotenv = require('dotenv');

// Load .env.local
const envPath = path.join(__dirname, '..', '.env.local');
const envConfig = dotenv.config({ path: envPath });

if (envConfig.error) {
    console.error('Er o ao carregar .env.local');
    process.exit(1);
}

const secretKey = process.env.STRIPE_SECRET_KEY;
if (!secretKey || secretKey.includes('sk_test_...')) {
    console.error('❌ STRIPE_SECRET_KEY inválida ou não encontrada em .env.local');
    console.error('Por favor, adicione suas chaves do Stripe no arquivo .env.local');
    process.exit(1);
}

const stripe = require('stripe')(secretKey);

const PRODUCTS = [
    {
        name: 'Basic',
        description: 'Plano ideal para pequenos negócios: dashboard, pedidos, produtos e categorias.',
        price: 4990, // cents
        features: ['Dashboard', 'Pedidos', 'Produtos']
    },
    {
        name: 'Professional',
        description: 'Recursos avançados: gestão de estoque, entregas, cozinha e fidelidade.',
        price: 7990,
        features: ['Estoque', 'Entregas', 'Cozinha', 'Fidelidade']
    },
    {
        name: 'Enterprise',
        description: 'Solução completa: todos os recursos + relatórios avançados e multiplas lojas.',
        price: 14990,
        features: ['Relatórios Avançados', 'Multi-lojas']
    }
];

async function setup() {
    console.log('🚀 Iniciando configuração do Stripe...');

    const newEnvLines = [];

    for (const plan of PRODUCTS) {
        console.log(`\nConfigurando plano ${plan.name}...`);

        // Check if product exists (simple check by name to avoid duplicates if re-run)
        const search = await stripe.products.search({
            query: `name:'${plan.name}'`,
        });

        let productId;
        let product;

        if (search.data.length > 0) {
            console.log(`✅ Produto ${plan.name} já existe: ${search.data[0].id}`);
            product = search.data[0];
            productId = product.id;
        } else {
            product = await stripe.products.create({
                name: plan.name,
                description: plan.description,
            });
            console.log(`✅ Produto ${plan.name} criado: ${product.id}`);
            productId = product.id;
        }

        // Create Price
        // We want a recurring monthly price
        // Check if a price with this amount and recurring exists
        const prices = await stripe.prices.list({
            product: productId,
            active: true,
            limit: 10,
        });

        let priceId;
        const existingPrice = prices.data.find(p =>
            p.unit_amount === plan.price &&
            p.recurring?.interval === 'month' &&
            p.currency === 'brl'
        );

        if (existingPrice) {
            console.log(`✅ Preço já existe: ${existingPrice.id}`);
            priceId = existingPrice.id;
        } else {
            const price = await stripe.prices.create({
                product: productId,
                unit_amount: plan.price,
                currency: 'brl',
                recurring: {
                    interval: 'month',
                },
            });
            console.log(`✅ Preço criado: ${price.id}`);
            priceId = price.id;
        }

        const envVarName = `NEXT_PUBLIC_STRIPE_PRICE_${plan.name.toUpperCase()}`;
        newEnvLines.push(`${envVarName}=${priceId}`);
    }

    console.log('\n----------------------------------------');
    console.log('📝 Adicione as seguintes linhas ao seu .env.local:');
    console.log('----------------------------------------');
    console.log(newEnvLines.join('\n'));
    console.log('----------------------------------------');

    // Attempt to verify if they are already in file
    const currentEnv = fs.readFileSync(envPath, 'utf8');
    let updatedEnv = currentEnv;
    let madeChanges = false;

    newEnvLines.forEach(line => {
        const [key, value] = line.split('=');
        if (updatedEnv.includes(key)) {
            // Replace existing
            const regex = new RegExp(`${key}=.*`);
            const match = updatedEnv.match(regex);
            if (match && match[0] !== line) {
                updatedEnv = updatedEnv.replace(regex, line);
                madeChanges = true;
            }
        } else {
            updatedEnv += `\n${line}`;
            madeChanges = true;
        }
    });

    if (madeChanges) {
        fs.writeFileSync(envPath, updatedEnv);
        console.log('✅ Arquivo .env.local atualizado automaticamente!');
    } else {
        console.log('✅ Arquivo .env.local já está atualizado.');
    }
}

setup().catch(err => {
    console.error('Erro na configuração:', err);
});

const fs = require('fs');
const path = require('path');
const readline = require('readline');

const envPath = path.join(__dirname, '..', '.env.local');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function getEnvValue(content, key) {
    const regex = new RegExp(`${key}=(.*)`);
    const match = content.match(regex);
    return match ? match[1].trim() : null;
}

function updateEnvFile(key, value) {
    let content = fs.existsSync(envPath) ? fs.readFileSync(envPath, 'utf8') : '';

    if (content.includes(key)) {
        const regex = new RegExp(`${key}=.*`);
        content = content.replace(regex, `${key}=${value}`);
    } else {
        content += `\n${key}=${value}\n`;
    }

    fs.writeFileSync(envPath, content);
    console.log(`✅ ${key} updated in .env.local`);
}

async function main() {
    console.log('🔧 Stripe Webhook Setup Helper');
    console.log('--------------------------------');

    if (!fs.existsSync(envPath)) {
        console.error('❌ .env.local not found!');
        process.exit(1);
    }

    const envContent = fs.readFileSync(envPath, 'utf8');
    const currentSecret = getEnvValue(envContent, 'STRIPE_WEBHOOK_SECRET');

    if (currentSecret) {
        console.log('✅ STRIPE_WEBHOOK_SECRET is already set.');
        console.log(`Current value: ${currentSecret.substring(0, 10)}...`);

        rl.question('Do you want to overwrite it? (y/n) ', (answer) => {
            if (answer.toLowerCase() === 'y') {
                askForSecret();
            } else {
                console.log('Exiting...');
                rl.close();
            }
        });
    } else {
        console.log('❌ STRIPE_WEBHOOK_SECRET is missing.');
        askForSecret();
    }
}

function askForSecret() {
    console.log('\nTo get your Webhook Secret:');
    console.log('1. Ensure Stripe CLI is installed.');
    console.log('2. Run: stripe listen --forward-to localhost:3000/api/stripe/webhook');
    console.log('3. Copy the "whsec_..." secret shown in the output.');
    console.log('\n(If you cannot install CLI, you cannot assume webhooks will work on localhost easily without a tunnel like ngrok)');

    rl.question('\nPaste your Stripe Webhook Secret (whsec_...): ', (secret) => {
        if (!secret || !secret.startsWith('whsec_')) {
            console.error('❌ Invalid format. Should start with "whsec_"');
            rl.close();
            return;
        }

        updateEnvFile('STRIPE_WEBHOOK_SECRET', secret.trim());
        console.log('\n🎉 Configuration updated! Please restart your dev server.');
        rl.close();
    });
}

main();

const { config } = require('dotenv');
config({ path: '.env.local' });

// Precisamos simular Next.js cache para carregar as actions fora do Next, mas uma vez que actions dependem do ambiente next, talvez seja melhor fazer a chamada via require normal.
// Para evitar problemas de module import, faremos via API fetch se existisse, mas não existe, é server action.

const { createClient } = require('@supabase/supabase-js');
const { config } = require('dotenv');

config({ path: '.env.local' });

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!supabaseUrl || !supabaseKey) {
    console.error("Missing keys");
    process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseKey);

async function main() {
    const userId = 'e3c65606-f8a2-4322-b56f-5893be4b2a13';
    const now = new Date();
    const endDate = new Date(now);
    endDate.setMonth(endDate.getMonth() + 1);

    const plan = {
        name: 'Básico',
        billing_interval: 'monthly',
        price_cents: 1000
    };

    const mapPlanType = (name) => {
        const n = name.toLowerCase();
        if (n.includes('basico') || n.includes('básico')) return 'Basico';
        if (n.includes('avancado') || n.includes('avançado')) return 'Avançado';
        if (n.includes('profissional')) return 'Profissional';
        return 'Basico';
    };

    const subData = {
        user_id: userId,
        plan_type: mapPlanType(plan.name),
        status: 'active',
        billing_period: plan.billing_interval || 'monthly',
        current_period_start: now.toISOString(),
        current_period_end: endDate.toISOString(),
        updated_at: now.toISOString(),
        payment_method: 'manual',
    };

    console.log("Trying to upsert subscriptions:", subData);
    const { error: subError } = await supabase.from('subscriptions').upsert(subData, { onConflict: 'user_id' });
    if (subError) {
        console.log("SubError:", subError);
    }

    console.log("Trying to update/insert subscriptions_cache");
    const { data: existingCache } = await supabase
        .from('subscriptions_cache')
        .select('id')
        .eq('tenant_id', userId)
        .maybeSingle();

    if (existingCache) {
        console.log("existing cache found", existingCache);
        const { error: cacheError } = await supabase
            .from('subscriptions_cache')
            .update({
                plan_name: plan.name,
                status: 'active',
                amount_cents: plan.price_cents,
                current_period_end: endDate.toISOString(),
            })
            .eq('id', existingCache.id);
        if (cacheError) console.log("Cache update error:", cacheError);
    } else {
        console.log("no existing cache, inserting...");
        const { error: cacheError } = await supabase
            .from('subscriptions_cache')
            .insert({
                id: `manual_${userId}`,
                tenant_id: userId,
                user_id: userId,
                plan_name: plan.name,
                status: 'active',
                amount_cents: plan.price_cents,
                current_period_end: endDate.toISOString(),
            });
        if (cacheError) console.log("Cache insert error:", cacheError);
    }
}

main();

'use server';

import { stripe } from '@/lib/stripe';
import { supabaseAdmin } from '@/lib/supabase-admin';
import { revalidatePath } from 'next/cache';

interface UpdatePlanParams {
    userId: string;
    planId: string; // The internal UUID from subscription_plans table
    periodEnd?: string;
}

export async function updateClientPlan({ userId, planId, periodEnd }: UpdatePlanParams) {
    try {
        console.log(`[ManagePlan] Updating plan for user ${userId} to plan ${planId}`);

        // 1. Fetch the Target Plan Details
        const { data: targetPlan, error: planError } = await supabaseAdmin
            .from('subscription_plans')
            .select('*')
            .eq('id', planId)
            .single();

        if (planError || !targetPlan) {
            return { success: false, error: `Plan not found: ${planError?.message}` };
        }

        // 2. Fetch User's Current Subscription (to check if it's Stripe or Manual)
        const { data: currentSub, error: subError } = await supabaseAdmin
            .from('subscriptions')
            .select('*')
            .eq('user_id', userId)
            .maybeSingle();

        if (subError) {
            return { success: false, error: `Error fetching subscription: ${subError.message}` };
        }

        let stripeSubscriptionId = currentSub?.stripe_subscription_id;
        let paymentMethod = currentSub?.payment_method || 'manual';

        // 3. Logic: If Stripe, update Stripe. If Manual, just update DB.
        if (stripeSubscriptionId && targetPlan.stripe_price_id) {
            try {
                console.log(`[ManagePlan] Updating Stripe Subscription ${stripeSubscriptionId}...`);

                // Get current subscription items to know what to delete/update
                const stripeSub = await stripe.subscriptions.retrieve(stripeSubscriptionId);
                const itemId = stripeSub.items.data[0].id;

                // Update Subscription in Stripe
                await stripe.subscriptions.update(stripeSubscriptionId, {
                    items: [{
                        id: itemId,
                        price: targetPlan.stripe_price_id,
                    }],
                    metadata: {
                        plan_type: targetPlan.name // Sync metadata
                    }
                });

                paymentMethod = 'card'; // Assumed if on Stripe
            } catch (stripeError) {
                console.error('[ManagePlan] Stripe Error:', stripeError);
                return { success: false, error: `Stripe Update Failed: ${stripeError instanceof Error ? stripeError.message : 'Unknown'}` };
            }
        }

        // 4. Update Supabase 'subscriptions' table (The App's Source of Truth)
        // Map Plan Name to Enum
        const mapPlanType = (name: string): 'Basico' | 'Avançado' | 'Profissional' => {
            const n = name.toLowerCase();
            if (n.includes('basico') || n.includes('básico')) return 'Basico';
            if (n.includes('avancado') || n.includes('avançado')) return 'Avançado';
            if (n.includes('profissional')) return 'Profissional';
            return 'Basico';
        };

        const planType = mapPlanType(targetPlan.name);

        // Calculate dates
        const now = new Date();
        const endDate = periodEnd ? new Date(periodEnd) : new Date(now.setMonth(now.getMonth() + 1));

        const subData = {
            user_id: userId,
            plan_type: planType,
            status: 'active',
            billing_period: targetPlan.billing_interval || 'monthly',
            current_period_start: new Date().toISOString(), // Reset period on change
            current_period_end: endDate.toISOString(),
            updated_at: new Date().toISOString(),
            payment_method: paymentMethod,
            // Only update stripe fields if we actually have them from the target plan
            ...(targetPlan.stripe_price_id ? { stripe_price_id: targetPlan.stripe_price_id } : {})
        };

        const { error: upsertError } = await supabaseAdmin
            .from('subscriptions')
            .upsert(subData, { onConflict: 'user_id' });

        if (upsertError) return { success: false, error: `Failed saving to Supabase: ${upsertError.message}` };

        // 5. Update 'subscriptions_cache' (The Admin Dashboard View)
        const cacheData = {
            tenant_id: userId,
            plan_name: targetPlan.name,
            status: 'active',
            amount_cents: targetPlan.price_cents,
            // mrr_cents is not a column, logic is calculated on frontend/view
            current_period_end: endDate.toISOString(),
            updated_at: new Date().toISOString()
        };

        const { error: cacheError } = await supabaseAdmin
            .from('subscriptions_cache')
            .upsert(cacheData, { onConflict: 'tenant_id' });

        if (cacheError) return { success: false, error: `Failed to update view cache: ${cacheError.message}` };

        revalidatePath('/admin/clients');
        return { success: true };

    } catch (error) {
        console.error('[ManagePlan] Critical Error:', error);
        return { success: false, error: error instanceof Error ? error.message : 'Unknown Server Error' };
    }
}

export async function updateClientFeatureFlags(userId: string, flags: Record<string, boolean>) {
    try {
        const upserts = Object.entries(flags).map(([feature_key, enabled]) => ({
            tenant_id: userId,
            feature_key,
            enabled,
            updated_at: new Date().toISOString()
        }));

        const { error } = await supabaseAdmin
            .from('tenant_feature_flags')
            .upsert(upserts, { onConflict: 'tenant_id,feature_key' });

        if (error) return { success: false, error: error.message };

        revalidatePath('/admin/clients');
        return { success: true };
    } catch (error) {
        console.error('[ManageFeatures] Error:', error);
        return { success: false, error: error instanceof Error ? error.message : 'Unknown Server Error' };
    }
}

'use client';

import React, { useState, useMemo } from 'react';
import { FiCreditCard, FiSmartphone } from 'react-icons/fi';
import { BsCash } from 'react-icons/bs';
import Card from '@/components/ui/Card';
import { useAuth } from '@/contexts/AuthContext';
import { formatCurrency } from '@/hooks/useFormatters';
import { useOrdersCache } from '@/hooks/useDataCache';

interface DaySummary {
    totalOrders: number;
    totalRevenue: number;
    paidOrders: number;
    pendingPayments: number;
    byMethod: { money: number; pix: number; credit: number; debit: number; };
}

export default function CaixaPage() {
    const { user } = useAuth();
    const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
    const { orders, loading } = useOrdersCache({ date: selectedDate });

    const summary = useMemo<DaySummary>(() => {
        if (!orders) return {
            totalOrders: 0, totalRevenue: 0, paidOrders: 0, pendingPayments: 0,
            byMethod: { money: 0, pix: 0, credit: 0, debit: 0 }
        };

        const startDate = new Date(`${selectedDate}T00:00:00`).getTime();
        const endDate = new Date(`${selectedDate}T23:59:59.999`).getTime();

        const filteredOrders = orders.filter(o => {
            const createdAt = new Date(o.created_at || 0).getTime();
            return createdAt >= startDate && createdAt <= endDate && o.status !== 'cancelled';
        });

        const paidOrders = filteredOrders.filter(o => o.payment_status === 'paid');
        const pendingOrders = filteredOrders.filter(o => o.payment_status === 'pending');

        const byMethod = {
            money: paidOrders.filter(o => o.payment_method === 'money').reduce((sum, o) => sum + (o.total || 0), 0),
            pix: paidOrders.filter(o => o.payment_method === 'pix').reduce((sum, o) => sum + (o.total || 0), 0),
            credit: paidOrders.filter(o => o.payment_method === 'credit').reduce((sum, o) => sum + (o.total || 0), 0),
            debit: paidOrders.filter(o => o.payment_method === 'debit').reduce((sum, o) => sum + (o.total || 0), 0)
        };

        return {
            totalOrders: filteredOrders.length,
            totalRevenue: paidOrders.reduce((sum, o) => sum + (o.total || 0), 0),
            paidOrders: paidOrders.length,
            pendingPayments: pendingOrders.reduce((sum, o) => sum + (o.total || 0), 0),
            byMethod
        };
    }, [orders, selectedDate]);

    const formatDateLong = (dateStr: string) => {
        const date = new Date(dateStr + 'T12:00:00');
        return new Intl.DateTimeFormat('pt-BR', { weekday: 'long', day: '2-digit', month: 'long' }).format(date);
    };

    const isToday = selectedDate === new Date().toISOString().split('T')[0];

    return (
        <div className="max-w-[1400px] mx-auto">
            <div className="flex items-start justify-between mb-8 gap-5 max-md:flex-col">
                <div>
                    <h1 className="text-[2rem] font-bold mb-2">Caixa</h1>
                    <p className="text-text-secondary">Resumo financeiro do dia</p>
                </div>
                <input
                    type="date"
                    value={selectedDate}
                    onChange={(e) => setSelectedDate(e.target.value)}
                    className="px-4 py-2.5 bg-bg-card border border-border rounded-md text-text-primary text-[0.9375rem] cursor-pointer [&::-webkit-calendar-picker-indicator]:invert [&::-webkit-calendar-picker-indicator]:cursor-pointer"
                />
            </div>

            <div className="text-lg text-text-secondary mb-6 capitalize">{isToday ? 'Hoje' : formatDateLong(selectedDate)}</div>

            {loading && orders.length === 0 ? (
                <div className="flex flex-col gap-6">
                    <div className="h-[150px] rounded-2xl bg-bg-tertiary animate-pulse" />
                    <div className="grid grid-cols-4 gap-4 mb-8 max-md:grid-cols-2">{[1, 2, 3, 4].map(i => <div key={i} className="h-[100px] rounded-xl bg-bg-tertiary animate-pulse" />)}</div>
                </div>
            ) : (
                <>
                    {/* Main Stats */}
                    <Card className="p-8! mb-8 bg-linear-to-br from-bg-card to-bg-tertiary">
                        <div className="text-center">
                            <span className="block text-[0.9375rem] text-text-secondary mb-2">Receita Total</span>
                            <span className="block text-5xl font-bold bg-linear-to-br from-primary to-accent bg-clip-text text-transparent mb-2 max-md:text-4xl">{formatCurrency(summary.totalRevenue)}</span>
                            <span className="text-sm text-text-muted">{summary.paidOrders} pedido{summary.paidOrders !== 1 ? 's' : ''} pago{summary.paidOrders !== 1 ? 's' : ''}</span>
                        </div>
                        {summary.pendingPayments > 0 && (
                            <div className="flex items-center gap-3 mt-6 p-4 bg-warning/10 border border-warning/30 rounded-md">
                                <span className="text-2xl">⚠️</span>
                                <div>
                                    <span className="block text-[0.8125rem] text-warning mb-0.5">Pagamentos Pendentes</span>
                                    <span className="block text-lg font-semibold text-warning">{formatCurrency(summary.pendingPayments)}</span>
                                </div>
                            </div>
                        )}
                    </Card>

                    {/* Payment Methods */}
                    <h3 className="text-base font-semibold text-text-secondary mb-4">Por Forma de Pagamento</h3>
                    <div className="grid grid-cols-4 gap-4 mb-8 max-md:grid-cols-2">
                        <Card className="flex items-center gap-3.5 p-4!">
                            <div className="w-11 h-11 rounded-md flex items-center justify-center text-xl bg-accent/10"><BsCash className="text-accent" /></div>
                            <div className="flex flex-col"><span className="text-[0.8125rem] text-text-secondary mb-0.5">Dinheiro</span><span className="text-base font-semibold">{formatCurrency(summary.byMethod.money)}</span></div>
                        </Card>
                        <Card className="flex items-center gap-3.5 p-4!">
                            <div className="w-11 h-11 rounded-md flex items-center justify-center text-xl bg-[#00cec9]/10"><FiSmartphone className="text-[#00cec9]" /></div>
                            <div className="flex flex-col"><span className="text-[0.8125rem] text-text-secondary mb-0.5">PIX</span><span className="text-base font-semibold">{formatCurrency(summary.byMethod.pix)}</span></div>
                        </Card>
                        <Card className="flex items-center gap-3.5 p-4!">
                            <div className="w-11 h-11 rounded-md flex items-center justify-center text-xl bg-info/10"><FiCreditCard className="text-info" /></div>
                            <div className="flex flex-col"><span className="text-[0.8125rem] text-text-secondary mb-0.5">Crédito</span><span className="text-base font-semibold">{formatCurrency(summary.byMethod.credit)}</span></div>
                        </Card>
                        <Card className="flex items-center gap-3.5 p-4!">
                            <div className="w-11 h-11 rounded-md flex items-center justify-center text-xl bg-[#9b59b6]/10"><FiCreditCard className="text-[#9b59b6]" /></div>
                            <div className="flex flex-col"><span className="text-[0.8125rem] text-text-secondary mb-0.5">Débito</span><span className="text-base font-semibold">{formatCurrency(summary.byMethod.debit)}</span></div>
                        </Card>
                    </div>

                    {/* Summary */}
                    <h3 className="text-base font-semibold text-text-secondary mb-4">Resumo</h3>
                    <Card className="p-5!">
                        <div className="flex justify-between py-3 border-b border-border text-text-secondary"><span>Total de Pedidos</span><span className="font-semibold text-text-primary">{summary.totalOrders}</span></div>
                        <div className="flex justify-between py-3 border-b border-border text-text-secondary"><span>Pedidos Pagos</span><span className="font-semibold text-text-primary">{summary.paidOrders}</span></div>
                        <div className="flex justify-between py-3 text-text-secondary"><span>Ticket Médio</span><span className="font-semibold text-text-primary">{summary.paidOrders > 0 ? formatCurrency(summary.totalRevenue / summary.paidOrders) : formatCurrency(0)}</span></div>
                    </Card>
                </>
            )}
        </div>
    );
}

