    const [deliveryTimeMin, setDeliveryTimeMin] = useState<number>(userSettings?.delivery_time_min ?? 30);
    const [deliveryTimeMax, setDeliveryTimeMax] = useState<number>(userSettings?.delivery_time_max ?? 45);
    const [sidebarColor, setSidebarColor] = useState(userSettings?.sidebar_color ?? userSettings?.secondary_color ?? '#2d3436');
    const [openingHours, setOpeningHours] = useState<OpeningHourInput[]>([]);

    // Ratings State
    const [storeRatings, setStoreRatings] = useState<{ id: string; rating: number; comment?: string; customer_name?: string; created_at: string; hidden?: boolean; reply?: string; user_id: string; products?: { name: string } }[]>([]);
    const [productRatings, setProductRatings] = useState<{ id: string; rating: number; comment?: string; customer_name?: string; created_at: string; hidden?: boolean; reply?: string; user_id: string; products?: { name: string } }[]>([]);
    const [ratingTab, setRatingTab] = useState<'store' | 'product'>('store');
    const [replyingId, setReplyingId] = useState<string | null>(null);
    const [replyText, setReplyText] = useState('');

    const SIDEBAR_MENU_ITEMS: { href: string; label: string; feature: FeatureKey }[] = [
        { href: '/dashboard', label: 'Dashboard', feature: 'dashboard' },
        { href: '/produtos', label: 'Produtos', feature: 'products' },
        { href: '/adicionais', label: 'Adicionais', feature: 'addons' },
        { href: '/categorias', label: 'Categorias', feature: 'categories' },
        { href: '/pedidos', label: 'Pedidos', feature: 'orders' },
        { href: '/cozinha', label: 'Cozinha', feature: 'kitchen' },
        { href: '/entregas', label: 'Entregas', feature: 'deliveries' },
        { href: '/estoque', label: 'Estoque', feature: 'inventory' },
        { href: '/cupons', label: 'Cupons', feature: 'coupons' },
        { href: '/fidelidade', label: 'Fidelidade', feature: 'loyalty' },
        { href: '/caixa', label: 'Caixa', feature: 'dashboard' },
        { href: '/contas', label: 'Contas', feature: 'bills' },
        { href: '/fluxo-caixa', label: 'Fluxo de Caixa', feature: 'cashFlow' },
        { href: '/funcionarios', label: 'Funcionários', feature: 'dashboard' },
        { href: '/relatorios', label: 'Relatórios', feature: 'reports' },
        { href: '/historico', label: 'Histórico', feature: 'actionHistory' },
        { href: '/assinatura', label: 'Assinatura', feature: 'dashboard' },
    ];


    const TABS = [
        { id: 'geral' as SettingsTab, label: 'Geral', icon: FiSettings },
        { id: 'aparencia' as SettingsTab, label: 'Aparência', icon: FiDroplet },
        { id: 'cardapio' as SettingsTab, label: 'Cardápio Online', icon: FiSmartphone },
        { id: 'pagamento' as SettingsTab, label: 'Pagamento', icon: FiDollarSign },
        { id: 'menu' as SettingsTab, label: 'Menu Lateral', icon: FiMenu },
        { id: 'avaliacoes' as SettingsTab, label: 'Avaliações', icon: FiStar },
        { id: 'atalhos' as SettingsTab, label: 'Atalhos', icon: FiCommand },
        { id: 'links' as SettingsTab, label: 'Links de Acesso', icon: FiUsers },
        { id: 'conta' as SettingsTab, label: 'Conta', icon: FiUser },
    ];

    useEffect(() => {
        if (userSettings) {
            setAppName(userSettings.app_name || 'Cola Aí');
            setSlogan(userSettings.slogan || '');
            setPrimaryColor(userSettings.primary_color || '#ff6b35');
            setSecondaryColor(userSettings.secondary_color || '#2d3436');
            setWhatsappNumber(userSettings.whatsapp_number || '');
            setPublicSlug(userSettings.public_slug || '');
            setPixKey(userSettings.pix_key || '');
            setPixKeyType(userSettings.pix_key_type || 'cpf');
            setMerchantCity(userSettings.merchant_city || '');
            setHiddenSidebarItems(userSettings.hidden_sidebar_items || []);
            setDeliveryFee(userSettings.delivery_fee_value ?? 5);
            setStoreOpen(userSettings.store_open ?? true);
            setDeliveryTimeMin(userSettings.delivery_time_min ?? 30);
            setDeliveryTimeMax(userSettings.delivery_time_max ?? 45);
            setSidebarColor(userSettings.sidebar_color ?? userSettings.secondary_color ?? '#2d3436');
            setTaxaServicoEnabled(userSettings.taxa_servico_enabled ?? false);
            setTaxaServicoPercent(userSettings.taxa_servico_percent ?? 10);
        }
    }, [userSettings]);

    // Auto-selecionar aba via parâmetro URL (ex: ?tab=suporte vindo do sidebar)
    useEffect(() => {
        const tab = searchParams.get('tab');
        if (tab && ['geral', 'aparencia', 'cardapio', 'pagamento', 'menu', 'avaliacoes', 'suporte', 'links', 'conta', 'atalhos'].includes(tab)) {
            setActiveTab(tab as SettingsTab);
            // Limpa o parâmetro da URL de forma "limpa" no Next.js
            const params = new URLSearchParams(searchParams.toString());
            params.delete('tab');
            const queryString = params.toString();
            router.replace(window.location.pathname + (queryString ? `?${queryString}` : ''), { scroll: false });
        }
    }, [searchParams, router]);

    useEffect(() => {
        if (user?.id) {
            getOpeningHours(user.id).then((data) => {
                if (data && data.length > 0) {
                    setOpeningHours(data.map(h => ({
                        day_of_week: h.day_of_week,
                        open_time: h.open_time,
                        close_time: h.close_time,
                        is_closed: h.is_closed
                    })));
                } else {
                    setOpeningHours(Array.from({ length: 7 }).map((_, i) => ({
                        day_of_week: i,
                        open_time: '18:00',
                        close_time: '23:00',
                        is_closed: false
                    })));
                }
            });
        }
    }, [user?.id]);

    const loadRatings = useCallback(() => {
        if (user?.id) {
            getRecentRatings(user.id).then(data => {
                setStoreRatings(data.storeRatings);
                setProductRatings(data.productRatings);
            });
        }
    }, [user?.id]);

    useEffect(() => {
        if (activeTab === 'avaliacoes') {
            loadRatings();
        }
    }, [activeTab, user?.id, loadRatings]);

    const getMenuUrl = () => {
        if (typeof window !== 'undefined' && publicSlug) {
            return `${window.location.origin}/menu/${publicSlug}`;
        }
        return '';
    };

    const handleSlugChange = (value: string) => {
        const sanitized = value.toLowerCase().replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-');
        setPublicSlug(sanitized);
        setSlugError('');
    };

    const checkSlugAvailability = async (slug: string): Promise<boolean> => {
        if (!slug) return true;
        const { data, error } = await supabase.from('user_settings').select('user_id').eq('public_slug', slug).neq('user_id', user?.id).maybeSingle();
        return !data && !error;
    };

    const handleSave = async () => {
        setSaving(true);
        setSaved(false);
        setSlugError('');
        try {
            if (publicSlug) {
                const isAvailable = await checkSlugAvailability(publicSlug);
                if (!isAvailable) { setSlugError('Este link já está em uso. Escolha outro.'); setSaving(false); return; }
            }
            const { error } = await updateSettings({
                app_name: appName, slogan: slogan || null, primary_color: primaryColor, secondary_color: secondaryColor, sidebar_color: sidebarColor,
                merchant_city: merchantCity || null, delivery_fee_value: deliveryFee, store_open: storeOpen, delivery_time_min: deliveryTimeMin, delivery_time_max: deliveryTimeMax,
                taxa_servico_enabled: taxaServicoEnabled, taxa_servico_percent: taxaServicoPercent
            });
            await Promise.all([
                updateStoreStatus(storeOpen),
                updateDeliveryTime(deliveryTimeMin, deliveryTimeMax),
                updateSidebarColor(sidebarColor),
                updateTaxaServico(taxaServicoEnabled, taxaServicoPercent),
                saveOpeningHours(openingHours)
            ]);

            revalidateStoreMenu();

            if (!error) { setSaved(true); toast.success('Configurações salvas com sucesso!'); setTimeout(() => setSaved(false), 3000); }
            else { toast.error('Erro ao salvar as configurações'); }
        } catch (error) { console.error('Error saving settings:', error); toast.error('Erro ao salvar as configurações'); } finally { setSaving(false); }
    };


    const handleOpeningHourChange = (index: number, field: keyof OpeningHourInput, value: string | boolean) => {
        setOpeningHours(prev => { const newHours = [...prev]; newHours[index] = { ...newHours[index], [field]: value }; return newHours; });
    };

    const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; if (!file || !user) return; setUploading(true);
        try {
            const fileExt = file.name.split('.').pop(); const fileName = `${user.id}/logo.${fileExt}`;
            const { error: uploadError } = await supabase.storage.from('logos').upload(fileName, file, { upsert: true });
            if (uploadError) throw uploadError;
            const { data: { publicUrl } } = supabase.storage.from('logos').getPublicUrl(fileName);
            await updateSettings({ logo_url: publicUrl });
            revalidateStoreMenu();
        } catch (error) { console.error('Error uploading logo:', error); } finally { setUploading(false); }
    };

    const applyPreset = (preset: typeof colorPresets[0]) => {
        setPrimaryColor(preset.primary); setSecondaryColor(preset.secondary); setSidebarColor(preset.secondary);
        previewSettings({ primary_color: preset.primary, secondary_color: preset.secondary, sidebar_color: preset.secondary });
    };

    const handleRemoveLogo = async () => {
        if (!user || !userSettings?.logo_url) return;
        try {
            const urlParts = userSettings.logo_url.split('/'); const fileName = `${user.id}/${urlParts[urlParts.length - 1]}`;
            await supabase.storage.from('logos').remove([fileName]); await updateSettings({ logo_url: null });
            revalidateStoreMenu();
        } catch (error) { console.error('Error removing logo:', error); }
    };

    const copyMenuLink = () => { const url = getMenuUrl(); if (url) { navigator.clipboard.writeText(url); setCopied(true); setTimeout(() => setCopied(false), 2000); } };
    const formatWhatsApp = (value: string) => { const digits = value.replace(/\D/g, ''); if (digits.length <= 2) return digits; if (digits.length <= 7) return `(${digits.slice(0, 2)}) ${digits.slice(2)}`; return `(${digits.slice(0, 2)}) ${digits.slice(2, 7)}-${digits.slice(7, 11)}`; };
    const toggleSidebarItem = (href: string) => { setHiddenSidebarItems(prev => prev.includes(href) ? prev.filter(h => h !== href) : [...prev, href]); };
    const hideUnavailableFeatures = () => { const toHide: string[] = []; SIDEBAR_MENU_ITEMS.forEach(item => { if (!canAccess(item.feature)) toHide.push(item.href); }); setHiddenSidebarItems(toHide); };
    const saveSidebarVisibility = async () => { setSaving(true); try { await updateSettings({ hidden_sidebar_items: hiddenSidebarItems }); setSaved(true); setTimeout(() => setSaved(false), 3000); } catch (error) { console.error('Error saving sidebar visibility:', error); } finally { setSaving(false); } };

    // Rating Handlers
    const handleToggleRatingVisibility = async (id: string, currentHidden: boolean, type: 'store' | 'product') => {
        try {
            if (type === 'store') await toggleStoreRatingVisibility(id, !currentHidden);
            else await toggleProductRatingVisibility(id, !currentHidden);
            loadRatings();
        } catch (error) { console.error('Error toggling visibility:', error); }
    };

    const handleDeleteRating = async (id: string, type: 'store' | 'product') => {
        if (!confirm('Tem certeza que deseja excluir esta avaliação?')) return;
        try {
            if (type === 'store') await deleteStoreRating(id);
            else await deleteProductRating(id);
            loadRatings();
        } catch (error) { console.error('Error deleting rating:', error); }
    };

    const handleReplyRating = async (id: string, type: 'store' | 'product') => {
        if (!replyText.trim()) return;
        try {
            if (type === 'store') await replyToStoreRating(id, replyText);
            else await replyToProductRating(id, replyText);
            setReplyingId(null);
            setReplyText('');
            loadRatings();
        } catch (error) { console.error('Error replying rating:', error); }
    };

    const renderTabContent = () => {
        switch (activeTab) {
            case 'geral':
                return (
                    <div className="p-6 sm:p-8">
                        <div className="mb-7 pb-5 border-b border-border"><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Informações do Negócio</h2><p className="text-sm text-text-muted">Configure as informações básicas do seu estabelecimento</p></div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                            <div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Nome do Negócio</label><Input value={appName} onChange={(e) => { setAppName(e.target.value); previewSettings({ app_name: e.target.value }); }} placeholder="Nome do seu negócio" /><span className="block text-[13px] text-text-muted mt-2">Este nome aparece no topo da sidebar</span></div>
                            <div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Slogan da Loja</label><Input value={slogan} onChange={(e) => { setSlogan(e.target.value); previewSettings({ slogan: e.target.value }); }} placeholder="A melhor experiência gastronômica, entregue na sua porta." /><span className="block text-[13px] text-text-muted mt-2">Aparece logo abaixo do nome no cardápio online</span></div>
                            <div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5"><FaWhatsapp style={{ marginRight: '8px', color: '#25D366' }} />WhatsApp</label><Input value={formatWhatsApp(whatsappNumber)} onChange={(e) => setWhatsappNumber(e.target.value.replace(/\D/g, ''))} placeholder="(11) 99999-9999" maxLength={16} /><span className="block text-[13px] text-text-muted mt-2">Usado para receber pedidos via WhatsApp</span></div>
                        </div>
                        <div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Logo do Negócio</label><div className="flex flex-col md:flex-row items-start md:items-center gap-5"><div className="w-20 h-20 rounded-xl bg-bg-tertiary border-2 border-border flex items-center justify-center overflow-hidden shrink-0">{userSettings?.logo_url ? <div className="relative w-full h-full"><Image src={userSettings.logo_url} alt="Logo" fill className="object-contain" sizes="100px" /></div> : <span className="text-5xl">🌭</span>}</div><div className="flex gap-3"><input ref={fileInputRef} type="file" accept="image/*" onChange={handleLogoUpload} hidden /><Button variant="outline" leftIcon={<FiUpload />} onClick={() => fileInputRef.current?.click()} isLoading={uploading}>{userSettings?.logo_url ? 'Trocar' : 'Carregar'}</Button>{userSettings?.logo_url && <Button variant="danger" leftIcon={<FiTrash2 />} onClick={handleRemoveLogo}>Remover</Button>}</div></div></div>

                        <div className="mb-7 pb-5 border-b border-border" style={{ marginTop: '2rem' }}><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Taxa de Serviço (Mesas)</h2><p className="text-sm text-text-muted">Configure a taxa de serviço cobrada nos pedidos de Mesas</p></div>
                        <div className="bg-bg-tertiary border border-border p-4 rounded-xl flex flex-col gap-6 shadow-sm">
                            <div className="flex items-center justify-between">
                                <div>
                                    <h3 className="text-base font-bold text-text-primary">Habilitar Taxa de Serviço</h3>
                                    <p className="text-sm text-text-secondary m-0">Define se a taxa será sugerida no fechamento da conta das mesas.</p>
                                </div>
                                <label className="relative inline-flex items-center cursor-pointer">
                                    <input
                                        type="checkbox"
                                        checked={taxaServicoEnabled}
                                        onChange={(e) => setTaxaServicoEnabled(e.target.checked)}
                                        className="sr-only peer"
                                    />
                                    <div className="w-11 h-6 bg-bg-card peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-primary"></div>
                                </label>
                            </div>

                            {taxaServicoEnabled && (
                                <div className="animate-slideDown">
                                    <label className="text-sm font-bold text-text-secondary mb-2 block tracking-tight">Percentual da Taxa (%)</label>
                                    <div className="relative w-32">
                                        <Input
                                            type="number"
                                            value={taxaServicoPercent}
                                            onChange={(e) => setTaxaServicoPercent(parseFloat(e.target.value) || 0)}
                                            className="text-center font-bold"
                                        />
                                        <span className="absolute right-3 top-1/2 -translate-y-1/2 text-text-muted font-bold">%</span>
                                    </div>
                                    <p className="text-xs text-text-muted mt-2">Valor padrão sugerido para garçom.</p>
                                </div>
                            )}
                        </div>

                        <div className="mb-7 pb-5 border-b border-border" style={{ marginTop: '2rem' }}><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Notificações</h2><p className="text-sm text-text-muted">Gerencie os alertas e avisos do sistema</p></div>
                        <div className="mb-6">
                            <label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Notificações Push no Computador/Celular</label>
                            <div className="bg-bg-tertiary border border-border p-4 rounded-xl flex flex-col items-start gap-4">
                                <p className="text-sm text-text-secondary m-0">Ative para receber avisos em tempo real e com som sempre que um novo pedido chegar.</p>
                                <div className="w-full sm:w-auto">
                                    <PushNotificationPrompt />
                                </div>
                            </div>
                        </div>

                        <div className="pt-6 border-t border-border mt-2"><Button size="lg" leftIcon={saved ? <FiCheck /> : <FiSave />} onClick={handleSave} isLoading={saving} style={saved ? { background: 'var(--accent)' } : {}}>{saved ? 'Salvo!' : 'Salvar Alterações'}</Button></div>
                    </div>
                );
            case 'aparencia':
                return (
                    <div className="p-6 sm:p-8">
                        <div className="mb-7 pb-5 border-b border-border"><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Personalização Visual</h2><p className="text-sm text-text-muted">Customize as cores do seu aplicativo</p></div>
                        <div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Temas Prontos</label><div className="grid grid-cols-2 sm:grid-cols-4 gap-2.5">{colorPresets.map((preset) => (<button key={preset.name} className={`flex items-center gap-2.5 px-3 py-3 bg-bg-tertiary border-2 border-border rounded-md cursor-pointer transition-all hover:border-border-light group ${primaryColor === preset.primary ? "!border-primary !bg-primary/10" : ""}`} onClick={() => applyPreset(preset)} title={preset.name}><span className="w-6 h-6 rounded-full shrink-0" style={{ background: preset.primary }} /><span className={`text-sm ${primaryColor === preset.primary ? "text-text-primary" : "text-text-secondary"}`}>{preset.name}</span></button>))}</div></div>
                        <div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Cores Personalizadas</label><div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="flex flex-col"><span className="block text-[13px] text-text-muted mb-2">Cor Principal</span><div className="flex items-center gap-3 px-3.5 py-2.5 bg-bg-tertiary border border-border rounded-md"><input type="color" value={primaryColor} onChange={(e) => { setPrimaryColor(e.target.value); previewSettings({ primary_color: e.target.value }); }} /><span className="font-mono text-sm text-text-secondary uppercase">{primaryColor}</span></div></div>
                            <div className="flex flex-col"><span className="block text-[13px] text-text-muted mb-2">Cor Secundária</span><div className="flex items-center gap-3 px-3.5 py-2.5 bg-bg-tertiary border border-border rounded-md"><input type="color" value={secondaryColor} onChange={(e) => { setSecondaryColor(e.target.value); previewSettings({ secondary_color: e.target.value }); }} /><span className="font-mono text-sm text-text-secondary uppercase">{secondaryColor}</span></div></div>
                            <div className="flex flex-col"><span className="block text-[13px] text-text-muted mb-2">Cor da Sidebar</span><div className="flex items-center gap-3 px-3.5 py-2.5 bg-bg-tertiary border border-border rounded-md"><input type="color" value={sidebarColor} onChange={(e) => { setSidebarColor(e.target.value); previewSettings({ sidebar_color: e.target.value }); }} /><span className="font-mono text-sm text-text-secondary uppercase">{sidebarColor}</span></div></div>
                        </div></div>
                        <div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Prévia</label><div className="flex bg-bg-primary border border-border rounded-xl overflow-hidden h-40"><div className="w-20 p-4 flex flex-col items-center gap-2" style={{ background: sidebarColor }}><div className="w-12 h-12 rounded-md flex items-center justify-center overflow-hidden" style={{ background: `${primaryColor}20` }}>{userSettings?.logo_url ? <div className="relative w-full h-full"><Image src={userSettings.logo_url} alt="" fill className="object-contain" sizes="40px" /></div> : <span>🌭</span>}</div><div className="text-[10px] font-bold text-center" style={{ color: primaryColor }}>{appName}</div></div><div className="flex-1 p-6 flex items-center justify-center"><div className="px-6 py-3 rounded-md text-white font-medium text-sm" style={{ background: primaryColor }}>Exemplo de Botão</div></div></div></div>
                        <div className="pt-6 border-t border-border mt-2"><Button size="lg" leftIcon={saved ? <FiCheck /> : <FiSave />} onClick={handleSave} isLoading={saving} style={saved ? { background: 'var(--accent)' } : {}}>{saved ? 'Salvo!' : 'Salvar Alterações'}</Button></div>
                    </div>
                );
            case 'cardapio':
                return (
                    <div className="space-y-8 animate-fadeIn">
                        <div className="flex flex-col gap-2 border-b border-border pb-6">
                            <h2 className="text-2xl font-bold text-text-primary">Cardápio Online</h2>
                            <p className="text-text-secondary">Configure a disponibilidade e horários da sua loja digital.</p>
                        </div>

                        {!canAccess('digitalMenu') ? (
                            <div className="flex flex-col items-center justify-center text-center py-16 px-6 bg-bg-tertiary rounded-xl border-2 border-dashed border-border">
                                <FiLock className="text-5xl text-text-muted mb-4" />
                                <h3 className="text-lg font-semibold text-text-primary mt-4 mb-2">Recurso não disponível no seu plano</h3>
                                <p className="text-sm text-text-muted">O Cardápio Online está disponível nos planos Avançado e Profissional.</p>
                                <a href="/assinatura" className="inline-flex items-center gap-2 px-6 py-3 bg-primary text-white font-semibold text-[15px] rounded-md transition-all hover:bg-primary-dark hover:-translate-y-0.5">Fazer Upgrade</a>
                            </div>
                        ) : (
                            <>
                                {/* Status & Key Info Cards - Vertical Stack */}
                                <div className="flex flex-col gap-6">
                                    {/* Store Status - Wide Banner Style */}
                                    <div className="bg-bg-tertiary border border-border rounded-xl p-4 sm:p-6 relative overflow-hidden group hover:border-border-light transition-all duration-300">
                                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 z-10 relative">
                                            <div className="flex items-center gap-4">
                                                <div className={cn("p-3 rounded-xl shrink-0", storeOpen ? "bg-primary/10 text-primary" : "bg-bg-card text-text-muted")}>
                                                    {storeOpen ? <FiSmartphone size={24} /> : <FiLock size={24} />}
                                                </div>
                                                <div>
                                                    <h3 className="text-lg font-bold text-text-primary">Status da Loja</h3>
                                                    <p className={cn(
                                                        "text-sm font-bold uppercase tracking-wider flex items-center gap-2 mt-1",
                                                        storeOpen ? "text-primary" : "text-text-muted"
                                                    )}>
                                                        {storeOpen ? (
                                                            <>
                                                                <span className="w-2 h-2 rounded-full bg-primary animate-pulse" />
                                                                Aberta para Pedidos
                                                            </>
                                                        ) : (
                                                            <>
                                                                <span className="w-2 h-2 rounded-full bg-text-muted" />
                                                                Atualmente Fechada
                                                            </>
                                                        )}
                                                    </p>
                                                </div>
                                            </div>

                                            <label className="relative inline-flex items-center cursor-pointer self-end sm:self-center">
                                                <input
                                                    type="checkbox"
                                                    checked={storeOpen}
                                                    onChange={(e) => setStoreOpen(e.target.checked)}
                                                    className="sr-only peer"
                                                />
                                                <div className="w-14 h-7 bg-bg-card peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:left-[4px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-primary shadow-sm hover:scale-105 transition-transform"></div>
                                            </label>
                                        </div>

                                        <div className="mt-4 pt-4 border-t border-white/5">
                                            <p className="text-sm text-text-secondary leading-relaxed flex items-center gap-2">
                                                <FiClock className="shrink-0" />
                                                {storeOpen
                                                    ? 'Sua loja está online! Clientes podem acessar o cardápio e enviar pedidos.'
                                                    : 'Loja fechada. O cardápio permanece visível apenas para consulta.'}
                                            </p>
                                        </div>
                                    </div>

                                    {/* Link Share - Full Width & Spacious */}
                                    <div className="bg-bg-tertiary border border-border rounded-xl p-4 sm:p-6 lg:p-8 flex flex-col gap-6 hover:border-border-light transition-all duration-300">
                                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                                            <div>
                                                <h3 className="text-xl font-bold text-text-primary">Link do Cardápio</h3>
                                                <p className="text-sm text-text-secondary mt-1">Este é o endereço único da sua loja digital</p>
                                            </div>
                                            {publicSlug && userSettings?.public_slug && (
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    onClick={() => window.open(getMenuUrl(), '_blank')}
                                                    leftIcon={<FiLink />}
                                                    className="w-full sm:w-auto justify-center shrink-0"
                                                >
                                                    Abrir Link
                                                </Button>
                                            )}
                                        </div>

                                        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 lg:gap-8 items-center">
                                            {/* Left: Input & Copy */}
                                            <div className="lg:col-span-2 flex flex-col gap-4">
                                                <div className="group relative">
                                                    <label className="text-xs font-bold text-text-muted uppercase tracking-wider mb-2 block">Personalizar Link</label>
                                                    <div className={cn(
                                                        "flex items-center bg-bg-card border rounded-xl overflow-hidden transition-all duration-300 h-14 sm:h-16 shadow-inner",
                                                        slugError ? "border-error" : "border-border group-focus-within:border-primary group-focus-within:ring-2 group-focus-within:ring-primary/20"
                                                    )}>
                                                        <div className="hidden sm:flex bg-bg-secondary/30 px-3 sm:px-5 h-full items-center text-sm sm:text-base text-text-muted border-r border-border font-mono select-none tracking-tight">
                                                            {typeof window !== 'undefined' ? window.location.host : ''}/menu/
                                                        </div>
                                                        <div className="flex sm:hidden bg-bg-secondary/30 px-3 h-full items-center text-sm text-text-muted border-r border-border font-mono select-none">
                                                            /
                                                        </div>
                                                        <input
                                                            value={publicSlug}
                                                            onChange={(e) => handleSlugChange(e.target.value)}
                                                            placeholder="nome-da-loja"
                                                            className="flex-1 bg-transparent border-none px-3 sm:px-5 h-full text-text-primary focus:outline-none font-bold text-base sm:text-lg placeholder:text-text-muted/30 placeholder:font-normal min-w-0"
                                                        />
                                                        {publicSlug && userSettings?.public_slug && (
                                                            <button
                                                                onClick={copyMenuLink}
                                                                className="px-4 sm:px-8 h-full text-sm font-bold text-primary hover:bg-primary hover:text-white transition-all duration-300 border-l border-border flex items-center gap-2 active:scale-95 shrink-0"
                                                                title="Copiar Link"
                                                            >
                                                                {copied ? <FiCheck size={20} /> : <FiCopy size={20} />}
                                                                <span className="hidden sm:inline">{copied ? 'Copiado!' : 'Copiar'}</span>
                                                            </button>
                                                        )}
                                                    </div>
                                                    {slugError && <p className="text-sm text-error mt-2 flex items-center gap-1 font-medium"><FiLock size={14} /> {slugError}</p>}
                                                </div>

                                                <div className="bg-bg-card/50 rounded-lg p-3 sm:p-4 border border-white/5">
                                                    <p className="text-xs sm:text-sm text-text-secondary flex gap-2">
                                                        <span className="text-primary font-bold shrink-0">💡 Dica:</span>
                                                        Escolha um nome curto e fácil de lembrar.
                                                    </p>
                                                </div>
                                            </div>

                                            {/* Right: QR Code */}
                                            {publicSlug && userSettings?.public_slug && (
                                                <div className="flex flex-col items-center justify-center p-4 sm:p-6 bg-bg-card/30 rounded-xl border border-white/5 mt-2 lg:mt-0">
                                                    <QRCodeGenerator url={getMenuUrl()} appName={appName} primaryColor={primaryColor} />
                                                    <p className="text-xs text-text-muted mt-3 text-center">Seu QR Code oficial</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>

                                {/* Delivery Settings */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="bg-bg-tertiary border border-border rounded-xl p-6 hover:border-border-light transition-colors">
                                        <div className="flex items-center gap-3 mb-4">
                                            <FiClock className="text-xl text-text-secondary" />
                                            <h3 className="text-lg font-semibold text-text-primary">Tempo de Entrega</h3>
                                        </div>
                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="flex-1">
                                                <label className="text-xs text-text-muted mb-1 block">Mínimo (min)</label>
                                                <Input
                                                    type="number"
                                                    value={deliveryTimeMin}
                                                    onChange={(e) => setDeliveryTimeMin(parseInt(e.target.value) || 0)}
                                                    className="text-center w-full"
                                                />
                                            </div>
                                            <div className="flex-1">
                                                <label className="text-xs text-text-muted mb-1 block">Máximo (min)</label>
                                                <Input
                                                    type="number"
                                                    value={deliveryTimeMax}
                                                    onChange={(e) => setDeliveryTimeMax(parseInt(e.target.value) || 0)}
                                                    className="text-center w-full"
                                                />
                                            </div>
                                        </div>
                                    </div>

                                    <div className="bg-bg-tertiary border border-border rounded-xl p-6 hover:border-border-light transition-colors">
                                        <div className="flex items-center gap-3 mb-4">
                                            <FiDollarSign className="text-xl text-text-secondary" />
                                            <h3 className="text-lg font-semibold text-text-primary">Taxa de Entrega</h3>
                                        </div>
                                        <div className="relative">
                                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-primary font-bold">R$</span>
                                            <Input
                                                type="number"
                                                step="0.01"
                                                min="0"
                                                value={deliveryFee}
                                                onChange={(e) => setDeliveryFee(parseFloat(e.target.value) || 0)}
                                                placeholder="0.00"
                                                style={{ paddingLeft: '40px' }}
                                            />
                                        </div>
                                    </div>
                                </div>

                                {/* Opening Hours Scheduler */}
                                <div className="bg-bg-tertiary border border-border rounded-xl p-6">
                                    <div className="flex items-center justify-between mb-6">
                                        <div>
                                            <h3 className="text-lg font-semibold text-text-primary">Horário de Funcionamento</h3>
                                            <p className="text-sm text-text-secondary mt-1">Configure os horários em que sua loja recebe pedidos automaticamente.</p>
                                        </div>
                                        <div className="p-2 bg-primary/10 rounded-lg">
                                            <FiClock className="text-primary text-xl" />
                                        </div>
                                    </div>

                                    <OpeningHoursScheduler
                                        hours={openingHours}
                                        onChange={handleOpeningHourChange}
                                    />
                                </div>

                                {/* Save Button */}
                                <div className="sticky bottom-4 z-10 pt-4 bg-bg-primary/80 backdrop-blur-sm border-t border-border mt-8 flex justify-end">
                                    <Button
                                        size="lg"
                                        leftIcon={saved ? <FiCheck /> : <FiSave />}
                                        onClick={handleSave}
                                        isLoading={saving}
                                        className={cn(
                                            "min-w-[200px] shadow-lg transition-all duration-300",
                                            saved ? "bg-success hover:bg-success" : "bg-primary hover:bg-primary-dark"
                                        )}
                                    >
                                        {saved ? 'Salvo com Sucesso!' : 'Salvar Alterações'}
                                    </Button>
                                </div>
                            </>
                        )}
                    </div>
                );
            case 'pagamento':
                return (
                    <div className="p-6 sm:p-8">
                        <div className="mb-7 pb-5 border-b border-border"><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Pagamento PIX</h2><p className="text-sm text-text-muted">Configure sua chave PIX para receber pagamentos</p></div>
                        <div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Tipo de Chave PIX</label><div className="flex flex-wrap gap-2 text-sm">{[{ value: 'cpf', label: 'CPF' }, { value: 'cnpj', label: 'CNPJ' }, { value: 'email', label: 'E-mail' }, { value: 'phone', label: 'Telefone' }, { value: 'random', label: 'Aleatória' }].map((type) => (<button key={type.value} className={`px-4 py-3 bg-bg-tertiary border-2 border-border rounded-md text-text-secondary font-medium cursor-pointer transition-all hover:border-border-light hover:text-text-primary ${pixKeyType === type.value ? "!border-[#32BCAD] !bg-[#32BCAD]/10 !text-[#32BCAD]" : ""}`} onClick={() => setPixKeyType(type.value as typeof pixKeyType)} type="button">{type.label}</button>))}</div></div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6"><div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Chave PIX</label><Input value={pixKey} onChange={(e) => setPixKey(e.target.value)} placeholder={pixKeyType === 'cpf' ? '000.000.000-00' : pixKeyType === 'cnpj' ? '00.000.000/0000-00' : pixKeyType === 'email' ? 'email@exemplo.com' : pixKeyType === 'phone' ? '+5511999999999' : 'xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx'} /><span className="block text-[13px] text-text-muted mt-2">Esta chave será usada para gerar QR Codes PIX nos pedidos</span></div><div className="mb-6"><label className="flex items-center text-[15px] font-medium text-text-primary mb-2.5">Cidade do Estabelecimento</label><Input value={merchantCity} onChange={(e) => setMerchantCity(e.target.value)} placeholder="São Paulo" maxLength={15} /><span className="block text-[13px] text-text-muted mt-2">Cidade que aparecerá no comprovante PIX (máx. 15 caracteres)</span></div></div>
                        <div className="pt-6 border-t border-border mt-2"><Button size="lg" leftIcon={saved ? <FiCheck /> : <FiSave />} onClick={handleSave} isLoading={saving} style={saved ? { background: 'var(--accent)' } : {}}>{saved ? 'Salvo!' : 'Salvar Alterações'}</Button></div>
                    </div>
                );
            case 'menu':
                return (
                    <div className="p-6 sm:p-8">
                        <div className="mb-7 pb-5 border-b border-border"><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Visibilidade do Menu</h2><p className="text-sm text-text-muted">Escolha quais itens aparecem no menu lateral</p></div>
                        <div className="flex flex-col md:flex-row gap-3 mb-6"><Button variant="outline" onClick={hideUnavailableFeatures} leftIcon={<FiEyeOff />}>Ocultar Itens Fora do Plano</Button><Button variant="outline" onClick={() => setHiddenSidebarItems([])} leftIcon={<FiEye />}>Mostrar Todos</Button></div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-2.5 mb-6">{SIDEBAR_MENU_ITEMS.map((item) => { const isHidden = hiddenSidebarItems.includes(item.href); const isAvailable = canAccess(item.feature); return (<label key={item.href} className={`flex items-center gap-2.5 px-3.5 py-3 bg-bg-tertiary border-2 border-border rounded-md cursor-pointer transition-all text-sm hover:border-border-light ${isHidden ? "opacity-60 bg-bg-secondary" : ""} ${!isAvailable ? "border-dashed" : ""}`}><input type="checkbox" checked={!isHidden} onChange={() => toggleSidebarItem(item.href)} /><span className={`flex items-center gap-1.5 flex-1 ${isHidden ? "text-text-muted" : "text-text-primary"}`}>{isHidden ? <FiEyeOff size={14} /> : <FiEye size={14} />}{item.label}</span>{!isAvailable && (<span className="flex items-center gap-1 text-[10px] px-1.5 py-0.5 bg-yellow-500/15 text-yellow-500 rounded font-semibold whitespace-nowrap"><FiLock size={10} /> Upgrade</span>)}</label>); })}</div>
                        <div className="pt-6 border-t border-border mt-2"><Button size="lg" leftIcon={saved ? <FiCheck /> : <FiSave />} onClick={saveSidebarVisibility} isLoading={saving} style={saved ? { background: 'var(--accent)' } : {}}>{saved ? 'Salvo!' : 'Salvar Visibilidade'}</Button></div>
                    </div>
                );
            case 'avaliacoes':
                const ratings = ratingTab === 'store' ? storeRatings : productRatings;
                return (
                    <div className="p-6 sm:p-8">
                        <div className="mb-7 pb-5 border-b border-border"><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Avaliações</h2><p className="text-sm text-text-muted">Gerencie as avaliações recebidas</p></div>
                        <div className="flex gap-4 mb-6">
                            <button onClick={() => setRatingTab('store')} className={`px-4 py-2 rounded-lg font-medium transition-colors ${ratingTab === 'store' ? 'bg-primary text-white' : 'bg-bg-tertiary text-text-secondary hover:text-text-primary'}`}>Loja ({storeRatings.length})</button>
                            <button onClick={() => setRatingTab('product')} className={`px-4 py-2 rounded-lg font-medium transition-colors ${ratingTab === 'product' ? 'bg-primary text-white' : 'bg-bg-tertiary text-text-secondary hover:text-text-primary'}`}>Produtos ({productRatings.length})</button>
                        </div>
                        <div className="space-y-4">
                            {ratings.length === 0 ? (
                                <div className="text-center py-12 text-text-muted"><FiStar size={48} className="mx-auto mb-4 opacity-50" /><p className="text-sm text-text-muted">Nenhuma avaliação recebida ainda.</p></div>
                            ) : (
                                ratings.map((rating) => (
                                    <div key={rating.id} className="bg-bg-card border border-white/5 rounded-xl p-5 shadow-sm">
                                        <div className="flex justify-between items-start mb-3">
                                            <div>
                                                <div className="flex items-center gap-1 mb-1">{Array.from({ length: 5 }).map((_, i) => (<FiStar key={i} size={16} className={i < rating.rating ? 'fill-yellow-400 text-yellow-400' : 'text-text-muted'} />))}</div>
                                                <div className="flex items-center gap-2 text-sm text-text-secondary">
                                                    <span className="font-semibold text-text-primary">{rating.customer_name || 'Anônimo'}</span>
                                                    <span>•</span>
                                                    <span>{new Date(rating.created_at).toLocaleDateString()}</span>
                                                    {ratingTab === 'product' && rating.products && (
                                                        <><span>•</span><span className="text-primary">{rating.products.name}</span></>
                                                    )}
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <button onClick={() => handleToggleRatingVisibility(rating.id, rating.hidden ?? false, ratingTab)} className={`p-2 rounded-lg transition-colors ${rating.hidden ? 'bg-error/10 text-error' : 'bg-bg-tertiary text-text-muted hover:text-primary'}`} title={rating.hidden ? 'Mostrar' : 'Ocultar'}>{rating.hidden ? <FiEyeOff size={18} /> : <FiEye size={18} />}</button>
                                                <button onClick={() => handleDeleteRating(rating.id, ratingTab)} className="p-2 rounded-lg bg-bg-tertiary text-text-muted hover:bg-error/10 hover:text-error transition-colors" title="Excluir"><FiTrash2 size={18} /></button>
                                            </div>
                                        </div>
                                        {rating.comment && <p className="text-text-primary mb-4 bg-bg-tertiary/50 p-3 rounded-lg">{rating.comment}</p>}
                                        {rating.reply ? (
                                            <div className="ml-4 pl-4 border-l-2 border-primary">
                                                <p className="text-xs text-primary font-bold mb-1">Sua resposta:</p>
                                                <p className="text-sm text-text-secondary">{rating.reply}</p>
                                            </div>
                                        ) : (
                                            replyingId === rating.id ? (
                                                <div className="mt-4 animate-fadeIn">
                                                    <textarea value={replyText} onChange={(e) => setReplyText(e.target.value)} className="w-full bg-bg-tertiary border border-white/10 rounded-lg p-3 text-sm focus:border-primary focus:outline-none mb-2" placeholder="Escreva sua resposta..." autoFocus />
                                                    <div className="flex justify-end gap-2">
                                                        <Button size="sm" variant="outline" onClick={() => { setReplyingId(null); setReplyText(''); }}>Cancelar</Button>
                                                        <Button size="sm" onClick={() => handleReplyRating(rating.id, ratingTab)} disabled={!replyText.trim()} leftIcon={<FiSend />}>Responder</Button>
                                                    </div>
                                                </div>
                                            ) : (
                                                <button onClick={() => setReplyingId(rating.id)} className="text-sm text-primary font-medium hover:underline flex items-center gap-1"><FiMessageSquare size={14} /> Responder</button>
                                            )
                                        )}
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                );
            case 'links':
                const accessToken = userSettings?.access_token; const baseUrl = typeof window !== 'undefined' ? window.location.origin : '';
                const accessLinks = [{ id: 'cozinha', title: 'Cozinha', icon: '👨‍🍳', description: 'Funcionários da cozinha podem visualizar e gerenciar pedidos pendentes', url: accessToken ? `${baseUrl}/acesso/${accessToken}/cozinha` : null }, { id: 'entregas', title: 'Entregas', icon: '🚚', description: 'Entregadores podem visualizar pedidos prontos para entrega', url: accessToken ? `${baseUrl}/acesso/${accessToken}/entregas` : null }];
                const copyAccessLink = (url: string, id: string) => { navigator.clipboard.writeText(url); setCopiedLink(id); setTimeout(() => setCopiedLink(null), 2000); };
                return (
                    <div className="p-6 sm:p-8">
                        <div className="mb-7 pb-5 border-b border-border"><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Links de Acesso</h2><p className="text-sm text-text-muted">Compartilhe links com funcionários para acessar páginas específicas com PIN</p></div>
                        {!accessToken ? (<div className="flex flex-col items-center justify-center text-center py-16 px-6 bg-bg-tertiary rounded-xl border-2 border-dashed border-border"><FiLink className="text-5xl text-text-muted mb-4" /><h3 className="text-lg font-semibold text-text-primary mt-4 mb-2">Carregando...</h3><p className="text-sm text-text-muted">Aguarde enquanto geramos seus links de acesso</p></div>) : (<div className="grid grid-cols-1 md:grid-cols-2 gap-5">{accessLinks.map((link) => (<div key={link.id} className="p-6 bg-bg-tertiary rounded-xl border border-border"><div className="flex items-center gap-3 mb-3"><span className="text-3xl">{link.icon}</span><h3 className="text-lg font-semibold text-text-primary m-0">{link.title}</h3></div><p className="text-sm text-text-secondary mb-4 leading-relaxed">{link.description}</p>{link.url && (<><div className="p-3 bg-bg-secondary rounded-md mb-4 overflow-x-auto"><code className="text-xs text-text-muted break-all">{link.url}</code></div><div className="flex gap-2"><Button variant="outline" size="sm" leftIcon={copiedLink === link.id ? <FiCheck /> : <FiCopy />} onClick={() => copyAccessLink(link.url!, link.id)}>{copiedLink === link.id ? 'Copiado!' : 'Copiar Link'}</Button><Button variant="outline" size="sm" leftIcon={<FiLink />} onClick={() => window.open(link.url!, '_blank')}>Abrir</Button></div></>)}</div>))}</div>)}
                        <div className="mb-6" style={{ marginTop: '24px' }}><div className="block text-[13px] text-text-muted mt-2"><strong>Como funciona:</strong><br />1. Copie o link desejado<br />2. Envie para o funcionário (WhatsApp, etc)<br />3. Funcionário acessa e digita seu PIN de 4 dígitos<br />4. Funcionário terá acesso apenas à página específica</div></div>
                    </div>
                );
            case 'conta':
                return (
                    <div className="p-6 sm:p-8">
                        <div className="mb-7 pb-5 border-b border-border"><h2 className="text-[1.375rem] font-semibold mb-1.5 text-text-primary">Minha Conta</h2><p className="text-sm text-text-muted">Informações da sua conta</p></div>
                        <div className="flex flex-col mb-8 bg-bg-tertiary rounded-md overflow-hidden"><div className="flex justify-between p-4 md:px-5 border-b border-border last:border-b-0"><span className="text-text-secondary">Email</span><span className="font-medium">{user?.email}</span></div><div className="flex justify-between p-4 md:px-5 border-b border-border last:border-b-0"><span className="text-text-secondary">Membro desde</span><span className="font-medium">{user?.created_at && new Intl.DateTimeFormat('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' }).format(new Date(user.created_at))}</span></div></div>
                        <div className="p-6 bg-red-500/5 border border-red-500/20 rounded-md"><h3 className="text-base font-semibold mb-1">Sair da Conta</h3><p className="text-sm text-text-muted">Você será desconectado do sistema</p><Button variant="danger" onClick={signOut}>Sair</Button></div>
                    </div>
                );
            case 'suporte':
                return (
                    <div className="p-6 sm:p-8">
                        <SupportTab />
                    </div>
                );
            default: return null;
        }
    };

    return (
        <div className="max-w-[1400px] mx-auto">
            <div className="mb-8"><h1 className="text-3xl font-bold mb-2">Configurações</h1><p className="text-text-secondary">Personalize seu aplicativo</p></div>
            <div className="grid grid-cols-1 md:grid-cols-[220px_1fr] gap-6 items-start">
                <div className="flex md:flex-col gap-2 md:gap-1 bg-bg-card rounded-xl p-3 border border-border sticky top-6 overflow-x-auto md:overflow-visible">{TABS.map((tab) => (<button key={tab.id} className={`flex items-center gap-3 px-4 py-3 bg-transparent border border-transparent md:border-none rounded-lg text-text-secondary text-[15px] font-medium cursor-pointer transition-all text-left hover:bg-bg-tertiary hover:text-text-primary whitespace-nowrap min-w-max md:min-w-0 ${activeTab === tab.id ? "!bg-primary/10 !text-primary" : ""}`} onClick={() => { if (tab.id === 'atalhos') { setShowHelp(true); } else { setActiveTab(tab.id); } }}><tab.icon /><span>{tab.label}</span></button>))}</div>
                <Card className="p-0 overflow-hidden">{renderTabContent()}</Card>
            </div>
        </div>
    );
}

export default function ConfiguracoesPage() {
    return (
        <Suspense fallback={
            <div className="flex items-center justify-center min-h-[400px]">
                <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary"></div>
            </div>
        }>
            <ConfiguracoesContent />
        </Suspense>
    );
}

