'use client';

import React, { useState, useRef, useCallback, useMemo } from 'react';
import { FiClock, FiCheck, FiVolume2, FiVolumeX, FiPrinter } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import UpgradePrompt from '@/components/ui/UpgradePrompt';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { useOrdersCache } from '@/hooks/useDataCache';
import { updateOrder } from '@/lib/dataAccess';
import type { CachedOrder } from '@/types/db';
import { printKitchenTicket } from '@/lib/print';
import { cn } from '@/lib/utils';

interface OrderItemAddon {
    id: string;
    addon_name: string;
    addon_price: number;
    quantity: number;
}

interface OrderItem {
    id: string;
    product_name: string;
    quantity: number;
    unit_price: number;
    total: number;
    notes: string | null;
    addons: OrderItemAddon[];
}

interface Order {
    id: string;
    order_number: number;
    customer_name: string;
    customer_phone: string | null;
    customer_address: string | null;
    status: string;
    payment_method: string;
    payment_status: string;
    subtotal: number;
    delivery_fee: number;
    total: number;
    notes: string | null;
    is_delivery: boolean;
    created_at: string;
    items: OrderItem[];
}

const KITCHEN_QUERY_KEY = ['kitchen-orders'];

export default function CozinhaPage() {
    const { plan, canAccess } = useSubscription();
    const { orders: rawOrders, loading } = useOrdersCache();
    const [soundEnabled, setSoundEnabled] = useState(true);
    const audioRef = useRef<HTMLAudioElement | null>(null);
    const prevOrdersCount = useRef(0);

    const playNotificationSound = useCallback(() => {
        if (audioRef.current) audioRef.current.play().catch(() => { });
    }, []);

    const orders = useMemo(() => {
        const filtered = rawOrders
            .filter((o: CachedOrder) => o.status === 'pending' || o.status === 'preparing')
            .sort((a: CachedOrder, b: CachedOrder) => new Date(a.created_at || 0).getTime() - new Date(b.created_at || 0).getTime());
        
        // Sound notification for new orders
        if (soundEnabled && !loading && filtered.length > prevOrdersCount.current) {
            playNotificationSound();
        }
        prevOrdersCount.current = filtered.length;
        
        return filtered;
    }, [rawOrders, soundEnabled, loading, playNotificationSound]);

    if (!canAccess('kitchen')) {
        return (
            <UpgradePrompt feature="Tela de Cozinha" requiredPlan="Profissional" currentPlan={plan} fullPage />
        );
    }

    const handleUpdateStatus = async (orderId: string, newStatus: string) => {
        try {
            await updateOrder(orderId, { status: newStatus });
        } catch (error) {
            console.error('Error updating order status:', error);
        }
    };

    const getTimeElapsed = (date: string) => {
        const now = new Date();
        const past = new Date(date);
        const diffMins = Math.floor((now.getTime() - past.getTime()) / 60000);
        if (diffMins < 1) return '< 1 min';
        if (diffMins < 60) return `${diffMins} min`;
        const hours = Math.floor(diffMins / 60);
        const mins = diffMins % 60;
        return `${hours}h ${mins}m`;
    };

    const getTimeColor = (date: string) => {
        const diffMins = Math.floor((new Date().getTime() - new Date(date).getTime()) / 60000);
        if (diffMins < 10) return 'text-accent';
        if (diffMins < 20) return 'text-warning';
        return 'text-error';
    };

    const pendingOrders = orders.filter((o: CachedOrder) => o.status === 'pending');
    const preparingOrders = orders.filter((o: CachedOrder) => o.status === 'preparing');

    const OrderCard = ({ order, isPreparing }: { order: CachedOrder; isPreparing?: boolean }) => (
        <Card className={cn('p-4! animate-[slideInUp_0.3s_ease]', isPreparing && 'border-info shadow-[0_0_0_1px_rgba(9,132,227,0.2)]')}>
            <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-2">
                    <span className="text-xl font-bold text-primary">#{order.order_number}</span>
                    <span className="text-xl">{order.is_delivery ? '🚚' : '🏪'}</span>
                </div>
                <div className={cn('flex items-center gap-1.5 text-sm font-semibold px-2.5 py-1 bg-white/5 rounded-full', getTimeColor(order.created_at || new Date().toISOString()))}>
                    <FiClock />
                    {getTimeElapsed(order.created_at || new Date().toISOString())}
                </div>
            </div>

            <div className="font-medium mb-3 pb-3 border-b border-border">{order.customer_name}</div>

            <div className="mb-4">
                {(order.order_items || []).map((item) => (
                    <div key={item.id} className="flex items-center gap-2 py-2 not-last:border-b not-last:border-dashed not-last:border-border">
                        <span className="font-bold text-primary min-w-8">{item.quantity}x</span>
                        <span className="flex-1 font-medium">{item.product_name}</span>
                        {item.notes && <span className="text-[0.8125rem] text-text-secondary italic">({item.notes})</span>}
                        {item.order_item_addons && item.order_item_addons.length > 0 && (
                            <div className="flex flex-wrap gap-1 w-full mt-1 pl-8">
                                {(item.order_item_addons || []).map((addon) => (
                                    <span key={addon.id} className="text-xs text-warning bg-warning/15 px-2 py-0.5 rounded-full font-medium">
                                        + {addon.addon_name}
                                    </span>
                                ))}
                            </div>
                        )}
                    </div>
                ))}
            </div>

            <div className="flex items-center gap-2">
                <Button
                    fullWidth
                    variant="primary"
                    leftIcon={isPreparing ? <FiCheck /> : undefined}
                    onClick={() => handleUpdateStatus(order.id, isPreparing ? 'ready' : 'preparing')}
                    style={isPreparing ? { background: 'var(--accent)' } : undefined}
                >
                    {isPreparing ? 'Marcar Pronto' : 'Iniciar Preparo'}
                </Button>
                <Button variant="ghost" leftIcon={<FiPrinter />} onClick={() => printKitchenTicket({ ...order, items: order.order_items || [] } as any)} title="Imprimir comanda" />
            </div>
        </Card>
    );

    return (
        <div className="max-w-[1400px] mx-auto">
            <audio ref={audioRef} src="https://koxmxvutlxlikeszwyir.supabase.co/storage/v1/object/public/sons/Cozinha.mp3" preload="auto" />

            {/* Header */}
            <div className="flex items-start justify-between mb-8 gap-5 max-md:flex-col">
                <div>
                    <h1 className="text-[2rem] font-bold mb-2">Cozinha</h1>
                    <p className="text-text-secondary">Fila de preparo • {orders.length} pedido{orders.length !== 1 ? 's' : ''} ativo{orders.length !== 1 ? 's' : ''}</p>
                </div>
                <Button variant={soundEnabled ? 'secondary' : 'ghost'} leftIcon={soundEnabled ? <FiVolume2 /> : <FiVolumeX />} onClick={() => setSoundEnabled(!soundEnabled)}>
                    {soundEnabled ? 'Som Ativo' : 'Som Mudo'}
                </Button>
            </div>

            {loading ? (
                <div className="grid grid-cols-2 gap-6 max-[1024px]:grid-cols-1">
                    <div className="h-[200px] rounded-2xl bg-bg-tertiary animate-pulse" />
                    <div className="h-[200px] rounded-2xl bg-bg-tertiary animate-pulse" />
                </div>
            ) : orders.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 px-5 text-center">
                    <span className="text-[5rem] mb-5">👨‍🍳</span>
                    <h3 className="text-2xl mb-2">Nenhum pedido na fila</h3>
                    <p className="text-text-secondary">Os novos pedidos aparecerão aqui automaticamente</p>
                </div>
            ) : (
                <div className="grid grid-cols-2 gap-6 items-start max-[1024px]:grid-cols-1">
                    {/* Pending Column */}
                    <div className="bg-bg-secondary rounded-lg border border-border overflow-hidden">
                        <div className="flex items-center justify-between px-5 py-4 bg-bg-tertiary border-b border-border">
                            <span className="flex items-center gap-2.5 font-semibold">
                                <span className="w-2.5 h-2.5 rounded-full bg-warning" />
                                Aguardando
                            </span>
                            <span className="px-3 py-1 bg-bg-card rounded-full text-sm font-semibold">{pendingOrders.length}</span>
                        </div>
                        <div className="p-4 flex flex-col gap-3 max-h-[calc(100vh-220px)] overflow-y-auto">
                            {pendingOrders.map((order) => <OrderCard key={order.id} order={order} />)}
                        </div>
                    </div>

                    {/* Preparing Column */}
                    <div className="bg-bg-secondary rounded-lg border border-border overflow-hidden">
                        <div className="flex items-center justify-between px-5 py-4 bg-bg-tertiary border-b border-border">
                            <span className="flex items-center gap-2.5 font-semibold">
                                <span className="w-2.5 h-2.5 rounded-full bg-info" />
                                Preparando
                            </span>
                            <span className="px-3 py-1 bg-bg-card rounded-full text-sm font-semibold">{preparingOrders.length}</span>
                        </div>
                        <div className="p-4 flex flex-col gap-3 max-h-[calc(100vh-220px)] overflow-y-auto">
                            {preparingOrders.map((order) => <OrderCard key={order.id} order={order} isPreparing />)}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useEffect, useState, useMemo, useCallback } from 'react';
import Link from 'next/link';
import {
    FiShoppingBag,
    FiDollarSign,
    FiTruck,
    FiClock,
    FiPlus,
    FiArrowRight,
    FiTrendingUp,
    FiTrendingDown,
    FiTarget,
    FiActivity
} from 'react-icons/fi';
import { GiCookingPot } from 'react-icons/gi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import { StatusBadge, type OrderStatus } from '@/components/ui/StatusBadge';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { useOrdersCache } from '@/hooks/useDataCache';
import type { CachedOrder } from '@/types/db';
import { formatCurrency, formatRelativeTime } from '@/hooks/useFormatters';
import { predictRemainingToday, getConfidenceLabel } from '@/lib/salesPrediction';
import { cn } from '@/lib/utils';
import { TrialBanner } from '@/components/subscription/TrialBanner';

interface Stats {
    totalOrders: number;
    totalRevenue: number;
    pendingOrders: number;
    pendingDeliveries: number;
    yesterdayRevenue: number;
    yesterdayOrders: number;
}

interface RecentOrder {
    id: string;
    order_number: number;
    customer_name: string;
    total: number;
    status: string;
    created_at: string;
}

interface HistoricalData {
    date: string;
    dayOfWeek: number;
    revenue: number;
    orders: number;
}

interface Prediction {
    predictedRevenue: number;
    predictedOrders: number;
    confidence: 'low' | 'medium' | 'high';
    basedOn: string;
}

export default function DashboardPage() {
    const { userSettings } = useAuth();
    const { canAccess } = useSubscription();
    const { orders: rawOrders, loading } = useOrdersCache();

    const appName = userSettings?.app_name || 'Cola Aí';

    const { stats, recentOrders, historicalData } = useMemo(() => {
        const todayStr = new Date().toISOString().split('T')[0];
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayStr = yesterday.toISOString().split('T')[0];
        
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
        thirtyDaysAgo.setHours(0, 0, 0, 0);

        const todayOrders = rawOrders.filter(o => o.created_at && o.created_at.startsWith(todayStr));
        const yesterdayOrders = rawOrders.filter(o => o.created_at && o.created_at.startsWith(yesterdayStr) && o.status !== 'cancelled');
        const historicalRecentOrders = rawOrders.filter(o => o.created_at && new Date(o.created_at) >= thirtyDaysAgo && o.status !== 'cancelled');

        const totalRevenue = todayOrders
            .filter(o => o.payment_status === 'paid')
            .reduce((sum, o) => sum + o.total, 0);

        const pendingOrders = todayOrders.filter(
            o => o.status === 'pending' || o.status === 'preparing'
        ).length;

        const pendingDeliveries = todayOrders.filter(
            o => o.status === 'delivering' || (o.status === 'ready' && o.is_delivery)
        ).length;

        const yesterdayRevenue = yesterdayOrders
            .filter(o => o.payment_status === 'paid')
            .reduce((sum, o) => sum + o.total, 0);

        // Daily data for predictions
        const dailyRecord: Record<string, { revenue: number; orders: number }> = {};
        historicalRecentOrders.forEach(order => {
            if (!order.created_at) return;
            const date = order.created_at.split('T')[0];
            if (!dailyRecord[date]) {
                dailyRecord[date] = { revenue: 0, orders: 0 };
            }
            if (order.payment_status === 'paid') {
                dailyRecord[date].revenue += order.total;
            }
            dailyRecord[date].orders++;
        });

        const historicalDataArr: HistoricalData[] = Object.entries(dailyRecord).map(([date, data]) => ({
            date,
            dayOfWeek: new Date(date + 'T12:00:00').getDay(),
            revenue: data.revenue,
            orders: data.orders
        }));

        return {
            stats: {
                totalOrders: todayOrders.length,
                totalRevenue,
                pendingOrders,
                pendingDeliveries,
                yesterdayRevenue,
                yesterdayOrders: yesterdayOrders.length
            },
            recentOrders: todayOrders.slice(0, 5),
            historicalData: historicalDataArr
        };
    }, [rawOrders]);

    const prediction = useMemo(() => {
        if (historicalData.length === 0) return null;
        return predictRemainingToday(
            historicalData,
            stats.totalRevenue,
            stats.totalOrders
        );
    }, [historicalData, stats.totalRevenue, stats.totalOrders]);

    const revenueChange = useMemo(() => {
        if (stats.yesterdayRevenue === 0) return stats.totalRevenue > 0 ? 100 : 0;
        return ((stats.totalRevenue - stats.yesterdayRevenue) / stats.yesterdayRevenue) * 100;
    }, [stats.totalRevenue, stats.yesterdayRevenue]);

    const ordersChange = useMemo(() => {
        if (stats.yesterdayOrders === 0) return stats.totalOrders > 0 ? 100 : 0;
        return ((stats.totalOrders - stats.yesterdayOrders) / stats.yesterdayOrders) * 100;
    }, [stats.totalOrders, stats.yesterdayOrders]);

    const progressToGoal = useMemo(() => {
        if (!prediction) return 0;
        return Math.min(100, (stats.totalRevenue / prediction.predictedRevenue) * 100);
    }, [stats.totalRevenue, prediction]);

    return (
        <div className="max-w-[1400px] mx-auto">
            {/* Header */}
            <div className="flex items-start justify-between mb-8 gap-5 max-md:flex-col">
                <div>
                    <h1 className="text-[2rem] font-bold mb-2">Dashboard</h1>
                    <p className="text-text-secondary">
                        Bem-vindo ao {appName}! Aqui está o resumo de hoje.
                    </p>
                </div>
                <Link href="/pedidos/novo">
                    <Button leftIcon={<FiPlus />}>Novo Pedido</Button>
                </Link>
            </div>

            {/* Trial Banner - Shows only during trial period */}
            <TrialBanner className="mb-6" />

            {/* Stats Grid */}
            <div className="grid grid-cols-4 gap-5 mb-8 max-[1200px]:grid-cols-2 max-md:grid-cols-1">
                <Card className="flex items-center gap-4 p-5! relative overflow-hidden" variant="gradient">
                    <div className="absolute top-0 right-0 w-[100px] h-[100px] bg-[radial-gradient(circle,rgba(var(--primary-rgb),0.05)_0%,transparent_70%)] rounded-full translate-x-[30%] -translate-y-[30%]" />
                    <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl shrink-0 bg-primary/10 text-primary">
                        <FiShoppingBag />
                    </div>
                    <div className="flex-1">
                        <span className="block text-sm text-text-secondary mb-1">Pedidos Hoje</span>
                        <span className="block text-2xl font-bold">{stats.totalOrders}</span>
                    </div>
                    <div className={cn('flex items-center gap-1 text-sm', ordersChange >= 0 ? 'text-accent' : 'text-error')}>
                        {ordersChange >= 0 ? <FiTrendingUp /> : <FiTrendingDown />}
                        <span>{ordersChange >= 0 ? '+' : ''}{ordersChange.toFixed(0)}%</span>
                    </div>
                </Card>

                <Card className="flex items-center gap-4 p-5! relative overflow-hidden" variant="gradient">
                    <div className="absolute top-0 right-0 w-[100px] h-[100px] bg-[radial-gradient(circle,rgba(var(--primary-rgb),0.05)_0%,transparent_70%)] rounded-full translate-x-[30%] -translate-y-[30%]" />
                    <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl shrink-0 bg-accent/10 text-accent">
                        <FiDollarSign />
                    </div>
                    <div className="flex-1">
                        <span className="block text-sm text-text-secondary mb-1">Receita do Dia</span>
                        <span className="block text-2xl font-bold">{formatCurrency(stats.totalRevenue)}</span>
                    </div>
                    <div className={cn('flex items-center gap-1 text-sm', revenueChange >= 0 ? 'text-accent' : 'text-error')}>
                        {revenueChange >= 0 ? <FiTrendingUp /> : <FiTrendingDown />}
                        <span>{revenueChange >= 0 ? '+' : ''}{revenueChange.toFixed(0)}%</span>
                    </div>
                </Card>

                <Card className="flex items-center gap-4 p-5! relative overflow-hidden" variant="gradient">
                    <div className="absolute top-0 right-0 w-[100px] h-[100px] bg-[radial-gradient(circle,rgba(var(--primary-rgb),0.05)_0%,transparent_70%)] rounded-full translate-x-[30%] -translate-y-[30%]" />
                    <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl shrink-0 bg-info/10 text-info">
                        <GiCookingPot />
                    </div>
                    <div className="flex-1">
                        <span className="block text-sm text-text-secondary mb-1">Em Preparo</span>
                        <span className="block text-2xl font-bold">{stats.pendingOrders}</span>
                    </div>
                    {stats.pendingOrders > 0 && (
                        <Link href="/cozinha" className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center text-text-secondary transition-all duration-fast hover:bg-white/10 hover:text-text-primary">
                            <FiArrowRight />
                        </Link>
                    )}
                </Card>

                <Card className="flex items-center gap-4 p-5! relative overflow-hidden" variant="gradient">
                    <div className="absolute top-0 right-0 w-[100px] h-[100px] bg-[radial-gradient(circle,rgba(var(--primary-rgb),0.05)_0%,transparent_70%)] rounded-full translate-x-[30%] -translate-y-[30%]" />
                    <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl shrink-0 bg-warning/10 text-warning">
                        <FiTruck />
                    </div>
                    <div className="flex-1">
                        <span className="block text-sm text-text-secondary mb-1">Para Entrega</span>
                        <span className="block text-2xl font-bold">{stats.pendingDeliveries}</span>
                    </div>
                    {stats.pendingDeliveries > 0 && (
                        <Link href="/entregas" className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center text-text-secondary transition-all duration-fast hover:bg-white/10 hover:text-text-primary">
                            <FiArrowRight />
                        </Link>
                    )}
                </Card>
            </div>

            {/* Sales Prediction Card */}
            {prediction && canAccess('salesPrediction') && (
                <Card className="p-6! mb-8 bg-linear-to-br from-[rgba(108,92,231,0.1)] to-[rgba(0,184,148,0.05)] border-[rgba(108,92,231,0.2)]">
                    <div className="flex justify-between items-center mb-6 flex-wrap gap-3">
                        <div className="flex items-center gap-2.5">
                            <FiTarget className="text-xl text-[#6c5ce7]" />
                            <h2 className="text-lg font-semibold text-text-primary m-0">Previsão para Hoje</h2>
                        </div>
                        <div className={cn(
                            'flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium uppercase',
                            prediction.confidence === 'high' && 'bg-accent/10 text-accent',
                            prediction.confidence === 'medium' && 'bg-warning/10 text-warning',
                            prediction.confidence === 'low' && 'bg-primary/10 text-primary'
                        )}>
                            <FiActivity />
                            {getConfidenceLabel(prediction.confidence)}
                        </div>
                    </div>

                    <div className="grid grid-cols-[auto_1fr] gap-8 items-center max-[900px]:grid-cols-1 max-[900px]:gap-5">
                        <div className="flex gap-8 max-[900px]:justify-around max-[480px]:flex-col max-[480px]:gap-4">
                            <div className="flex flex-col gap-1">
                                <span className="text-[0.8rem] text-text-secondary">Receita Prevista</span>
                                <span className="text-2xl font-bold text-text-primary">{formatCurrency(prediction.predictedRevenue)}</span>
                            </div>
                            <div className="flex flex-col gap-1">
                                <span className="text-[0.8rem] text-text-secondary">Pedidos Previstos</span>
                                <span className="text-2xl font-bold text-text-primary">{prediction.predictedOrders}</span>
                            </div>
                        </div>

                        <div className="flex flex-col gap-2">
                            <div className="flex justify-between items-center text-sm text-text-secondary">
                                <span>Progresso do Dia</span>
                                <span className="font-semibold text-accent">{progressToGoal.toFixed(0)}%</span>
                            </div>
                            <div className="w-full h-2.5 bg-bg-tertiary rounded-full overflow-hidden">
                                <div
                                    className="h-full bg-linear-to-r from-[#6c5ce7] to-accent rounded-full transition-[width] duration-500 ease-out"
                                    style={{ width: `${progressToGoal}%` }}
                                />
                            </div>
                            <span className="text-xs text-text-muted">
                                Baseado em: {prediction.basedOn}
                            </span>
                        </div>
                    </div>
                </Card>
            )}

            {/* Content Grid */}
            <div className="grid grid-cols-[1fr_400px] gap-6 max-[1200px]:grid-cols-1">
                {/* Recent Orders */}
                <Card className="p-6!">
                    <div className="flex items-center justify-between mb-5">
                        <h2 className="text-lg font-semibold">Pedidos Recentes</h2>
                        <Link href="/pedidos" className="flex items-center gap-1.5 text-sm text-primary transition-opacity duration-fast hover:opacity-80">
                            Ver todos <FiArrowRight />
                        </Link>
                    </div>

                    {loading ? (
                        <div className="flex flex-col gap-2">
                            {[1, 2, 3].map(i => (
                                <div key={i} className="h-[60px] rounded-md bg-bg-tertiary animate-pulse" />
                            ))}
                        </div>
                    ) : recentOrders.length > 0 ? (
                        <div className="flex flex-col gap-2">
                            {recentOrders.map((order) => (
                                <Link
                                    key={order.id}
                                    href={`/pedidos/${order.id}`}
                                    className="flex items-center justify-between px-4 py-3.5 bg-bg-tertiary rounded-md border border-transparent transition-all duration-fast hover:border-border hover:translate-x-1"
                                >
                                    <div className="flex items-center gap-3">
                                        <span className="font-semibold text-primary">#{order.order_number}</span>
                                        <span className="text-text-primary">{order.customer_name}</span>
                                    </div>
                                    <div className="flex items-center gap-4 max-[480px]:flex-col max-[480px]:items-end max-[480px]:gap-1">
                                        <StatusBadge
                                            status={order.status as OrderStatus}
                                            size="sm"
                                            showIcon
                                        />
                                        <span className="font-semibold text-accent">
                                            {formatCurrency(order.total)}
                                        </span>
                                        <span className="flex items-center gap-1 text-sm text-text-muted">
                                            <FiClock /> {formatRelativeTime(order.created_at || new Date().toISOString())}
                                        </span>
                                    </div>
                                </Link>
                            ))}
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center py-10 px-5 text-center">
                            <span className="text-5xl mb-3">📋</span>
                            <p className="text-text-secondary mb-4">Nenhum pedido hoje</p>
                            <Link href="/pedidos/novo">
                                <Button variant="outline" size="sm" leftIcon={<FiPlus />}>
                                    Criar Pedido
                                </Button>
                            </Link>
                        </div>
                    )}
                </Card>

                {/* Quick Actions */}
                <Card className="p-6!">
                    <div className="flex items-center justify-between mb-5">
                        <h2 className="text-lg font-semibold">Ações Rápidas</h2>
                    </div>

                    <div className="grid grid-cols-2 gap-3 max-md:grid-cols-3 max-[480px]:grid-cols-2">
                        <Link href="/pedidos/novo" className="flex flex-col items-center gap-2.5 px-4 py-5 bg-bg-tertiary rounded-md border border-transparent transition-all duration-fast text-center hover:border-border hover:-translate-y-0.5 group">
                            <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl bg-primary/10">
                                <FiPlus className="text-primary" />
                            </div>
                            <span className="text-sm font-medium text-text-secondary group-hover:text-text-primary">Novo Pedido</span>
                        </Link>

                        <Link href="/cozinha" className="flex flex-col items-center gap-2.5 px-4 py-5 bg-bg-tertiary rounded-md border border-transparent transition-all duration-fast text-center hover:border-border hover:-translate-y-0.5 group">
                            <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl bg-info/10">
                                <GiCookingPot className="text-info" />
                            </div>
                            <span className="text-sm font-medium text-text-secondary group-hover:text-text-primary">Ver Cozinha</span>
                        </Link>

                        <Link href="/entregas" className="flex flex-col items-center gap-2.5 px-4 py-5 bg-bg-tertiary rounded-md border border-transparent transition-all duration-fast text-center hover:border-border hover:-translate-y-0.5 group">
                            <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl bg-warning/10">
                                <FiTruck className="text-warning" />
                            </div>
                            <span className="text-sm font-medium text-text-secondary group-hover:text-text-primary">Entregas</span>
                        </Link>

                        <Link href="/caixa" className="flex flex-col items-center gap-2.5 px-4 py-5 bg-bg-tertiary rounded-md border border-transparent transition-all duration-fast text-center hover:border-border hover:-translate-y-0.5 group">
                            <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl bg-accent/10">
                                <FiDollarSign className="text-accent" />
                            </div>
                            <span className="text-sm font-medium text-text-secondary group-hover:text-text-primary">Abrir Caixa</span>
                        </Link>

                        <Link href="/produtos" className="flex flex-col items-center gap-2.5 px-4 py-5 bg-bg-tertiary rounded-md border border-transparent transition-all duration-fast text-center hover:border-border hover:-translate-y-0.5 group">
                            <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl bg-[rgba(155,89,182,0.1)]">
                                <FiShoppingBag className="text-[#9b59b6]" />
                            </div>
                            <span className="text-sm font-medium text-text-secondary group-hover:text-text-primary">Produtos</span>
                        </Link>

                        <Link href="/relatorios" className="flex flex-col items-center gap-2.5 px-4 py-5 bg-bg-tertiary rounded-md border border-transparent transition-all duration-fast text-center hover:border-border hover:-translate-y-0.5 group">
                            <div className="w-12 h-12 rounded-md flex items-center justify-center text-2xl bg-[rgba(52,152,219,0.1)]">
                                <FiTrendingUp className="text-[#3498db]" />
                            </div>
                            <span className="text-sm font-medium text-text-secondary group-hover:text-text-primary">Relatórios</span>
                        </Link>
                    </div>
                </Card>
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { FiCheck, FiPhone, FiMapPin, FiClock, FiVolume2, FiVolumeX } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import UpgradePrompt from '@/components/ui/UpgradePrompt';
import { StatusBadge } from '@/components/ui/StatusBadge';
import { useToast } from '@/components/ui/Toast';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { formatCurrency, formatRelativeTime, formatDateTime } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';
import { useOrdersCache } from '@/hooks/useDataCache';
import { updateOrder } from '@/lib/dataAccess';
import type { CachedOrder as Order } from '@/types/db';

export default function EntregasPage() {
    const { user } = useAuth();
    const { plan, canAccess } = useSubscription();
    const { orders: rawOrders, loading } = useOrdersCache();
    const [activeTab, setActiveTab] = useState<'pending' | 'history'>('pending');
    const [soundEnabled, setSoundEnabled] = useState(true);
    const audioRef = useRef<HTMLAudioElement | null>(null);
    const prevOrdersCount = useRef<number>(0);
    const toast = useToast();

    const orders = useMemo(() => {
        if (!rawOrders) return [];
        let filtered = rawOrders.filter(o => o.is_delivery);
        
        if (activeTab === 'pending') {
            filtered = filtered.filter(o => ['ready', 'delivering'].includes(o.status || ''));
            return filtered.sort((a, b) => new Date(a.created_at || 0).getTime() - new Date(b.created_at || 0).getTime());
        } else {
            filtered = filtered.filter(o => o.status === 'delivered');
            return filtered.sort((a, b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime());
        }
    }, [rawOrders, activeTab]);

    // Notification sound for new 'ready' orders
    useEffect(() => {
        if (!soundEnabled || loading) return;
        
        const readyCount = rawOrders.filter(o => o.is_delivery && o.status === 'ready').length;
        if (readyCount > prevOrdersCount.current) {
            if (audioRef.current) audioRef.current.play().catch(() => { });
        }
        prevOrdersCount.current = readyCount;
    }, [rawOrders, soundEnabled, loading]);

    if (!canAccess('deliveries')) {
        return <UpgradePrompt feature="Gestão de Entregas" requiredPlan="Avançado" currentPlan={plan} fullPage />;
    }

    const playNotificationSound = () => {
        if (audioRef.current) audioRef.current.play().catch(() => { });
    };

    const handleUpdateStatus = async (orderId: string, newStatus: string) => {
        try {
            await updateOrder(orderId, { status: newStatus, updated_at: new Date().toISOString() });
            toast.success(newStatus === 'delivering' ? 'Saiu para entrega!' : 'Entrega finalizada!');
        }
        catch (error) {
            console.error('Error updating order:', error);
            toast.error('Erro ao atualizar entrega');
        }
    };

    const readyOrders = orders.filter(o => o.status === 'ready');
    const deliveringOrders = orders.filter(o => o.status === 'delivering');

    return (
        <div className="max-w-[1400px] mx-auto">
            <audio ref={audioRef} src="https://koxmxvutlxlikeszwyir.supabase.co/storage/v1/object/public/sons/Entrega.mp3" preload="auto" />

            <div className="flex items-start justify-between mb-8 gap-5 max-md:flex-col">
                <div>
                    <h1 className="text-[2rem] font-bold mb-2">Entregas</h1>
                    <p className="text-text-secondary">Gerencie suas entregas</p>
                </div>
                <Button variant={soundEnabled ? 'secondary' : 'ghost'} leftIcon={soundEnabled ? <FiVolume2 /> : <FiVolumeX />} onClick={() => setSoundEnabled(!soundEnabled)}>
                    {soundEnabled ? 'Som Ativo' : 'Som Mudo'}
                </Button>
            </div>

            {/* Tabs */}
            <div className="flex gap-1 bg-bg-secondary p-1 rounded-lg mb-6 w-fit">
                <button className={cn('flex items-center gap-2 px-5 py-2.5 bg-transparent border-none rounded-md text-text-secondary text-[0.9375rem] font-medium cursor-pointer transition-all duration-fast hover:text-text-primary', activeTab === 'pending' && 'bg-bg-card text-text-primary')} onClick={() => setActiveTab('pending')}>
                    Pendentes
                    {activeTab === 'pending' && orders.length > 0 && <span className="px-2 py-0.5 bg-primary text-white text-xs font-semibold rounded-full">{orders.length}</span>}
                </button>
                <button className={cn('flex items-center gap-2 px-5 py-2.5 bg-transparent border-none rounded-md text-text-secondary text-[0.9375rem] font-medium cursor-pointer transition-all duration-fast hover:text-text-primary', activeTab === 'history' && 'bg-bg-card text-text-primary')} onClick={() => setActiveTab('history')}>
                    Histórico
                </button>
            </div>

            {loading ? (
                <div className="flex flex-col gap-3">
                    {[1, 2, 3].map(i => <div key={i} className="h-[140px] rounded-xl bg-bg-tertiary animate-pulse" />)}
                </div>
            ) : activeTab === 'pending' ? (
                orders.length > 0 ? (
                    <div className="grid grid-cols-2 gap-6 items-start max-md:grid-cols-1">
                        {/* Ready for Delivery */}
                        <div className="bg-bg-secondary rounded-lg border border-border p-4">
                            <h3 className="flex items-center gap-2.5 text-[0.9375rem] font-semibold mb-4 pb-3 border-b border-border">
                                <span className="w-2.5 h-2.5 rounded-full bg-accent" />
                                Prontos para Entrega ({readyOrders.length})
                            </h3>
                            <div className="flex flex-col gap-3">
                                {readyOrders.map((order) => (
                                    <Card key={order.id} className="p-4!">
                                        <div className="flex justify-between items-center mb-2">
                                            <span className="text-lg font-bold text-primary">#{order.order_number}</span>
                                            <span className="flex items-center gap-1 text-[0.8125rem] text-text-muted"><FiClock /> {formatRelativeTime(order.created_at || new Date().toISOString())}</span>
                                        </div>
                                        <div className="font-medium mb-2">{order.customer_name}</div>
                                        {order.customer_phone && <div className="flex items-center gap-2 text-sm text-text-secondary mb-1"><FiPhone /> {order.customer_phone}</div>}
                                        {order.customer_address && <div className="flex items-center gap-2 text-sm text-text-secondary mb-1"><FiMapPin /> {order.customer_address}</div>}
                                        <div className="flex justify-between items-center mt-3 pt-3 border-t border-border">
                                            <span className="text-lg font-bold text-accent">{formatCurrency(order.total)}</span>
                                            <Button size="sm" onClick={() => handleUpdateStatus(order.id, 'delivering')}>Saiu para Entrega</Button>
                                        </div>
                                    </Card>
                                ))}
                            </div>
                        </div>

                        {/* Delivering */}
                        <div className="bg-bg-secondary rounded-lg border border-border p-4">
                            <h3 className="flex items-center gap-2.5 text-[0.9375rem] font-semibold mb-4 pb-3 border-b border-border">
                                <span className="w-2.5 h-2.5 rounded-full bg-primary" />
                                Em Entrega ({deliveringOrders.length})
                            </h3>
                            <div className="flex flex-col gap-3">
                                {deliveringOrders.map((order) => (
                                    <Card key={order.id} className="p-4! border-primary">
                                        <div className="flex justify-between items-center mb-2">
                                            <span className="text-lg font-bold text-primary">#{order.order_number}</span>
                                            <span className="flex items-center gap-1 text-[0.8125rem] text-text-muted"><FiClock /> {formatRelativeTime(order.created_at || new Date().toISOString())}</span>
                                        </div>
                                        <div className="font-medium mb-2">{order.customer_name}</div>
                                        {order.customer_address && <div className="flex items-center gap-2 text-sm text-text-secondary mb-1"><FiMapPin /> {order.customer_address}</div>}
                                        <div className="flex justify-between items-center mt-3 pt-3 border-t border-border">
                                            <span className="text-lg font-bold text-accent">{formatCurrency(order.total)}</span>
                                            <Button size="sm" leftIcon={<FiCheck />} onClick={() => handleUpdateStatus(order.id, 'delivered')} style={{ background: 'var(--accent)' }}>Entregue</Button>
                                        </div>
                                    </Card>
                                ))}
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center py-20 px-5 text-center">
                        <span className="text-6xl mb-4">🚚</span>
                        <h3 className="text-xl mb-2">Nenhuma entrega pendente</h3>
                        <p className="text-text-secondary">As entregas prontas aparecerão aqui</p>
                    </div>
                )
            ) : (
                orders.length > 0 ? (
                    <div className="flex flex-col gap-2">
                        {orders.map((order) => (
                            <Card key={order.id} className="flex justify-between items-center px-5! py-4! max-md:flex-col max-md:items-start max-md:gap-3">
                                <div className="flex items-center gap-4">
                                    <span className="text-lg font-bold text-primary">#{order.order_number}</span>
                                    <span className="font-medium">{order.customer_name}</span>
                                </div>
                                <div className="flex items-center gap-4 max-md:w-full max-md:justify-between">
                                    <span className="text-lg font-bold text-accent">{formatCurrency(order.total)}</span>
                                    <span className="text-sm text-text-secondary">{formatDateTime(order.created_at || new Date().toISOString())}</span>
                                    <StatusBadge status="delivered" size="sm" />
                                </div>
                            </Card>
                        ))}
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center py-20 px-5 text-center">
                        <span className="text-6xl mb-4">📦</span>
                        <h3 className="text-xl mb-2">Nenhuma entrega no histórico</h3>
                        <p className="text-text-secondary">As entregas finalizadas aparecerão aqui</p>
                    </div>
                )
            )}
        </div>
    );
}

