'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { FiTrendingUp, FiTrendingDown, FiCalendar, FiRefreshCw, FiDollarSign, FiShoppingBag, FiToggleLeft, FiToggleRight, FiTrash2 } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import UpgradePrompt from '@/components/ui/UpgradePrompt';
import { useToast } from '@/components/ui/Toast';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { supabase } from '@/lib/supabase';
import { formatCurrency } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';
import { useCashFlowCache, useOrdersCache, useProductsCache, useCategoriesCache } from '@/hooks/useDataCache';
import { createCashFlowEntry, deleteCashFlowEntry } from '@/lib/dataAccess';

interface CashFlowEntry {
    id: string;
    type: 'income' | 'expense';
    category: string;
    description: string;
    amount: number;
    payment_method: string | null;
    transaction_date: string;
    created_at: string;
}

interface DailySummary {
    date: string;
    income: number;
    expense: number;
    balance: number;
}

interface CategoryDetail {
    name: string;
    count: number;
}

interface DailyCategoryInfo {
    date: string;
    itemCount: number;
    categories: CategoryDetail[];
}

export default function FluxoCaixaPage() {
    const { user } = useAuth();
    const { canAccess, plan } = useSubscription();

    const [period, setPeriod] = useState<'week' | 'month' | 'year'>('month');
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');

    // Cached Data
    const { entries, loading: loadingEntries, refetch: refetchEntries } = useCashFlowCache(dateFrom, dateTo);
    const { orders, loading: loadingOrders } = useOrdersCache();
    const { products } = useProductsCache();
    const { categories } = useCategoriesCache();

    // Derived State
    const [dailySummaries, setDailySummaries] = useState<DailySummary[]>([]);
    const [ordersRevenue, setOrdersRevenue] = useState(0);
    const [loadingRevenue, setLoadingRevenue] = useState(false);
    const [showCategoryDetails, setShowCategoryDetails] = useState(true);
    const [dailyCategoryInfo, setDailyCategoryInfo] = useState<DailyCategoryInfo[]>([]);

    const hasAccess = canAccess('cashFlow');
    const toast = useToast();

    useEffect(() => {
        const now = new Date();
        const from = new Date(now.getFullYear(), now.getMonth(), 1);
        const to = new Date(now.getFullYear(), now.getMonth() + 1, 0);
        setDateFrom(from.toISOString().split('T')[0]);
        setDateTo(to.toISOString().split('T')[0]);
    }, []);

    // Calculate statistics from cached data
    useEffect(() => {
        if (!orders || !dateFrom || !dateTo) return;
        
        const startDate = new Date(`${dateFrom}T00:00:00`);
        const endDate = new Date(`${dateTo}T23:59:59.999`);

        const filteredOrders = orders.filter(o => {
            const date = new Date(o.created_at || '');
            return o.payment_status === 'paid' && 
                   o.status !== 'cancelled' && 
                   date >= startDate && 
                   date <= endDate;
        });

        const totalRevenue = filteredOrders.reduce((sum, order) => sum + (order.total || 0), 0);
        setOrdersRevenue(totalRevenue);

        // Category breakdown logic using local data
        if (filteredOrders.length > 0) {
            const productCategoryMap = new Map<string, string>();
            products.forEach(p => {
                if (p.category_id) {
                    const cat = categories.find(c => c.id === p.category_id);
                    if (cat) productCategoryMap.set(p.id, cat.name);
                }
            });

            const dailyMap = new Map<string, { itemCount: number; categories: Map<string, number> }>();

            filteredOrders.forEach(order => {
                const date = (order.created_at || '').split('T')[0];
                if (!dailyMap.has(date)) {
                    dailyMap.set(date, { itemCount: 0, categories: new Map() });
                }

                // Dexie orders usually have items embedded or we use items cache
                // But for now let's assume we have what we need in the order object if it was cached with items
                // If items are NOT in CachedOrder, we might need useOrderItemsCache
                const info = dailyMap.get(date)!;
                // info.itemCount += ...; // Logic depends on how items are stored
            });
            
            // Note: Full category info requires items which might not be in CachedOrder
            // For now, let's keep the revenue calculation local and the complex item-category 
            // logic can be improved if CachedOrder includes items summary.
        }
    }, [orders, products, categories, dateFrom, dateTo]);

    // Recalcular DailySummaries quando entries mudar
    useEffect(() => {
        const summaryMap = new Map<string, { income: number; expense: number }>();
        entries.forEach(entry => {
            if (!summaryMap.has(entry.transaction_date)) summaryMap.set(entry.transaction_date, { income: 0, expense: 0 });
            const s = summaryMap.get(entry.transaction_date)!;
            if (entry.type === 'income') s.income += entry.amount; else s.expense += entry.amount;
        });
        const summaries: DailySummary[] = Array.from(summaryMap.entries()).map(([date, { income, expense }]) => ({ date, income, expense, balance: income - expense })).sort((a, b) => b.date.localeCompare(a.date));
        setDailySummaries(summaries);
    }, [entries]);

    const fetchData = useCallback(() => {
        refetchEntries();
    }, [refetchEntries]);

    const handleDeleteEntry = async (id: string) => {
        if (!confirm('Tem certeza que deseja excluir esta movimentação? Essa ação não pode ser desfeita.')) return;

        try {
            await deleteCashFlowEntry(id);
            toast.success('Movimentação excluída com sucesso!');
        } catch (error) {
            console.error('Erro ao excluir movimentação:', error);
            toast.error('Erro ao excluir movimentação');
        }
    };

    const loading = loadingEntries || loadingOrders;

    if (!hasAccess) {
        return <UpgradePrompt feature="Fluxo de Caixa" requiredPlan="Avançado" currentPlan={plan} fullPage />;
    }

    const setPeriodDates = (p: 'week' | 'month' | 'year') => {
        const now = new Date();
        let from: Date;
        if (p === 'week') from = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        else if (p === 'month') from = new Date(now.getFullYear(), now.getMonth(), 1);
        else from = new Date(now.getFullYear(), 0, 1);
        setPeriod(p);
        setDateFrom(from.toISOString().split('T')[0]);
        setDateTo(now.toISOString().split('T')[0]);
        // Reset orders revenue when period changes
        setOrdersRevenue(0);
        setDailyCategoryInfo([]);
    };

    const formatDateShort = (date: string) => new Date(date + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: 'short' });

    const income = entries.filter(e => e.type === 'income').reduce((sum, e) => sum + e.amount, 0);
    const expense = entries.filter(e => e.type === 'expense').reduce((sum, e) => sum + e.amount, 0);
    const totals = { income, expense, balance: (income + ordersRevenue) - expense };

    // Total combinado: entradas + receita de pedidos
    const totalCombined = totals.income + ordersRevenue;

    const categoryBreakdown = (type: 'income' | 'expense') => {
        const categories = new Map<string, number>();
        entries.filter(e => e.type === type).forEach(e => categories.set(e.category, (categories.get(e.category) || 0) + e.amount));
        return Array.from(categories.entries()).sort((a, b) => b[1] - a[1]).slice(0, 5);
    };

    // Helper para obter info de categoria de um dia específico
    const getCategoryInfoForDate = (date: string) => {
        return dailyCategoryInfo.find(info => info.date === date);
    };

    return (
        <div className="max-w-[1400px] mx-auto">
            <div className="flex justify-between items-start mb-8">
                <div>
                    <h1 className="text-[2rem] font-bold mb-2">Fluxo de Caixa</h1>
                    <p className="text-text-secondary">Acompanhe entradas e saídas</p>
                </div>
                <div className="flex gap-3">
                    <Button
                        variant="outline"
                        leftIcon={<FiDollarSign />}
                        onClick={() => refetchEntries()}
                        isLoading={loadingEntries}
                        title="Isso é feito automaticamente, mas você pode forçar uma atualização da nuvem"
                    >
                        Atualizar
                    </Button>
                </div>
            </div>

            {/* Period Filter */}
            <div className="flex justify-between items-center mb-6 gap-4 flex-wrap max-md:flex-col max-md:items-stretch">
                <div className="flex gap-2">
                    {[{ value: 'week', label: 'Semana' }, { value: 'month', label: 'Mês' }, { value: 'year', label: 'Ano' }].map(p => (
                        <button key={p.value} className={cn('px-5 py-2.5 bg-bg-tertiary border border-border rounded-md text-text-secondary text-sm font-medium cursor-pointer transition-all duration-fast hover:border-primary', period === p.value && 'bg-primary border-primary text-white')} onClick={() => setPeriodDates(p.value as 'week' | 'month' | 'year')}>{p.label}</button>
                    ))}
                </div>
                <div className="flex items-center gap-3 text-text-muted max-md:flex-wrap">
                    <FiCalendar />
                    <input type="date" className="px-3.5 py-2.5 bg-bg-tertiary border border-border rounded-md text-text-primary text-sm" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} />
                    <span>até</span>
                    <input type="date" className="px-3.5 py-2.5 bg-bg-tertiary border border-border rounded-md text-text-primary text-sm" value={dateTo} onChange={(e) => setDateTo(e.target.value)} />
                </div>
            </div>

            {/* Summary Grid */}
            <div className="grid grid-cols-4 gap-4 mb-6 max-md:grid-cols-1 max-lg:grid-cols-2">
                <Card className="flex items-center gap-4 p-6!">
                    <div className="w-12 h-12 flex items-center justify-center rounded-md text-2xl bg-[#27ae60]/10 text-[#27ae60]"><FiTrendingUp /></div>
                    <div className="flex flex-col"><span className="text-[0.8125rem] text-text-muted mb-1">Entradas</span><span className="text-2xl font-bold text-[#27ae60]">{formatCurrency(totals.income)}</span></div>
                </Card>
                <Card className="flex items-center gap-4 p-6!">
                    <div className="w-12 h-12 flex items-center justify-center rounded-md text-2xl bg-primary/10 text-primary"><FiShoppingBag /></div>
                    <div className="flex flex-col">
                        <span className="text-[0.8125rem] text-text-muted mb-1">Receita de Pedidos</span>
                        <span className="text-2xl font-bold text-primary">{formatCurrency(ordersRevenue)}</span>
                        {ordersRevenue > 0 && <span className="text-xs text-text-muted mt-0.5">Total: {formatCurrency(totalCombined)}</span>}
                    </div>
                </Card>
                <Card className="flex items-center gap-4 p-6!">
                    <div className="w-12 h-12 flex items-center justify-center rounded-md text-2xl bg-error/10 text-error"><FiTrendingDown /></div>
                    <div className="flex flex-col"><span className="text-[0.8125rem] text-text-muted mb-1">Saídas</span><span className="text-2xl font-bold text-error">{formatCurrency(totals.expense)}</span></div>
                </Card>
                <Card className="flex items-center gap-4 p-6!">
                    <div className="flex flex-col"><span className="text-[0.8125rem] text-text-muted mb-1">Saldo do Período</span><span className={cn('text-2xl font-bold', totals.balance >= 0 ? 'text-[#27ae60]' : 'text-error')}>{totals.balance >= 0 ? '+' : ''}{formatCurrency(totals.balance)}</span></div>
                </Card>
            </div>

            <div className="grid grid-cols-[2fr_1fr] gap-6 mb-6 max-[1024px]:grid-cols-1">
                {/* Daily Summary */}
                <Card className="max-h-[400px] overflow-y-auto">
                    <div className="flex items-center justify-between mb-4">
                        <h2 className="text-base font-semibold">Resumo Diário</h2>
                        {dailyCategoryInfo.length > 0 && (
                            <button
                                onClick={() => setShowCategoryDetails(!showCategoryDetails)}
                                className="flex items-center gap-2 text-sm text-text-secondary hover:text-primary transition-colors"
                                title={showCategoryDetails ? 'Ocultar categorias' : 'Mostrar categorias'}
                            >
                                {showCategoryDetails ? <FiToggleRight className="text-primary text-xl" /> : <FiToggleLeft className="text-xl" />}
                                <span className="max-md:hidden">Categorias</span>
                            </button>
                        )}
                    </div>
                    {loading ? <div className="p-8 text-center text-text-secondary">Carregando...</div> : dailySummaries.length === 0 ? <div className="p-8 text-center text-text-muted">Nenhuma movimentação no período</div> : (
                        <div className="flex flex-col">
                            {dailySummaries.map(day => {
                                const categoryInfo = getCategoryInfoForDate(day.date);
                                return (
                                    <div key={day.date} className="py-3 border-b border-border last:border-b-0">
                                        <div className="flex items-center justify-between">
                                            <span className="font-medium min-w-[100px]">{formatDateShort(day.date)}</span>
                                            <div className="flex gap-4"><span className="text-sm text-[#27ae60]">+{formatCurrency(day.income)}</span><span className="text-sm text-error">-{formatCurrency(day.expense)}</span></div>
                                            <span className={cn('font-semibold min-w-[100px] text-right', day.balance >= 0 ? 'text-[#27ae60]' : 'text-error')}>{day.balance >= 0 ? '+' : ''}{formatCurrency(day.balance)}</span>
                                        </div>
                                        {showCategoryDetails && categoryInfo && categoryInfo.itemCount > 0 && (
                                            <div className="mt-2 pl-4 text-xs text-text-muted flex flex-wrap gap-2 items-center">
                                                <span className="font-medium text-text-secondary">{categoryInfo.itemCount} {categoryInfo.itemCount === 1 ? 'item' : 'itens'} vendido{categoryInfo.itemCount === 1 ? '' : 's'}:</span>
                                                {categoryInfo.categories.map((cat) => (
                                                    <span key={cat.name} className="bg-bg-tertiary px-2 py-0.5 rounded-full">
                                                        {cat.name}: {cat.count}
                                                    </span>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </Card>

                {/* Category Breakdown */}
                <div className="flex flex-col gap-4 max-[1024px]:flex-row max-md:flex-col">
                    <Card className="p-4! flex-1">
                        <h3 className="flex items-center gap-2 text-sm font-semibold mb-3 text-text-secondary"><FiTrendingUp /> Top Entradas</h3>
                        <div className="flex flex-col gap-2">{categoryBreakdown('income').map(([category, amount]) => <div key={category} className="flex justify-between text-sm"><span>{category}</span><span className="font-medium">{formatCurrency(amount)}</span></div>)}{categoryBreakdown('income').length === 0 && <p className="text-text-muted text-sm text-center py-4">Sem dados</p>}</div>
                    </Card>
                    <Card className="p-4! flex-1">
                        <h3 className="flex items-center gap-2 text-sm font-semibold mb-3 text-text-secondary"><FiTrendingDown /> Top Saídas</h3>
                        <div className="flex flex-col gap-2">{categoryBreakdown('expense').map(([category, amount]) => <div key={category} className="flex justify-between text-sm"><span>{category}</span><span className="font-medium">{formatCurrency(amount)}</span></div>)}{categoryBreakdown('expense').length === 0 && <p className="text-text-muted text-sm text-center py-4">Sem dados</p>}</div>
                    </Card>
                </div>
            </div>

            {/* Transactions */}
            <Card>
                <h2 className="text-base font-semibold mb-4">Movimentações</h2>
                {loading ? <div className="p-8 text-center text-text-secondary">Carregando...</div> : entries.length === 0 ? (
                    <div className="p-8 text-center text-text-muted"><p>Nenhuma movimentação registrada</p><small className="block mt-2 text-xs">As movimentações são criadas automaticamente ao marcar contas como pagas</small></div>
                ) : (
                    <div className="flex flex-col">
                        {entries.map(entry => (
                            <div key={entry.id} className="grid grid-cols-[40px_1fr_120px_120px_40px] items-center gap-4 py-3 border-b border-border last:border-b-0 max-md:grid-cols-[40px_1fr_80px_40px]">
                                <div className={cn('w-9 h-9 flex items-center justify-center rounded-full text-base', entry.type === 'income' ? 'bg-[#27ae60]/10 text-[#27ae60]' : 'bg-error/10 text-error')}>
                                    {entry.type === 'income' ? <FiTrendingUp /> : <FiTrendingDown />}
                                </div>
                                <div className="flex flex-col gap-0.5"><span className="font-medium">{entry.description}</span><span className="text-xs text-text-muted">{entry.category}</span></div>
                                <div className="flex flex-col items-end max-md:hidden"><span className="text-[0.8125rem]">{new Date(entry.transaction_date + 'T12:00:00').toLocaleDateString('pt-BR')}</span>{entry.payment_method && <span className="text-xs text-text-muted">{entry.payment_method}</span>}</div>
                                <span className={cn('font-semibold text-right', entry.type === 'income' ? 'text-[#27ae60]' : 'text-error')}>{entry.type === 'income' ? '+' : '-'}{formatCurrency(entry.amount)}</span>
                                <button
                                    onClick={() => handleDeleteEntry(entry.id)}
                                    className="p-2 text-text-muted hover:text-error hover:bg-error/10 rounded-md transition-colors flex items-center justify-center"
                                    title="Excluir movimentação"
                                >
                                    <FiTrash2 />
                                </button>
                            </div>
                        ))}
                    </div>
                )}
            </Card>
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { FiPlus, FiEdit2, FiTrash2, FiUser, FiUsers, FiShield, FiPhone, FiMail, FiToggleLeft, FiToggleRight, FiLock } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import UpgradePrompt from '@/components/ui/UpgradePrompt';
import { useEmployeesCache } from '@/hooks/useDataCache';
import { cn } from '@/lib/utils';
import EditEmployeeSheet, { EmployeeData } from '@/components/funcionarios/EditEmployeeSheet';
import type { CachedEmployee } from '@/types/db';

type Employee = CachedEmployee;

const ROLES = [
    { value: 'admin', label: 'Administrador', icon: '👑', color: '#9b59b6' },
    { value: 'manager', label: 'Gerente', icon: '📋', color: '#3498db' },
    { value: 'cashier', label: 'Caixa', icon: '💵', color: '#27ae60' },
    { value: 'kitchen', label: 'Cozinha', icon: '👨‍🍳', color: '#e67e22' },
    { value: 'attendant', label: 'Atendente', icon: '🧑‍💼', color: '#1abc9c' },
    { value: 'delivery', label: 'Entregador', icon: '🚴', color: '#e74c3c' }
];

const DEFAULT_PERMISSIONS: Record<string, Record<string, boolean>> = {
    admin: { orders: true, products: true, categories: true, customers: true, reports: true, settings: true, employees: true, finance: true },
    manager: { orders: true, products: true, categories: true, customers: true, reports: true, settings: false, employees: true, finance: true },
    cashier: { orders: true, products: false, categories: false, customers: true, reports: false, settings: false, employees: false, finance: true },
    kitchen: { orders: true, products: false, categories: false, customers: false, reports: false, settings: false, employees: false, finance: false },
    attendant: { orders: true, products: true, categories: false, customers: true, reports: false, settings: false, employees: false, finance: false },
    delivery: { orders: true, products: false, categories: false, customers: true, reports: false, settings: false, employees: false, finance: false }
};

export default function FuncionariosPage() {
    const { user } = useAuth();
    const { plan, isWithinLimit, getLimit } = useSubscription();
    const { employees, loading, error: cacheError } = useEmployeesCache();
    const [showModal, setShowModal] = useState(false);
    const [showUpgradeModal, setShowUpgradeModal] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    const handleAddClick = () => { 
        const regularEmployees = employees.filter(e => !e.is_fixed); 
        if (!isWithinLimit('employees', regularEmployees.length)) { 
            setShowUpgradeModal(true); 
            return; 
        } 
        setEditingEmployee(null); 
        setShowModal(true); 
    };

    const handleSave = async (updatedData: EmployeeData) => {
        if (!user) return;
        
        const isCreating = !editingEmployee;
        const { createEmployee, updateEmployee } = await import('@/lib/dataAccess');
        
        if (editingEmployee?.is_fixed) {
            await updateEmployee(editingEmployee.id, { pin_code: updatedData.pin_code || null });
            setShowModal(false);
            setEditingEmployee(null);
            return;
        }

        const employeeData = {
            user_id: user.id,
            name: updatedData.name,
            email: updatedData.email || null,
            phone: updatedData.phone || null,
            role: updatedData.role,
            pin_code: updatedData.pin_code || null,
            hourly_rate: updatedData.hourly_rate || null,
            salario_fixo: updatedData.salario_fixo || 0,
            is_active: updatedData.is_active,
            permissions: DEFAULT_PERMISSIONS[updatedData.role as keyof typeof DEFAULT_PERMISSIONS] || DEFAULT_PERMISSIONS.attendant
        };

        if (isCreating) {
            await createEmployee(employeeData);
        } else {
            await updateEmployee(editingEmployee.id, employeeData);
        }

        setShowModal(false);
        setEditingEmployee(null);
    };

    const handleToggleActive = async (employee: Employee) => { 
        if (!user) return; 
        const { updateEmployee } = await import('@/lib/dataAccess');
        await updateEmployee(employee.id, { is_active: !employee.is_active }); 
    };

    const handleDelete = async (employee: Employee) => { 
        if (!user) return; 
        if (employee.is_fixed) { 
            alert('Este funcionário é fixo e não pode ser removido.'); 
            return; 
        } 
        if (!confirm('Excluir este funcionário?')) return; 
        const { deleteEmployee } = await import('@/lib/dataAccess');
        await deleteEmployee(employee.id); 
    };
    const openEdit = (employee: Employee) => { setEditingEmployee(employee); setShowModal(true); };
    const getRoleInfo = (role: string) => ROLES.find(r => r.value === role) || ROLES[4];

    const regularEmployees = employees.filter((e: Employee) => !e.is_fixed);
    const fixedEmployees = employees.filter((e: Employee) => e.is_fixed);
    const stats = { 
        total: regularEmployees.length, 
        active: regularEmployees.filter((e: Employee) => e.is_active).length, 
        byRole: ROLES.map(r => ({ ...r, count: employees.filter((e: Employee) => e.role === r.value).length })) 
    };

    return (
        <div className="max-w-[1400px] mx-auto">
            <div className="flex justify-between items-start mb-8 gap-5 max-md:flex-col">
                <div><h1 className="text-[2rem] font-bold mb-2">Funcionários</h1><p className="text-text-secondary">Gerencie sua equipe ({regularEmployees.length}/{getLimit('employees') === Infinity ? '∞' : getLimit('employees')}){fixedEmployees.length > 0 && <span className="opacity-70 ml-2">+ {fixedEmployees.length} fixo(s)</span>}</p></div>
                <Button leftIcon={<FiPlus />} onClick={handleAddClick}>Novo Funcionário</Button>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-4 gap-4 mb-6 max-md:grid-cols-2 max-[480px]:grid-cols-1">
                <Card className="flex items-center gap-4 p-5!"><FiUsers className="text-2xl text-primary" /><div className="flex flex-col"><span className="text-xl font-bold">{stats.total}</span><span className="text-[0.8125rem] text-text-muted">Total</span></div></Card>
                <Card className="flex items-center gap-4 p-5!"><FiUser className="text-2xl text-[#27ae60]" /><div className="flex flex-col"><span className="text-xl font-bold">{stats.active}</span><span className="text-[0.8125rem] text-text-muted">Ativos</span></div></Card>
                {stats.byRole.filter(r => r.count > 0).slice(0, 2).map(r => (
                    <Card key={r.value} className="flex items-center gap-4 p-5!"><span className="text-2xl">{r.icon}</span><div className="flex flex-col"><span className="text-xl font-bold">{r.count}</span><span className="text-[0.8125rem] text-text-muted">{r.label}</span></div></Card>
                ))}
            </div>

            {/* Employees List */}
            <Card>
                {loading ? <div className="p-12 text-center text-text-secondary">Carregando...</div> : employees.length === 0 ? (
                    <div className="flex flex-col items-center p-12 text-center text-text-muted"><FiUsers size={48} className="mb-4 opacity-50" /><h3 className="text-lg font-semibold text-text-secondary mb-2">Nenhum funcionário cadastrado</h3><p>Adicione sua equipe para gerenciar permissões</p></div>
                ) : (
                    <div className="flex flex-col">
                        {employees.map(employee => {
                            const roleInfo = getRoleInfo(employee.role);
                            return (
                                <div key={employee.id} className={cn('flex items-center gap-4 p-4 border-b border-border transition-all duration-fast hover:bg-bg-tertiary last:border-b-0 max-md:flex-wrap', !employee.is_active && 'opacity-50')}>
                                    <div className="w-12 h-12 flex items-center justify-center rounded-full border-2 text-xl" style={{ borderColor: roleInfo.color }}><span>{roleInfo.icon}</span></div>
                                    <div className="flex-1 min-w-[150px]"><span className="font-medium block">{employee.name}</span><div className="flex items-center gap-3 text-xs text-text-muted mt-1 flex-wrap">{employee.email && <span className="flex items-center gap-1"><FiMail size={12} /> {employee.email}</span>}{employee.phone && <span className="flex items-center gap-1"><FiPhone size={12} /> {employee.phone}</span>}</div></div>
                                    <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium" style={{ background: `${roleInfo.color}20`, color: roleInfo.color }}><FiShield size={12} />{roleInfo.label}{employee.is_fixed && <span className="flex items-center gap-1 ml-1 text-[10px] opacity-70" title="Fixo"><FiLock size={10} /> FIXO</span>}</div>
                                    <button className={cn('p-1 bg-transparent border-none cursor-pointer transition-all duration-fast', employee.is_active ? 'text-[#27ae60]' : 'text-text-muted')} onClick={() => handleToggleActive(employee)} title={employee.is_active ? 'Desativar' : 'Ativar'} disabled={employee.is_fixed}>{employee.is_active ? <FiToggleRight size={24} /> : <FiToggleLeft size={24} />}</button>
                                    <div className="flex gap-2 w-full md:w-auto justify-end mt-2 md:mt-0"><button className="p-2 bg-transparent border border-border rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:text-primary hover:border-primary" onClick={() => window.location.href = `/funcionarios/${employee.id}`} title="Painel de Ganhos">📊</button><button className="p-2 bg-transparent border border-border rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:text-text-primary hover:border-border-light" onClick={() => openEdit(employee)} title={employee.is_fixed ? 'Alterar PIN' : 'Editar'}><FiEdit2 /></button>{!employee.is_fixed && <button className="p-2 bg-transparent border border-border rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:text-error hover:border-error" onClick={() => handleDelete(employee)}><FiTrash2 /></button>}</div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </Card>

            {/* Unified Employee Modal */}
            <EditEmployeeSheet 
                isOpen={showModal}
                onClose={() => setShowModal(false)}
                employee={editingEmployee as unknown as EmployeeData}
                onSave={handleSave}
            />

            {/* Upgrade Modal */}
            {showUpgradeModal && (
                <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-1000 p-4" onClick={() => setShowUpgradeModal(false)}>
                    <div className="bg-bg-card border border-border rounded-lg p-6 w-full max-w-[600px]" onClick={e => e.stopPropagation()}>
                        <UpgradePrompt feature="Limite de Funcionários Atingido" requiredPlan={plan === 'Basico' ? 'Avançado' : 'Profissional'} currentPlan={plan} />
                        <div className="mt-4 text-center"><Button variant="ghost" onClick={() => setShowUpgradeModal(false)}>Fechar</Button></div>
                    </div>
                </div>
            )}

            {/* Upgrade Modal */}
            {showUpgradeModal && (
                <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-1000 p-4" onClick={() => setShowUpgradeModal(false)}>
                    <div className="bg-bg-card border border-border rounded-lg p-6 w-full max-w-[600px]" onClick={e => e.stopPropagation()}>
                        <UpgradePrompt feature="Limite de Funcionários Atingido" requiredPlan={plan === 'Basico' ? 'Avançado' : 'Profissional'} currentPlan={plan} />
                        <div className="mt-4 text-center"><Button variant="ghost" onClick={() => setShowUpgradeModal(false)}>Fechar</Button></div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { FiActivity, FiFilter, FiCalendar, FiRefreshCw, FiChevronLeft, FiChevronRight, FiTrash2 } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import UpgradePrompt from '@/components/ui/UpgradePrompt';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { supabase } from '@/lib/supabase';
import { getActionTypeLabel, getEntityTypeLabel, getActionIcon, ActionType, EntityType } from '@/lib/actionLogger';
import { useActionLogsCache } from '@/hooks/useDataCache';
import { clearActionLogsDAL } from '@/lib/dataAccess';

const PAGE_SIZE = 20;

export default function HistoricoPage() {
    const { user } = useAuth();
    const { canAccess, plan } = useSubscription();
    
    const [page, setPage] = useState(1);
    const [filterAction, setFilterAction] = useState<ActionType | ''>('');
    const [filterEntity, setFilterEntity] = useState<EntityType | ''>('');
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [cleaning, setCleaning] = useState(false);

    const hasAccess = canAccess('actionHistory');

    const { logs, totalCount, loading, refetch } = useActionLogsCache(PAGE_SIZE, page, {
        action: filterAction || undefined,
        entity: filterEntity || undefined,
        from: dateFrom || undefined,
        to: dateTo || undefined
    });

    if (!hasAccess) return <UpgradePrompt feature="Histórico de Ações" requiredPlan="Avançado" currentPlan={plan} fullPage />;

    const clearFilters = () => { setFilterAction(''); setFilterEntity(''); setDateFrom(''); setDateTo(''); setPage(1); };

    const cleanupOldLogs = async () => { 
        if (!user) return; 
        if (!confirm('Deseja apagar logs com mais de 7 dias?')) return; 
        setCleaning(true); 
        try { 
            const sevenDaysAgo = new Date(); 
            sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7); 
            
            await clearActionLogsDAL(user.id, sevenDaysAgo.toISOString());
            await refetch(); 
        } catch (e) { 
            console.error(e); 
        } finally { 
            setCleaning(false); 
        } 
    };

    const clearAllLogs = async () => { 
        if (!user) return; 
        if (!confirm('Tem certeza que deseja apagar TODO o histórico de ações?')) return; 
        setCleaning(true); 
        try { 
            await clearActionLogsDAL(user.id);
            await refetch();
        } catch (e) { 
            console.error(e); 
        } finally { 
            setCleaning(false); 
        } 
    };

    const formatDateTime = (dateString: string) => new Intl.DateTimeFormat('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }).format(new Date(dateString));
    const getRelativeTime = (dateString: string) => { const date = new Date(dateString); const diffMs = Date.now() - date.getTime(); const diffMins = Math.floor(diffMs / 60000); const diffHours = Math.floor(diffMs / 3600000); const diffDays = Math.floor(diffMs / 864000000); if (diffMins < 1) return 'agora'; if (diffMins < 60) return `há ${diffMins} min`; if (diffHours < 24) return `há ${diffHours}h`; if (diffDays < 7) return `há ${diffDays} dias`; return formatDateTime(dateString); };

    const totalPages = Math.ceil(totalCount / PAGE_SIZE);
    const actionTypes: ActionType[] = ['create', 'update', 'delete', 'status_change', 'payment', 'stock_movement', 'print', 'export', 'login', 'logout'];
    const entityTypes: EntityType[] = ['order', 'product', 'category', 'customer', 'coupon', 'ingredient', 'reward', 'addon', 'settings', 'report'];

    return (
        <div className="max-w-[1400px] mx-auto">
            {/* Header */}
            <div className="flex justify-between items-start mb-8 gap-5 flex-wrap">
                <div className="w-full md:w-auto"><h1 className="text-[2rem] font-bold mb-2">Histórico de Ações</h1><p className="text-text-secondary">{totalCount} {totalCount === 1 ? 'registro encontrado' : 'registros encontrados'}</p></div>
                <div className="flex w-full md:w-auto gap-2 flex-wrap">
                    <Button variant="outline" className="flex-1 md:flex-none" leftIcon={<FiRefreshCw />} onClick={() => refetch()}>Atualizar</Button>
                    {totalCount > 0 && (<><Button variant="outline" className="flex-1 md:flex-none" leftIcon={<FiTrash2 />} onClick={cleanupOldLogs} isLoading={cleaning}>Limpar +7 dias</Button><Button variant="ghost" className="flex-1 md:flex-none text-error!" leftIcon={<FiTrash2 />} onClick={clearAllLogs} isLoading={cleaning}>Limpar Tudo</Button></>)}
                </div>
            </div>

            {/* Filters */}
            <Card className="mb-6 p-4!">
                <div className="grid grid-cols-1 sm:grid-cols-2 md:flex md:flex-wrap md:items-end gap-4">
                    <div className="flex flex-col gap-1 w-full"><label className="text-sm text-text-secondary flex items-center gap-1"><FiFilter /> Tipo de Ação</label><select className="px-3 py-2 bg-bg-tertiary border border-border rounded-md text-text-primary text-sm w-full" value={filterAction} onChange={(e) => { setFilterAction(e.target.value as ActionType | ''); setPage(1); }}><option value="">Todas</option>{actionTypes.map(type => (<option key={type} value={type}>{getActionTypeLabel(type)}</option>))}</select></div>
                    <div className="flex flex-col gap-1 w-full"><label className="text-sm text-text-secondary">Entidade</label><select className="px-3 py-2 bg-bg-tertiary border border-border rounded-md text-text-primary text-sm w-full" value={filterEntity} onChange={(e) => { setFilterEntity(e.target.value as EntityType | ''); setPage(1); }}><option value="">Todas</option>{entityTypes.map(type => (<option key={type} value={type}>{getEntityTypeLabel(type)}</option>))}</select></div>
                    <div className="flex flex-col gap-1 w-full"><label className="text-sm text-text-secondary flex items-center gap-1"><FiCalendar /> De</label><input type="date" className="px-3 py-2 bg-bg-tertiary border border-border rounded-md text-text-primary text-sm w-full" value={dateFrom} onChange={(e) => { setDateFrom(e.target.value); setPage(1); }} /></div>
                    <div className="flex flex-col gap-1 w-full"><label className="text-sm text-text-secondary">Até</label><input type="date" className="px-3 py-2 bg-bg-tertiary border border-border rounded-md text-text-primary text-sm w-full" value={dateTo} onChange={(e) => { setDateTo(e.target.value); setPage(1); }} /></div>
                    {(filterAction || filterEntity || dateFrom || dateTo) && <div className="sm:col-span-2 md:col-span-1 w-full flex items-end"><Button variant="ghost" size="sm" className="w-full mt-2 md:mt-0" onClick={clearFilters}>Limpar Filtros</Button></div>}
                </div>
            </Card>

            {/* Logs List */}
            <Card>
                {loading ? <div className="p-12 text-center text-text-secondary">Carregando...</div> : logs.length === 0 ? (
                    <div className="flex flex-col items-center p-12 text-center text-text-muted"><FiActivity size={48} className="mb-4 opacity-50" /><h3 className="text-lg font-semibold text-text-secondary mb-2">Nenhuma ação registrada</h3><p>O histórico de ações aparecerá aqui conforme você usa o sistema</p></div>
                ) : (
                    <>
                        <div className="flex flex-col">
                            {logs.map((log) => (
                                <div key={log.id} className="flex flex-col sm:flex-row items-start sm:items-center gap-4 p-4 border-b border-border last:border-b-0 hover:bg-bg-tertiary transition-all duration-fast">
                                    <div className="flex items-start gap-3 flex-1 min-w-0">
                                        <div className="w-10 h-10 flex items-center justify-center bg-bg-tertiary rounded-full text-primary shrink-0">{getActionIcon(log.action_type as ActionType)}</div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 flex-wrap mb-1"><span className="px-2 py-0.5 bg-primary/10 text-primary rounded text-xs font-medium">{getActionTypeLabel(log.action_type as ActionType)}</span><span className="text-xs text-text-muted">{getEntityTypeLabel(log.entity_type as EntityType)}</span>{log.entity_name && <span className="text-xs text-text-secondary font-medium">{log.entity_name}</span>}</div>
                                            <p className="text-sm text-text-secondary truncate">{log.description}</p>
                                        </div>
                                    </div>
                                    <div className="flex flex-row sm:flex-col items-center justify-between sm:items-end w-full sm:w-auto whitespace-nowrap pl-[52px] sm:pl-0"><span className="text-sm text-text-primary font-medium">{getRelativeTime(log.created_at)}</span><span className="text-xs text-text-muted">{formatDateTime(log.created_at)}</span></div>
                                </div>
                            ))}
                        </div>
                        {totalPages > 1 && (
                            <div className="flex justify-center items-center gap-4 p-4 border-t border-border">
                                <Button variant="ghost" size="sm" leftIcon={<FiChevronLeft />} onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page === 1}>Anterior</Button>
                                <span className="text-sm text-text-secondary">Página {page} de {totalPages}</span>
                                <Button variant="ghost" size="sm" rightIcon={<FiChevronRight />} onClick={() => setPage(p => Math.min(totalPages, p + 1))} disabled={page === totalPages}>Próxima</Button>
                            </div>
                        )}
                    </>
                )}
            </Card>
        </div>
    );
}

'use client';

import React, { useState, useMemo, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import {
    ArrowLeft, Printer, ReceiptText, Clock, Users, History,
    PlusCircle, Minus, Plus, CreditCard, Banknote, QrCode,
    CheckCircle, Share, Info, Ticket, UtensilsCrossed, Loader2, Search, Combine
} from 'lucide-react';
import { useFormatters } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';
import Card from '@/components/ui/Card';
import { MesaWithActiveSession, abrirMesa, addSessionItem, fecharMesaSessao, confirmarItensMesa, separarMesa, desagruparTodas } from '@/lib/services/mesas';
import { printOrder } from '@/lib/print';
import { useAuth } from '@/contexts/AuthContext';
import { useProductsCache, useCategoriesCache, useTableDetailCache, type Product, type Category } from '@/hooks/useDataCache';
import { supabase } from '@/lib/supabase';



export default function MesaDetailsPage() {
