                                        />
                                        <Legend />
                                        <Bar dataKey="quantidade" fill="#ff6b35" name="Quantidade" radius={[0, 4, 4, 0]} />
                                        <Bar dataKey="receita" fill="#00b894" name="Receita" radius={[0, 4, 4, 0]} />
                                    </BarChart>
