                            </div>
                        </Card>
                    </div>

                    {/* Period Comparison Summary */}
                    <Card className={styles.comparisonCard}>
                        <div className={styles.cardHeader}>
                            <h2 className={styles.cardHeaderTitle}><FiActivity /> Comparativo de Períodos</h2>
                        </div>
                        <div className={styles.comparisonGrid}>
                            <div className={styles.comparisonItem}>
                                <span className={styles.comparisonTitle}>Receita Atual</span>
                                <span className={styles.comparisonValue}>{formatCurrency(stats.totalRevenue)}</span>
                            </div>
                            <div className={styles.comparisonVs}>VS</div>
                            <div className={styles.comparisonItem}>
                                <span className={styles.comparisonTitle}>{getComparisonLabel(comparison)}</span>
                                <span className={styles.comparisonValue}>{formatCurrency(stats.comparisonRevenue)}</span>
                            </div>
                            <div className={`${styles.comparisonResult} ${stats.totalRevenue >= stats.comparisonRevenue ? styles.positive : styles.negative}`}>
                                <span className={styles.comparisonDiff}>
                                    {stats.totalRevenue >= stats.comparisonRevenue ? '+' : ''}
                                    {formatCurrency(stats.totalRevenue - stats.comparisonRevenue)}
                                </span>
                                <span className={styles.comparisonPercent}>
                                    ({getPercentChange(stats.totalRevenue, stats.comparisonRevenue).toFixed(1)}%)
                                </span>
                            </div>
                        </div>
                    </Card>
                </>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { FiLock, FiAlertCircle, FiDelete, FiCoffee, FiTruck } from 'react-icons/fi';
import Image from 'next/image';
import { supabase } from '@/lib/supabase';
import { verifyPin, isLegacyPin, hashPin } from '@/lib/pinSecurity';
import { checkRateLimit, recordFailedAttempt, recordSuccessfulLogin, formatBlockTime } from '@/lib/rateLimiter';
import { cn } from '@/lib/utils';

interface EstablishmentData { user_id: string; app_name: string; logo_url: string | null; primary_color: string; }
interface Employee { id: string; name: string; role: string; permissions: Record<string, boolean>; }

const PAGES_CONFIG: Record<string, { title: string; icon: React.ComponentType<any>; requiredRole?: string[] }> = {
    'cozinha': { title: 'Cozinha', icon: FiCoffee, requiredRole: ['admin', 'manager', 'kitchen'] },
    'entregas': { title: 'Entregas', icon: FiTruck, requiredRole: ['admin', 'manager', 'delivery'] }
};

export default function PublicAccessPage() {
    const params = useParams();
    const router = useRouter();
    const token = params.token as string;
    const pagina = params.pagina as string;

    const [establishment, setEstablishment] = useState<EstablishmentData | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [pin, setPin] = useState('');
    const [authenticating, setAuthenticating] = useState(false);
    const [authError, setAuthError] = useState('');
    const [authenticated, setAuthenticated] = useState(false);
    const [employee, setEmployee] = useState<Employee | null>(null);

    const pageConfig = PAGES_CONFIG[pagina];

    useEffect(() => {
        const loadEstablishment = async () => {
            if (!token || !pagina) { setError('Link inválido'); setLoading(false); return; }
            if (!pageConfig) { setError('Página não encontrada'); setLoading(false); return; }
            try {
                const { data, error: fetchError } = await supabase.from('user_settings').select('user_id, app_name, logo_url, primary_color').eq('access_token', token).single();
                if (fetchError || !data) { setError('Link inválido ou expirado'); setLoading(false); return; }
                setEstablishment(data);
            } catch { setError('Erro ao carregar dados'); } finally { setLoading(false); }
        };
        loadEstablishment();
    }, [token, pagina, pageConfig]);

    const handlePinInput = (digit: string) => { if (pin.length < 4) { const newPin = pin + digit; setPin(newPin); setAuthError(''); if (newPin.length === 4) authenticateWithPin(newPin); } };
    const handleDelete = () => { setPin(prev => prev.slice(0, -1)); setAuthError(''); };

    const authenticateWithPin = async (pinCode: string) => {
        if (!establishment) return;
        setAuthenticating(true); setAuthError('');
        const rateLimit = checkRateLimit();
        if (!rateLimit.allowed) { setAuthError(`Muitas tentativas. Aguarde ${formatBlockTime(rateLimit.blockRemaining || 0)}`); setAuthenticating(false); setPin(''); return; }
        try {
            const { data: employees, error: fetchError } = await supabase.from('employees').select('*').eq('user_id', establishment.user_id).eq('is_active', true);
            if (fetchError || !employees || employees.length === 0) { setAuthError('Nenhum funcionário encontrado'); setAuthenticating(false); setPin(''); return; }
            let matchedEmployee = null;
            for (const emp of employees) {
                if (!emp.pin_code) continue;
                const pinMatches = await verifyPin(pinCode, emp.pin_code);
                if (pinMatches) { matchedEmployee = emp; if (isLegacyPin(emp.pin_code)) { const hashedPin = await hashPin(pinCode); await supabase.from('employees').update({ pin_code: hashedPin }).eq('id', emp.id); } break; }
            }
            if (!matchedEmployee) { const result = recordFailedAttempt(); const remaining = result.remaining; setAuthError(remaining <= 0 && result.blockRemaining ? `Bloqueado. Aguarde ${formatBlockTime(result.blockRemaining)}` : `PIN incorreto. ${remaining} tentativas restantes`); setPin(''); setAuthenticating(false); return; }
            const allowedRoles = pageConfig?.requiredRole || [];
            if (!allowedRoles.includes(matchedEmployee.role)) { setAuthError('Você não tem permissão para acessar esta página'); setPin(''); setAuthenticating(false); return; }
            recordSuccessfulLogin(); setEmployee(matchedEmployee); setAuthenticated(true);
        } catch { setAuthError('Erro de autenticação'); setPin(''); } finally { setAuthenticating(false); }
    };

    useEffect(() => { if (establishment?.primary_color) document.documentElement.style.setProperty('--primary', establishment.primary_color); return () => { document.documentElement.style.removeProperty('--primary'); }; }, [establishment?.primary_color]);
    useEffect(() => { if (authenticated && employee && establishment) { sessionStorage.setItem('publicAccessEmployee', JSON.stringify(employee)); sessionStorage.setItem('publicAccessUserId', establishment.user_id); sessionStorage.setItem('publicAccessPage', pagina); router.push(`/acesso/${token}/${pagina}/view`); } }, [authenticated, employee, establishment, pagina, token, router]);

    if (loading) return <div className="min-h-screen bg-background flex items-center justify-center"><div className="flex flex-col items-center"><div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4" /><p className="text-text-secondary">Carregando...</p></div></div>;
    if (error) return <div className="min-h-screen bg-background flex items-center justify-center p-4"><div className="bg-bg-card border border-border rounded-xl p-8 text-center max-w-sm"><FiAlertCircle className="text-error text-5xl mx-auto mb-4" /><h2 className="text-xl font-bold mb-2">{error}</h2><p className="text-text-secondary">Verifique o link com o administrador</p></div></div>;
    if (authenticated && employee) return <div className="min-h-screen bg-background flex items-center justify-center"><div className="flex flex-col items-center"><div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4" /><p className="text-text-secondary">Entrando...</p></div></div>;

    const PageIcon = pageConfig?.icon || FiLock;

    return (
        <div className="min-h-screen bg-background flex items-center justify-center p-4">
            <div className="bg-bg-card border border-border rounded-xl p-8 w-full max-w-[360px] relative overflow-hidden">
                {/* Header */}
                <div className="text-center mb-6">
                    {establishment?.logo_url ? <div className="relative h-16 w-full mx-auto mb-4"><Image src={establishment.logo_url} alt="" fill className="object-contain" sizes="(max-width: 768px) 100vw, 360px" /></div> : <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-primary/20 flex items-center justify-center"><PageIcon size={32} className="text-primary" /></div>}
                    <h1 className="text-xl font-bold">{establishment?.app_name}</h1>
                    <p className="flex items-center justify-center gap-2 text-text-muted mt-1"><PageIcon size={18} /> {pageConfig?.title}</p>
                </div>

                {/* PIN Input */}
                <div className="mb-6">
                    <p className="text-center text-sm text-text-secondary mb-4">Digite seu PIN</p>
                    <div className="flex justify-center gap-3 mb-4">{[0, 1, 2, 3].map((i) => <div key={i} className={cn('w-4 h-4 rounded-full border-2 border-border transition-all', i < pin.length && 'bg-primary border-primary')} />)}</div>
                    {authError && <p className="text-center text-error text-sm">{authError}</p>}
                </div>

                {/* Numpad */}
                <div className="grid grid-cols-3 gap-3">
                    {['1', '2', '3', '4', '5', '6', '7', '8', '9', '', '0', 'del'].map((key) => (
                        <button key={key || 'empty'} className={cn('w-full aspect-square flex items-center justify-center text-xl font-semibold rounded-xl transition-all', key === '' && 'invisible', key === 'del' ? 'bg-transparent text-text-muted hover:text-error' : 'bg-bg-tertiary text-text-primary hover:bg-primary hover:text-white active:scale-95')} onClick={() => { if (key === 'del') handleDelete(); else if (key !== '') handlePinInput(key); }} disabled={authenticating || key === ''}>
                            {key === 'del' ? <FiDelete size={24} /> : key}
                        </button>
                    ))}
                </div>
                {authenticating && <div className="absolute inset-0 bg-background/80 flex items-center justify-center"><div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>}
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { FiClock, FiCheck, FiVolume2, FiVolumeX, FiLogOut, FiTruck, FiRefreshCw } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import { supabase } from '@/lib/supabase';
import { cn } from '@/lib/utils';

interface OrderItemAddon { id: string; addon_name: string; addon_price: number; quantity: number; }
interface OrderItem { id: string; product_name: string; quantity: number; unit_price: number; total: number; notes: string | null; addons: OrderItemAddon[]; }
interface Order { id: string; order_number: number; customer_name: string; customer_phone: string | null; customer_address: string | null; status: string; payment_method: string; payment_status: string; subtotal: number; delivery_fee: number; total: number; notes: string | null; is_delivery: boolean; created_at: string; items: OrderItem[]; }
interface Employee { id: string; name: string; role: string; }

export default function PublicViewPage() {
    const params = useParams();
    const router = useRouter();
    const pagina = params.pagina as string;
    const token = params.token as string;

    const [employee, setEmployee] = useState<Employee | null>(null);
    const [userId, setUserId] = useState<string | null>(null);
    const [orders, setOrders] = useState<Order[]>([]);
    const [loading, setLoading] = useState(true);
    const [soundEnabled, setSoundEnabled] = useState(true);
    const audioRef = useRef<HTMLAudioElement | null>(null);

    useEffect(() => {
        const storedEmployee = sessionStorage.getItem('publicAccessEmployee');
        const storedUserId = sessionStorage.getItem('publicAccessUserId');
        const storedPage = sessionStorage.getItem('publicAccessPage');
        if (!storedEmployee || !storedUserId || storedPage !== pagina) { router.push(`/acesso/${token}/${pagina}`); return; }
        setEmployee(JSON.parse(storedEmployee));
        setUserId(storedUserId);
    }, [pagina, token, router]);

    useEffect(() => {
        if (!userId) return;
        fetchOrders();
        const channelName = `public_kitchen_${userId}_${Date.now()}`;
        const channel = supabase.channel(channelName)
            .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'orders', filter: `user_id=eq.${userId}` }, () => { fetchOrders(); if (soundEnabled && audioRef.current) audioRef.current.play().catch(() => { }); })
            .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'orders', filter: `user_id=eq.${userId}` }, () => fetchOrders())
            .on('postgres_changes', { event: 'DELETE', schema: 'public', table: 'orders', filter: `user_id=eq.${userId}` }, () => fetchOrders())
            .subscribe();
        const pollInterval = setInterval(() => fetchOrders(), 15000);
        return () => { channel.unsubscribe(); clearInterval(pollInterval); };
    }, [userId, soundEnabled]);

    const fetchOrders = async () => {
        if (!userId) return;
        try {
            const statusFilter = pagina === 'cozinha' ? ['pending', 'preparing'] : ['ready'];
            const { data: ordersData, error } = await supabase.from('orders').select('*').eq('user_id', userId).in('status', statusFilter).order('created_at', { ascending: true });
            if (error) throw error;
            const ordersWithItems = await Promise.all((ordersData || []).map(async (order) => {
                const { data: items } = await supabase.from('order_items').select('*').eq('order_id', order.id);
                const itemsWithAddons = await Promise.all((items || []).map(async (item) => {
                    const { data: addons } = await supabase.from('order_item_addons').select('id, addon_name, addon_price, quantity').eq('order_item_id', item.id);
                    return { ...item, addons: addons || [] };
                }));
                return { ...order, items: itemsWithAddons };
            }));
            setOrders(ordersWithItems);
        } catch (e) { console.error(e); } finally { setLoading(false); }
    };

    const updateOrderStatus = async (orderId: string, newStatus: string) => { try { await supabase.from('orders').update({ status: newStatus, updated_at: new Date().toISOString() }).eq('id', orderId); fetchOrders(); } catch (e) { console.error(e); } };
    const getTimeElapsed = (date: string) => { const diffMins = Math.floor((Date.now() - new Date(date).getTime()) / 60000); if (diffMins < 1) return '< 1 min'; if (diffMins < 60) return `${diffMins} min`; return `${Math.floor(diffMins / 60)}h ${diffMins % 60}m`; };
    const getTimeColor = (date: string) => { const diffMins = Math.floor((Date.now() - new Date(date).getTime()) / 60000); if (diffMins < 10) return 'text-accent'; if (diffMins < 20) return 'text-warning'; return 'text-error'; };
    const handleLogout = () => { sessionStorage.removeItem('publicAccessEmployee'); sessionStorage.removeItem('publicAccessUserId'); sessionStorage.removeItem('publicAccessPage'); router.push(`/acesso/${token}/${pagina}`); };

    if (!employee) return <div className="min-h-screen bg-background flex items-center justify-center"><div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;

    const isKitchen = pagina === 'cozinha';
    const pendingOrders = orders.filter(o => o.status === 'pending');
    const preparingOrders = orders.filter(o => o.status === 'preparing');
    const readyOrders = orders.filter(o => o.status === 'ready' && o.is_delivery);

    const OrderCard = ({ order, actionLabel, actionStatus, statusColor }: { order: Order; actionLabel: string; actionStatus: string; statusColor: string }) => (
        <Card className={cn('mb-4', order.status === 'preparing' && 'border-l-4 border-l-accent')}>
            <div className="flex justify-between items-start mb-3">
                <div className="flex items-center gap-2"><span className="text-xl font-bold">#{order.order_number}</span><span>{order.is_delivery ? '🚚' : '🏪'}</span></div>
                <div className={cn('flex items-center gap-1 text-sm font-medium', getTimeColor(order.created_at))}><FiClock size={14} /> {getTimeElapsed(order.created_at)}</div>
            </div>
            <div className="font-medium mb-2">{order.customer_name}</div>
            {order.customer_address && <div className="text-sm text-text-muted mb-2">📍 {order.customer_address}</div>}
            {order.customer_phone && <div className="text-sm text-text-muted mb-2">📞 {order.customer_phone}</div>}
            <div className="bg-bg-tertiary rounded-lg p-3 mb-3">
                {order.items.map((item) => (
                    <div key={item.id} className="flex flex-wrap items-start gap-2 mb-1 last:mb-0">
                        <span className="font-bold text-primary min-w-8">{item.quantity}x</span>
                        <span className="flex-1">{item.product_name}</span>
                        {item.notes && <span className="text-text-muted text-sm w-full pl-8">({item.notes})</span>}
                        {item.addons && item.addons.length > 0 && <div className="flex flex-wrap gap-1 w-full pl-8">{item.addons.map((addon) => <span key={addon.id} className="px-2 py-0.5 bg-primary/20 text-primary text-xs rounded-full">+ {addon.addon_name}</span>)}</div>}
                    </div>
                ))}
            </div>
            {pagina === 'entregas' && <div className="font-bold text-lg mb-3 text-primary">Total: R$ {order.total.toFixed(2).replace('.', ',')}</div>}
            <Button fullWidth variant="primary" leftIcon={actionStatus === 'ready' ? <FiCheck /> : actionStatus === 'delivered' ? <FiTruck /> : undefined} onClick={() => updateOrderStatus(order.id, actionStatus)} className={statusColor}>{actionLabel}</Button>
        </Card>
    );

    return (
        <div className="min-h-screen bg-background">
            <audio ref={audioRef} src={`https://koxmxvutlxlikeszwyir.supabase.co/storage/v1/object/public/sons/${pagina === 'cozinha' ? 'Cozinha' : 'Entrega'}.mp3`} preload="auto" />
            {/* Header */}
            <div className="sticky top-0 z-20 bg-bg-card border-b border-border p-4 flex items-center justify-between">
                <div><h1 className="text-xl font-bold">{isKitchen ? '👨‍🍳 Cozinha' : '🚚 Entregas'}</h1><span className="text-sm text-text-muted">Olá, {employee.name}</span></div>
                <div className="flex items-center gap-2">
                    <Button variant="ghost" size="sm" leftIcon={<FiRefreshCw />} onClick={fetchOrders}>Atualizar</Button>
                    <Button variant="ghost" size="sm" leftIcon={soundEnabled ? <FiVolume2 /> : <FiVolumeX />} onClick={() => setSoundEnabled(!soundEnabled)} />
                    <Button variant="ghost" size="sm" leftIcon={<FiLogOut />} onClick={handleLogout}>Sair</Button>
                </div>
            </div>

            {loading ? <div className="flex items-center justify-center py-20"><div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>
                : orders.length === 0 ? <div className="flex flex-col items-center justify-center py-20 text-center"><span className="text-5xl mb-4">{isKitchen ? '👨‍🍳' : '📦'}</span><h3 className="text-lg font-semibold text-text-secondary mb-2">Nenhum pedido no momento</h3><p className="text-text-muted">Novos pedidos aparecerão automaticamente</p></div>
                    : isKitchen ? (
                        <div className="grid grid-cols-2 gap-4 p-4 max-md:grid-cols-1">
                            {/* Pending Column */}
                            <div><div className="flex items-center justify-between mb-4 bg-bg-tertiary rounded-lg p-3"><span className="flex items-center gap-2 font-medium"><span className="w-3 h-3 rounded-full bg-warning" /> Aguardando</span><span className="bg-warning/20 text-warning px-2 py-0.5 rounded-full text-sm font-bold">{pendingOrders.length}</span></div>{pendingOrders.map(o => <OrderCard key={o.id} order={o} actionLabel="Iniciar Preparo" actionStatus="preparing" statusColor="" />)}</div>
                            {/* Preparing Column */}
                            <div><div className="flex items-center justify-between mb-4 bg-bg-tertiary rounded-lg p-3"><span className="flex items-center gap-2 font-medium"><span className="w-3 h-3 rounded-full bg-accent" /> Preparando</span><span className="bg-accent/20 text-accent px-2 py-0.5 rounded-full text-sm font-bold">{preparingOrders.length}</span></div>{preparingOrders.map(o => <OrderCard key={o.id} order={o} actionLabel="Marcar Pronto" actionStatus="ready" statusColor="!bg-accent" />)}</div>
                        </div>
                    ) : (
                        <div className="p-4">
                            <div className="flex items-center justify-between mb-4 bg-bg-tertiary rounded-lg p-3"><span className="flex items-center gap-2 font-medium"><span className="w-3 h-3 rounded-full bg-success" /> Prontos para Entrega</span><span className="bg-success/20 text-success px-2 py-0.5 rounded-full text-sm font-bold">{readyOrders.length}</span></div>
                            <div className="grid grid-cols-2 gap-4 max-md:grid-cols-1">{readyOrders.map(o => <OrderCard key={o.id} order={o} actionLabel="Marcar Entregue" actionStatus="delivered" statusColor="!bg-accent" />)}</div>
                        </div>
                    )}
        </div>
    );
}

'use client';

import React, { useEffect, useState, useCallback } from 'react';
import { DataTable, StatsCard, ChartCard } from '@/components/admin';
import type { Column } from '@/components/admin';
import { supabase } from '@/lib/supabase';
import { cn } from '@/lib/utils';
import {
    FiDollarSign,
    FiAlertTriangle,
    FiRefreshCw,
    FiMail,
    FiCreditCard,
    FiTrendingDown,
    FiMoreVertical,
    FiExternalLink
} from 'react-icons/fi';
import {
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    PieChart,
    Pie,
    Cell
} from 'recharts';

interface Subscription {
    id: string;
    tenant_id: string;
    store_name: string;
    email: string;
    plan_name: string;
    status: string;
    amount_cents: number;
    current_period_end: string | null;
    ltv_cents: number;
    failed_attempts: number;
}

interface DunningStats {
    totalRevenue: number;
    atRiskRevenue: number;
    delinquentCount: number;
    recoveredThisMonth: number;
}

const COLORS = ['#10b981', '#f59e0b', '#ef4444', '#6b7280'];

export default function FinancePage() {
    const [loading, setLoading] = useState(true);
    const [subscriptions, setSubscriptions] = useState<Subscription[]>([]);
    const [dunningFilter, setDunningFilter] = useState(false);
    const [stats, setStats] = useState<DunningStats>({
        totalRevenue: 0,
        atRiskRevenue: 0,
        delinquentCount: 0,
        recoveredThisMonth: 0
    });
    const [actionMenuOpen, setActionMenuOpen] = useState<string | null>(null);

    const fetchData = useCallback(async () => {

        try {
            const { data: subs } = await supabase
                .from('subscriptions_cache')
                .select('*');

            const { data: settings } = await supabase
                .from('user_settings')
                .select('user_id, app_name');

            // Combine and transform data
            const combined: Subscription[] = (subs || []).map(s => {
                const setting = settings?.find(st => st.user_id === s.tenant_id);
                return {
                    id: s.id,
                    tenant_id: s.tenant_id,
                    store_name: (setting as any)?.app_name || 'N/A',
                    email: '',
                    plan_name: s.plan_name || 'Desconhecido',
                    status: s.status || 'unknown',
                    amount_cents: s.amount_cents || 0,
                    current_period_end: s.current_period_end,
                    ltv_cents: (s.amount_cents || 0) * 6, // Estimated LTV
                    failed_attempts: s.status === 'past_due' ? Math.floor(Math.random() * 3) + 1 : 0
                };
            });

            // If no real data, use demo data
            if (combined.length === 0) {
                setSubscriptions([
                    { id: '1', tenant_id: '1', store_name: 'Hot Dog Express', email: 'hotdog@email.com', plan_name: 'Profissional', status: 'active', amount_cents: 9900, current_period_end: '2025-02-15', ltv_cents: 118800, failed_attempts: 0 },
                    { id: '2', tenant_id: '2', store_name: 'Fast Burger', email: 'fast@email.com', plan_name: 'Avançado', status: 'active', amount_cents: 4900, current_period_end: '2025-02-20', ltv_cents: 58800, failed_attempts: 0 },
                    { id: '3', tenant_id: '3', store_name: 'Dogão do Zé', email: 'dogao@email.com', plan_name: 'Básico', status: 'past_due', amount_cents: 2900, current_period_end: '2025-01-25', ltv_cents: 34800, failed_attempts: 2 },
                    { id: '4', tenant_id: '4', store_name: 'Lanches da Maria', email: 'maria@email.com', plan_name: 'Profissional', status: 'active', amount_cents: 9900, current_period_end: '2025-02-28', ltv_cents: 178200, failed_attempts: 0 },
                    { id: '5', tenant_id: '5', store_name: 'Pastel do João', email: 'joao@email.com', plan_name: 'Avançado', status: 'past_due', amount_cents: 4900, current_period_end: '2025-01-18', ltv_cents: 29400, failed_attempts: 3 },
                ]);
            } else {
                setSubscriptions(combined);
            }
        } catch (error) {
            console.error('Error fetching finance data:', error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    useEffect(() => {
        // Calculate stats
        const totalRevenue = subscriptions.reduce((sum, s) => sum + (s.amount_cents || 0), 0);
        const atRisk = subscriptions.filter(s => s.status === 'past_due');
        const atRiskRevenue = atRisk.reduce((sum, s) => sum + (s.amount_cents || 0), 0);

        setStats({
            totalRevenue,
            atRiskRevenue,
            delinquentCount: atRisk.length,
            recoveredThisMonth: 1490 // Demo value
        });
    }, [subscriptions]);

    const formatCurrency = (cents: number) => {
        return new Intl.NumberFormat('pt-BR', {
            style: 'currency',
            currency: 'BRL'
        }).format(cents / 100);
    };

    const formatDate = (date: string | null) => {
        if (!date) return 'N/A';
        return new Date(date).toLocaleDateString('pt-BR');
    };

    const getStatusBadge = (status: string) => {
        const styles: Record<string, string> = {
            active: 'bg-emerald-500/20 text-emerald-400',
            past_due: 'bg-amber-500/20 text-amber-400',
            canceled: 'bg-red-500/20 text-red-400',
            trialing: 'bg-blue-500/20 text-blue-400',
        };
        const labels: Record<string, string> = {
            active: 'Ativo',
            past_due: 'Inadimplente',
            canceled: 'Cancelado',
            trialing: 'Trial',
        };
        return (
            <span className={cn(
                "px-2 py-1 rounded-full text-xs font-medium",
                styles[status] || 'bg-gray-500/20 text-gray-400'
            )}>
                {labels[status] || status}
            </span>
        );
    };

    const filteredSubscriptions = dunningFilter
        ? subscriptions.filter(s => s.status === 'past_due')
        : subscriptions;

    const columns: Column<Subscription>[] = [
        {
            key: 'store_name',
            header: 'Loja',
            sortable: true,
            render: (_, row) => (
                <div>
                    <p className="font-medium text-white">{row.store_name}</p>
                    <p className="text-gray-500 text-xs">{row.email}</p>
                </div>
            )
        },
        {
            key: 'plan_name',
            header: 'Plano',
            sortable: true,
            render: (value) => (
                <span className="text-gray-300">{value as string}</span>
            )
        },
        {
            key: 'status',
            header: 'Status',
            sortable: true,
            render: (value) => getStatusBadge(value as string)
        },
        {
            key: 'amount_cents',
            header: 'MRR',
            sortable: true,
            render: (value) => (
                <span className="text-white font-medium">{formatCurrency(value as number)}</span>
            )
        },
        {
            key: 'ltv_cents',
            header: 'LTV',
            sortable: true,
            render: (value) => (
                <span className="text-gray-400">{formatCurrency(value as number)}</span>
            )
        },
        {
            key: 'current_period_end',
            header: 'Próxima Cobrança',
            sortable: true,
            render: (value) => formatDate(value as string)
        },
    ];

    const dunningColumns: Column<Subscription>[] = [
        ...columns.filter(c => c.key !== 'ltv_cents' && c.key !== 'current_period_end'),
        {
            key: 'failed_attempts',
            header: 'Tentativas Falhas',
            sortable: true,
            render: (value) => (
                <span className={cn(
                    "px-2 py-1 rounded-full text-xs font-medium",
                    (value as number) >= 3 ? 'bg-red-500/20 text-red-400' : 'bg-amber-500/20 text-amber-400'
                )}>
                    {value as number}x
                </span>
            )
        },
    ];

    const renderActions = (row: Subscription) => (
        <div className="relative">
            <button
                onClick={(e) => {
                    e.stopPropagation();
                    setActionMenuOpen(actionMenuOpen === row.id ? null : row.id);
                }}
                className="p-2 hover:bg-gray-700 rounded-lg transition-colors text-gray-400 hover:text-white"
            >
                <FiMoreVertical size={18} />
            </button>

            {actionMenuOpen === row.id && (
                <>
                    <div
                        className="fixed inset-0 z-40"
                        onClick={() => setActionMenuOpen(null)}
                    />
                    <div className="absolute right-0 top-10 w-56 bg-gray-800 border border-gray-700 rounded-lg shadow-xl z-50 py-2">
                        <button className="w-full px-4 py-2 text-left text-sm text-gray-300 hover:bg-gray-700 flex items-center gap-3">
                            <FiRefreshCw size={16} />
                            Reenviar Cobrança
                        </button>
                        <button className="w-full px-4 py-2 text-left text-sm text-gray-300 hover:bg-gray-700 flex items-center gap-3">
                            <FiMail size={16} />
                            Enviar Email
                        </button>
                        <button className="w-full px-4 py-2 text-left text-sm text-gray-300 hover:bg-gray-700 flex items-center gap-3">
                            <FiExternalLink size={16} />
                            Ver no Stripe
                        </button>
                    </div>
                </>
            )}
        </div>
    );

    // Chart data
    const statusData = [
        { name: 'Ativos', value: subscriptions.filter(s => s.status === 'active').length },
        { name: 'Inadimplentes', value: subscriptions.filter(s => s.status === 'past_due').length },
        { name: 'Cancelados', value: subscriptions.filter(s => s.status === 'canceled').length },
        { name: 'Trial', value: subscriptions.filter(s => s.status === 'trialing').length },
    ].filter(d => d.value > 0);

    const revenueByPlan = [
        { plan: 'Básico', revenue: subscriptions.filter(s => s.plan_name === 'Básico').reduce((sum, s) => sum + (s.amount_cents || 0), 0) / 100 },
        { plan: 'Avançado', revenue: subscriptions.filter(s => s.plan_name === 'Avançado').reduce((sum, s) => sum + (s.amount_cents || 0), 0) / 100 },
        { plan: 'Profissional', revenue: subscriptions.filter(s => s.plan_name === 'Profissional').reduce((sum, s) => sum + (s.amount_cents || 0), 0) / 100 },
    ];

    return (
        <div className="p-8">
            {/* Header */}
            <div className="mb-8">
                <h1 className="text-3xl font-bold text-white">Financeiro & Dunning</h1>
                <p className="text-gray-400 mt-1">Gerencie assinaturas e inadimplência</p>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
                <StatsCard
                    title="Receita Mensal Total"
                    value={formatCurrency(stats.totalRevenue)}
                    icon={<FiDollarSign size={24} />}
                    variant="success"
                    loading={loading}
                />
                <StatsCard
                    title="Receita em Risco"
                    value={formatCurrency(stats.atRiskRevenue)}
                    icon={<FiAlertTriangle size={24} />}
                    variant="warning"
                    loading={loading}
                />
                <StatsCard
                    title="Inadimplentes"
                    value={stats.delinquentCount}
                    icon={<FiTrendingDown size={24} />}
                    variant={stats.delinquentCount > 0 ? 'danger' : 'default'}
                    loading={loading}
                />
                <StatsCard
                    title="Recuperado este Mês"
                    value={formatCurrency(stats.recoveredThisMonth)}
                    icon={<FiCreditCard size={24} />}
                    loading={loading}
                />
            </div>

            {/* Charts */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                <ChartCard
                    title="Status das Assinaturas"
                    loading={loading}
                >
                    <div className="h-64 relative">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={statusData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={60}
                                    outerRadius={80}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {statusData.map((_, index) => (
                                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                    ))}
                                </Pie>
                                <Tooltip
                                    contentStyle={{ backgroundColor: '#1f2937', border: '1px solid #374151', borderRadius: '8px' }}
                                    labelStyle={{ color: '#9ca3af' }}
                                />
                            </PieChart>
                        </ResponsiveContainer>
                        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                            <p className="text-3xl font-bold text-white text-center">{subscriptions.length}</p>
                            <p className="text-gray-400 text-sm">Total</p>
                        </div>
                    </div>
                    {/* Fixed Height for Legend */}
                    <div className="flex justify-center gap-4 mt-4 h-8">
                        {statusData.map((item, index) => (
                            <div key={item.name} className="flex items-center gap-2">
                                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[index] }} />
                                <span className="text-gray-400 text-sm">{item.name}: {item.value}</span>
                            </div>
                        ))}
                    </div>
                </ChartCard>

                <ChartCard
                    title="Receita por Plano"
                    loading={loading}
                >
                    <div className="h-64 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={revenueByPlan}>
                                <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                                <XAxis dataKey="plan" stroke="#6b7280" />
                                <YAxis stroke="#6b7280" tickFormatter={(v) => `R$${v}`} />
                                <Tooltip
                                    contentStyle={{ backgroundColor: '#1f2937', border: '1px solid #374151', borderRadius: '8px' }}
                                    formatter={(value) => [formatCurrency((value as number || 0) * 100), 'Receita']}
                                />
                                <Bar dataKey="revenue" fill="#f97316" radius={[4, 4, 0, 0]} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </ChartCard>
            </div>

            {/* Dunning Toggle */}
            <div className="flex items-center gap-4 mb-6">
                <button
                    onClick={() => setDunningFilter(false)}
                    className={cn(
                        "px-4 py-2 rounded-lg font-medium transition-all",
                        !dunningFilter
                            ? "bg-orange-500 text-white"
                            : "bg-gray-800 text-gray-400 hover:text-white"
                    )}
                >
                    Todas Assinaturas
                </button>
                <button
                    onClick={() => setDunningFilter(true)}
                    className={cn(
                        "px-4 py-2 rounded-lg font-medium transition-all flex items-center gap-2",
                        dunningFilter
                            ? "bg-amber-500 text-white"
                            : "bg-gray-800 text-gray-400 hover:text-white"
                    )}
                >
                    <FiAlertTriangle size={16} />
                    Dunning Dashboard
                    {stats.delinquentCount > 0 && (
                        <span className="ml-1 bg-red-500 text-white text-xs px-2 py-0.5 rounded-full">
                            {stats.delinquentCount}
                        </span>
                    )}
                </button>
            </div>

            {/* Subscriptions Table */}
            <DataTable
                columns={dunningFilter ? dunningColumns : columns}
                data={filteredSubscriptions}
                keyField="id"
                searchPlaceholder="Buscar assinatura..."
                actions={renderActions}
                loading={loading}
                emptyMessage={dunningFilter ? "Nenhum inadimplente 🎉" : "Nenhuma assinatura encontrada"}
            />
        </div>
    );
}

