'use client';

import React, { useEffect, useState } from 'react';
import { usePathname, useRouter } from 'next/navigation';
import { AdminSidebar } from '@/components/admin';
import { isSuperAdminAuthenticated } from '@/lib/admin-auth';
import { FiLoader } from 'react-icons/fi';

export default function AdminLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const pathname = usePathname();
    const router = useRouter();
    const [isAuthenticated, setIsAuthenticated] = useState<boolean | null>(null);

    // Check authentication on mount and route changes
    useEffect(() => {
        // Skip auth check for login page
        if (pathname === '/admin/login') {
            return;
        }

        const authenticated = isSuperAdminAuthenticated();
        setIsAuthenticated(authenticated);

        if (!authenticated) {
            router.replace('/admin/login');
        }
    }, [pathname, router]);

    // Login page has its own layout
    if (pathname === '/admin/login') {
        return <>{children}</>;
    }

    // Show loading while checking auth
    if (isAuthenticated === null) {
        return (
            <div className="min-h-screen bg-gray-950 flex items-center justify-center">
                <FiLoader className="animate-spin text-orange-500" size={32} />
            </div>
        );
    }

    // Not authenticated - will redirect
    if (!isAuthenticated) {
        return (
            <div className="min-h-screen bg-gray-950 flex items-center justify-center">
                <FiLoader className="animate-spin text-orange-500" size={32} />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-950">
            <AdminSidebar />
            <main className="ml-64 min-h-screen">
                {children}
            </main>
        </div>
    );
}

'use client';

import React, { useEffect, useState, useCallback } from 'react';
import { DataTable, StatsCard } from '@/components/admin';
import type { Column } from '@/components/admin';
import { supabase } from '@/lib/supabase';
import { cn } from '@/lib/utils';
import {
    FiPackage,
    FiPlus,
    FiEdit2,
    FiTrash2,
    FiCheck,
    FiX,
    FiSave,
    FiActivity,
    FiDollarSign
} from 'react-icons/fi';

interface Plan {
    id: string;
    name: string;
    description: string | null;
    price_cents: number;
    interval: string;
    active: boolean;
    created_at: string;
}

export default function PlansPage() {
    const [loading, setLoading] = useState(true);
    const [plans, setPlans] = useState<Plan[]>([]);

    // Fetch plans from subscription_plans (Source of Truth)
    const fetchPlans = useCallback(async () => {
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('subscription_plans')
                .select('*')
                .order('price_cents', { ascending: true });

            if (error) throw error;

            // Map to local interface
            const mapped: Plan[] = (data || []).map(p => ({
                id: p.id,
                name: p.name,
                description: p.description,
                price_cents: p.price_cents,
                interval: p.billing_interval || 'monthly',
                active: p.is_active,
                created_at: p.created_at
            }));

            setPlans(mapped);
        } catch (error) {
            console.error('Error fetching plans:', error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchPlans();
    }, [fetchPlans]);

    const formatCurrency = (cents: number) => {
        return new Intl.NumberFormat('pt-BR', {
            style: 'currency',
            currency: 'BRL'
        }).format(cents / 100);
    };

    const columns: Column<Plan>[] = [
        {
            key: 'name',
            header: 'Nome',
            sortable: true,
            render: (_, row) => (
                <div>
                    <p className="font-medium text-white">{row.name}</p>
                    <p className="text-gray-500 text-xs">{row.description}</p>
                </div>
            )
        },
        {
            key: 'price_cents',
            header: 'Preço',
            sortable: true,
            render: (val) => <span className="text-white font-medium">{formatCurrency(val as number)}</span>
        },
        {
            key: 'active',
            header: 'Status',
            render: (_, row) => (
                <span className={cn(
                    "px-2 py-1 rounded-full text-xs font-medium border flex items-center gap-1 w-fit",
                    row.active
                        ? "bg-emerald-500/20 text-emerald-400 border-emerald-500/30"
                        : "bg-gray-500/20 text-gray-400 border-gray-500/30"
                )}>
                    {row.active ? 'Ativo' : 'Inativo'}
                </span>
            )
        }
    ];

    return (
        <div className="p-8">
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-white">Planos do Sistema</h1>
                    <p className="text-gray-400 mt-1">Planos sincronizados com Stripe e Supabase</p>
                </div>
                {/* 
                <button
                    onClick={() => {}} 
                    className="flex items-center gap-2 px-6 py-3 rounded-lg font-medium transition-all bg-gray-700 text-gray-400 cursor-not-allowed"
                    disabled
                >
                    <FiRefreshCw size={18} />
                    Sincronizar (Automático)
                </button>
                */}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <StatsCard
                    title="Total de Planos"
                    value={plans.length}
                    icon={<FiPackage size={24} />}
                    loading={loading}
                />
                <StatsCard
                    title="Planos Ativos"
                    value={plans.filter(p => p.active).length}
                    icon={<FiCheck size={24} />}
                    variant="success"
                    loading={loading}
                />
                <StatsCard
                    title="Ticket Médio"
                    value={formatCurrency(plans.length ? plans.reduce((a, b) => a + b.price_cents, 0) / plans.length : 0)}
                    icon={<FiDollarSign size={24} />}
                    loading={loading}
                    variant="warning"
                />
            </div>

            <DataTable
                columns={columns}
                data={plans}
                keyField="id"
                loading={loading}
                searchPlaceholder="Buscar planos..."
            />
        </div>
    );
}

import { NextRequest, NextResponse } from 'next/server';
import { getAbacatepayBilling } from '@/lib/abacatepay';
import { supabaseAdmin } from '@/lib/supabase-admin';
import { getStripeCustomer } from '@/lib/stripe';

// Get billing period from subscription or default
async function getPeriodDaysForBilling(billingId: string): Promise<number> {
    const { data: subscription } = await supabaseAdmin
        .from('subscriptions')
        .select('billing_period')
        .eq('abacatepay_billing_id', billingId)
        .maybeSingle();

    return subscription?.billing_period === 'annual' ? 365 : 30;
}

// Ativa a assinatura automaticamente quando o pagamento for confirmado
// Também cria/reutiliza cliente no Stripe para unificar gestão de clientes
async function activateSubscriptionIfPaid(billingId: string): Promise<boolean> {
    try {
        // Buscar a subscription pelo billingId com dados do usuário
        const { data: subscription } = await supabaseAdmin
            .from('subscriptions')
            .select('user_id, plan_type, status, billing_period, stripe_customer_id')
            .eq('abacatepay_billing_id', billingId)
            .maybeSingle();

        if (!subscription || subscription.status === 'active') {
            return false; // Já ativa ou não encontrada
        }

        // Buscar dados do usuário para criar/reutilizar cliente no Stripe
        const { data: userData } = await supabaseAdmin.auth.admin.getUserById(subscription.user_id);
        const user = userData?.user;

        let stripeCustomerId = subscription.stripe_customer_id;

        // Criar/reutilizar cliente no Stripe se ainda não tiver
        if (!stripeCustomerId && user?.email) {
            try {
                console.log('[AbacatePay Check Status] Criando/reutilizando cliente Stripe para:', user.email);
                const stripeCustomer = await getStripeCustomer(
                    subscription.user_id,
                    user.email,
                    user.user_metadata?.full_name
                );
                stripeCustomerId = stripeCustomer.id;
                console.log('[AbacatePay Check Status] Stripe customer ID:', stripeCustomerId);
            } catch (stripeError: any) {
                console.error('[AbacatePay Check Status] Erro ao criar cliente Stripe:', stripeError.message);
                // Continua mesmo se falhar - a assinatura PIX funciona sem Stripe
            }
        }

        // Calcular período correto baseado no billing_period
        const now = new Date();
        const days = subscription.billing_period === 'annual' ? 365 : 30;
        const periodEnd = new Date(now.getTime() + days * 24 * 60 * 60 * 1000);

        // Montar dados de update incluindo stripe_customer_id se disponível
        const updateData: any = {
            status: 'active',
            current_period_start: now.toISOString(),
            current_period_end: periodEnd.toISOString(),
        };

        if (stripeCustomerId) {
            updateData.stripe_customer_id = stripeCustomerId;
        }

        const { error } = await supabaseAdmin
            .from('subscriptions')
            .update(updateData)
            .eq('user_id', subscription.user_id);

        if (error) {
            console.error('[AbacatePay Check Status] Error activating subscription:', error);
            return false;
        }

        console.log('[AbacatePay Check Status] Subscription activated for user:', subscription.user_id, 'Period:', subscription.billing_period, 'Stripe Customer:', stripeCustomerId || 'N/A');
        return true;
    } catch (err) {
        console.error('[AbacatePay Check Status] Exception:', err);
        return false;
    }
}

export async function GET(req: NextRequest) {
    try {
        const billingId = req.nextUrl.searchParams.get('billingId');

        if (!billingId) {
            return NextResponse.json(
                { error: 'billingId is required' },
                { status: 400 }
            );
        }

        const billing = await getAbacatepayBilling(billingId);

        if (!billing) {
            return NextResponse.json(
                { error: 'Billing not found' },
                { status: 404 }
            );
        }

        // Se o status for PAID, ativar a assinatura automaticamente
        let activated = false;
        if (billing.status === 'PAID') {
            activated = await activateSubscriptionIfPaid(billingId);
        }

        return NextResponse.json({
            billingId: billing.id,
            status: billing.status,
            amount: billing.amount,
            activated, // Informa se a assinatura foi ativada nesta verificação
        });

    } catch (error: any) {
        console.error('[AbacatePay Check Status] Error:', error);
        return NextResponse.json(
            { error: `Erro: ${error.message}` },
            { status: 500 }
        );
    }
}

import { NextResponse } from 'next/server';
import { supabaseAdmin } from '@/lib/supabase-admin';
import { getPeriodDays, BillingPeriod } from '@/lib/abacatepay';
import { getStripeCustomer } from '@/lib/stripe';

const ABACATEPAY_API_URL = 'https://api.abacatepay.com/v1';
const API_KEY = process.env.ABACATEPAY_API_KEY_PROD || process.env.ABACATEPAY_API_KEY_DEV;

export async function POST(req: Request) {
    try {
        const body = await req.json();
        const { userId, planType, billingPeriod, userEmail, userName, price } = body;

        // 1. Validação de entrada
        if (!userEmail || !userId) {
            return NextResponse.json({ error: 'Dados do usuário ausentes' }, { status: 400 });
        }

        if (!price || price < 100) {
            return NextResponse.json({ error: 'Preço inválido (mínimo 100 centavos)' }, { status: 400 });
        }

        console.log('[AbacatePay] === CRIANDO BILLING COM STRIPE CUSTOMER ===');
        console.log('[AbacatePay] Timestamp:', new Date().toISOString());
        console.log('[AbacatePay] User:', userId, 'Email:', userEmail);
        console.log('[AbacatePay] Plan:', planType, 'Period:', billingPeriod, 'Price:', price);

        // 2. Criar ou reutilizar cliente no Stripe (mesma lógica do cartão de crédito)
        let stripeCustomerId: string | null = null;
        try {
            const stripeCustomer = await getStripeCustomer(userId, userEmail, userName);
            stripeCustomerId = stripeCustomer.id;
            console.log('[AbacatePay] Stripe customer (criado/reutilizado):', stripeCustomerId);
        } catch (stripeError: any) {
            console.error('[AbacatePay] Erro ao criar/buscar cliente Stripe:', stripeError.message);
            // Continua mesmo se falhar - o PIX funciona sem Stripe, mas é bom ter o cliente
        }

        // 3. Montar body com placeholders para evitar erros de validação
        // AbacatePay exige cellphone e taxId se o objeto customer estiver presente.
        // O usuário completará os dados REAIS na tela de checkout.
        const billingBody = {
            frequency: "ONE_TIME",
            methods: ["PIX"],
            products: [
                {
                    externalId: `plan-${planType}-${billingPeriod}-${userId}`,
                    name: `Plano ${planType} - Cola Aí`,
                    description: `Assinatura ${billingPeriod} do plano ${planType}`,
                    quantity: 1,
                    price: price
                }
            ],
            customer: {
                name: userName || userEmail.split('@')[0],
                email: userEmail,
                cellphone: "11999999999", // Placeholder com DDD
                taxId: "41304588805",   // CPF de teste válido (passa no mod11)
            },
            returnUrl: "https://usecolaai.vercel.app",
            completionUrl: "https://usecolaai.vercel.app",
            metadata: {
                userId: userId,
                planType: planType,
                billingPeriod: billingPeriod
            }
        };

        console.log('[AbacatePay] Billing body (com placeholders):', JSON.stringify(billingBody, null, 2));

        const response = await fetch(`${ABACATEPAY_API_URL}/billing/create`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Accept': 'application/json',
                'Authorization': `Bearer ${API_KEY}`,
            },
            body: JSON.stringify(billingBody),
        });

        const data = await response.json();
        console.log('[AbacatePay] Billing response:', JSON.stringify(data, null, 2));

        if (!response.ok || data.error) {
            console.error('[AbacatePay] Erro:', data);

            // Se falhar por falta de customer, tentaremos o fallback de criar apenas com email se for possível
            // Mas a documentação diz que são opcionais.
            return NextResponse.json({
                success: false,
                error: data.error || 'Erro na API AbacatePay'
            }, { status: 500 });
        }

        const billing = data.data;
        console.log('[AbacatePay] Billing criado:', billing?.id);
        console.log('[AbacatePay] Checkout URL:', billing?.url);

        // 4. Salvar no Supabase (com stripe_customer_id se disponível)
        const now = new Date();
        const days = getPeriodDays(billingPeriod as BillingPeriod);
        const periodEnd = new Date(now.getTime() + days * 24 * 60 * 60 * 1000);

        const subscriptionData: any = {
            user_id: userId,
            plan_type: planType,
            status: 'pending_pix',
            payment_method: 'pix',
            abacatepay_billing_id: billing?.id,
            current_period_start: now.toISOString(),
            current_period_end: periodEnd.toISOString(),
            billing_period: billingPeriod,
        };

        // Adiciona stripe_customer_id se foi criado/encontrado
        if (stripeCustomerId) {
            subscriptionData.stripe_customer_id = stripeCustomerId;
        }

        await supabaseAdmin
            .from('subscriptions')
            .upsert(subscriptionData, { onConflict: 'user_id' });

        return NextResponse.json({
            success: true,
            url: billing?.url
        });

    } catch (error: any) {
        console.error('[AbacatePay] Exception:', error);
        return NextResponse.json({
            success: false,
            error: 'Internal Server Error'
        }, { status: 500 });
    }
}

