import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { stripe, getStripeCustomer } from '@/lib/stripe';
import { cookies } from 'next/headers';

export async function POST(req: NextRequest) {
    try {
        const supabase = await createClient();

        const {
            data: { user },
        } = await supabase.auth.getUser();

        if (!user) {
            return new NextResponse('Unauthorized', { status: 401 });
        }

        // Ensure we have a Stripe customer
        const customer = await getStripeCustomer(
            user.id,
            user.email || '',
            user.user_metadata?.full_name
        );

        if (!customer) {
            return new NextResponse('Could not create Stripe customer', { status: 500 });
        }

        // Search for existing subscription to check if we need to update stripe_customer_id
        const { data: subscription } = await supabase
            .from('subscriptions')
            .select('stripe_customer_id')
            .eq('user_id', user.id)
            .single();

        // If no subscription or no stripe_id, we might need to update/insert
        // But for Portal, we strictly need a Customer ID.
        // We should try to update the local DB with this customer ID if it's missing
        if (subscription && !subscription.stripe_customer_id) {
            const { error: updateError } = await supabase
                .from('subscriptions')
                .update({ stripe_customer_id: customer.id } as any)
                .eq('user_id', user.id);

            if (updateError) {
                console.error('Error updating stripe_customer_id in portal route:', updateError);
            }
        }

        // Use VERCEL_URL for production deployments, fallback to NEXT_PUBLIC_APP_URL or localhost
        const vercelUrl = process.env.VERCEL_URL ? `https://${process.env.VERCEL_URL}` : null;
        const appUrl = process.env.NEXT_PUBLIC_APP_URL || vercelUrl || 'http://localhost:3000';

        const session = await stripe.billingPortal.sessions.create({
            customer: customer.id,
            return_url: `${appUrl}/assinatura?portal=true`,
        });

        return NextResponse.json({ url: session.url });
    } catch (error) {
        console.error('Stripe portal error:', error);
        return new NextResponse('Internal Error: ' + (error as Error).message, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { stripe } from '@/lib/stripe';
import { supabaseAdmin } from '@/lib/supabase-admin';

// Map Stripe subscription status to Supabase status
function mapStripeStatus(stripeStatus: string): string {
    switch (stripeStatus) {
        case 'trialing':
            return 'trial';
        case 'active':
            return 'active';
        case 'canceled':
        case 'cancelled':
            return 'cancelled';
        case 'past_due':
        case 'unpaid':
            return 'expired';
        default:
            return stripeStatus;
    }
}

// Derive plan type from Stripe price ID
function getPlanTypeFromPriceId(priceId: string): string {
    if (priceId === process.env.NEXT_PUBLIC_STRIPE_PRICE_BASIC) return 'Basico';
    if (priceId === process.env.NEXT_PUBLIC_STRIPE_PRICE_PROFESSIONAL) return 'Avançado';
    if (priceId === process.env.NEXT_PUBLIC_STRIPE_PRICE_ENTERPRISE) return 'Profissional';
    return 'Basico'; // Default fallback
}

export async function POST(req: NextRequest) {
    try {
        const supabase = await createClient();
        const {
            data: { user },
        } = await supabase.auth.getUser();

        if (!user) {
            return new NextResponse('Unauthorized', { status: 401 });
        }

        console.log('[Sync] Starting sync for user:', user.id);

        // Get local subscription to find stripe_customer_id
        const { data: subscription } = await supabaseAdmin
            .from('subscriptions')
            .select('*')
            .eq('user_id', user.id)
            .maybeSingle(); // Use maybeSingle to handle no results gracefully

        // First try to get subscriptions from Stripe using customer ID
        let stripeCustomerId = subscription?.stripe_customer_id;

        // If no customer ID in local DB, try to find by email in Stripe
        if (!stripeCustomerId) {
            const customers = await stripe.customers.list({
                email: user.email,
                limit: 1
            });
            if (customers.data.length > 0) {
                stripeCustomerId = customers.data[0].id;
            }
        }

        if (!stripeCustomerId) {
            console.log('[Sync] No Stripe Customer ID found for user:', user.id);
            return new NextResponse('No Stripe Customer ID found', { status: 404 });
        }

        console.log('[Sync] Found Stripe customer:', stripeCustomerId);

        // List subscriptions from Stripe - prioritize active and trialing
        const stripeSubscriptions = await stripe.subscriptions.list({
            customer: stripeCustomerId,
            limit: 10, // Get more to find active one
        });

        console.log('[Sync] Found', stripeSubscriptions.data.length, 'subscriptions in Stripe');

        // Find the best subscription (prioritize active > trialing > others)
        let stripeSub = stripeSubscriptions.data.find(s => s.status === 'active');
        if (!stripeSub) {
            stripeSub = stripeSubscriptions.data.find(s => s.status === 'trialing');
        }
        if (!stripeSub && stripeSubscriptions.data.length > 0) {
            stripeSub = stripeSubscriptions.data[0]; // Fall back to most recent
        }

        if (!stripeSub) {
            console.log('[Sync] No subscriptions found in Stripe for customer:', stripeCustomerId);
            return NextResponse.json({ message: 'No subscriptions found in Stripe' });
        }

        console.log('[Sync] Using subscription:', stripeSub.id, 'status:', stripeSub.status);

        // Map Price ID to Plan Type
        const priceId = stripeSub.items.data[0].price.id;
        const planType = getPlanTypeFromPriceId(priceId);
        const mappedStatus = mapStripeStatus(stripeSub.status);

        console.log('[Sync] Plan type:', planType, 'Status:', mappedStatus);

        // Get the next invoice date from Stripe (this is the exact date of the next charge)
        let nextInvoiceDate: string | null = null;
        try {
            const upcomingInvoice = await stripe.invoices.createPreview({
                customer: stripeCustomerId,
                subscription: stripeSub.id
            } as any);
            if (upcomingInvoice.next_payment_attempt) {
                nextInvoiceDate = new Date(upcomingInvoice.next_payment_attempt * 1000).toISOString();
            } else if (upcomingInvoice.created) {
                nextInvoiceDate = new Date(upcomingInvoice.created * 1000 + 30 * 24 * 60 * 60 * 1000).toISOString();
            }
            console.log('[Sync] Next invoice date from Stripe:', nextInvoiceDate);
        } catch (invoiceError) {
            console.log('[Sync] No upcoming invoice found, using current_period_end');
            nextInvoiceDate = new Date((stripeSub as any).current_period_end * 1000).toISOString();
        }

        // Upsert to handle both insert and update cases
        const { error } = await supabaseAdmin
            .from('subscriptions')
            .upsert({
                user_id: user.id,
                stripe_customer_id: stripeCustomerId,
                stripe_subscription_id: stripeSub.id,
                stripe_price_id: priceId,
                status: mappedStatus,
                plan_type: planType,
                trial_ends_at: stripeSub.trial_end ? new Date(stripeSub.trial_end * 1000).toISOString() : null,
                current_period_start: (stripeSub as any).current_period_start ? new Date((stripeSub as any).current_period_start * 1000).toISOString() : new Date().toISOString(),
                current_period_end: (stripeSub as any).current_period_end ? new Date((stripeSub as any).current_period_end * 1000).toISOString() : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
                stripe_current_period_end: nextInvoiceDate || ((stripeSub as any).current_period_end ? new Date((stripeSub as any).current_period_end * 1000).toISOString() : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()),
                billing_period: 'monthly'
            } as any, { onConflict: 'user_id' });

        if (error) {
            console.error('[Sync] Error syncing subscription:', error);
            return NextResponse.json({
                error: 'Failed to update subscription',
                details: error.message,
                code: error.code
            }, { status: 500 });
        }

        console.log('[Sync] Successfully synced subscription');

        return NextResponse.json({
            message: 'Subscription synced successfully',
            status: mappedStatus,
            plan_type: planType,
            current_period_end: nextInvoiceDate || new Date((stripeSub as any).current_period_end * 1000).toISOString()
        });

    } catch (error) {
        console.error('[Sync] Sync error:', error);
        return new NextResponse('Internal Error', { status: 500 });
    }
}

'use client';

import React, { useEffect, useState } from 'react';
import { FiCheck, FiAlertCircle } from 'react-icons/fi';
import Image from 'next/image';
import { supabase } from '@/lib/supabase';
import StarRating from '@/components/ui/StarRating';
import { formatCurrency } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';

interface OrderInfo { id: string; order_number: number; customer_name: string; total: number; rated: boolean; user_settings: { app_name: string; logo_url: string | null; primary_color: string; }; }

export default function RatingClient({ token }: { token: string }) {
    const [order, setOrder] = useState<OrderInfo | null>(null);
    const [loading, setLoading] = useState(true);
    const [rating, setRating] = useState(0);
    const [comment, setComment] = useState('');
    const [submitting, setSubmitting] = useState(false);
    const [submitted, setSubmitted] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => { fetchOrder(); }, [token]);
    useEffect(() => { if (order?.user_settings) document.documentElement.style.setProperty('--primary', order.user_settings.primary_color); }, [order]);

    const fetchOrder = async () => {
        try {
            const { data, error } = await supabase.from('orders').select('id,order_number,customer_name,total,rated,user_id').eq('rating_token', token).single();
            if (error || !data) { setError('Pedido não encontrado'); setLoading(false); return; }
            if (data.rated) setSubmitted(true);
            const { data: settings } = await supabase.from('user_settings').select('app_name, logo_url, primary_color').eq('user_id', data.user_id).single();
            setOrder({ ...data, user_settings: settings || { app_name: 'Cola Aí', logo_url: null, primary_color: '#ff6b35' } });
        } catch { setError('Erro ao carregar pedido'); } finally { setLoading(false); }
    };



    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (rating === 0) { setError('Por favor, selecione uma avaliação'); return; }
        setSubmitting(true); setError('');
        try {
            const { data: orderData } = await supabase.from('orders').select('id, user_id, customer_name').eq('rating_token', token).single();
            if (!orderData) { setError('Pedido não encontrado'); return; }

            // Insert into store_ratings instead of ratings
            const { error: ratingError } = await supabase.from('store_ratings').insert({
                user_id: orderData.user_id,
                rating,
                comment: comment.trim() || null,
                customer_name: orderData.customer_name || 'Cliente'
            });

            if (ratingError) throw ratingError;

            await supabase.from('orders').update({ rated: true }).eq('id', orderData.id);
            setSubmitted(true);
        } catch (err) { console.error(err); setError('Erro ao enviar avaliação. Tente novamente.'); } finally { setSubmitting(false); }
    };

    if (loading) return <div className="min-h-screen bg-background flex items-center justify-center"><div className="flex flex-col items-center gap-4"><div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin" /><p className="text-text-muted">Carregando...</p></div></div>;
    if (error && !order) return <div className="min-h-screen bg-background flex items-center justify-center p-4"><div className="text-center"><FiAlertCircle className="text-error text-5xl mx-auto mb-4" /><h2 className="text-xl font-bold mb-2">{error}</h2><p className="text-text-muted">O link pode ter expirado ou o pedido não existe.</p></div></div>;
    if (submitted) return <div className="min-h-screen bg-background flex items-center justify-center p-4"><div className="text-center"><div className="w-20 h-20 mx-auto mb-6 rounded-full bg-success/20 flex items-center justify-center"><FiCheck className="text-success text-4xl" /></div><h2 className="text-2xl font-bold mb-2">Obrigado pela avaliação!</h2><p className="text-text-muted mb-4">Sua opinião é muito importante para nós.</p>{order?.user_settings && <p className="text-primary font-medium">{order.user_settings.app_name}</p>}</div></div>;

    return (
        <div className="min-h-screen bg-background flex items-center justify-center p-4">
            <div className="w-full max-w-md bg-bg-card border border-border rounded-xl overflow-hidden">
                {/* Header */}
                <div className="bg-primary/10 p-6 text-center">
                    <div className="relative w-20 h-20 mx-auto mb-4 rounded-full bg-bg-card flex items-center justify-center overflow-hidden">{order?.user_settings?.logo_url ? <Image src={order.user_settings.logo_url} alt="" fill className="object-contain" sizes="80px" /> : <span className="text-4xl">🌭</span>}</div>
                    <h1 className="text-xl font-bold">{order?.user_settings?.app_name}</h1>
                </div>

                {/* Order Info */}
                <div className="p-6 text-center border-b border-border">
                    <span className="inline-block px-4 py-1 bg-primary/20 text-primary rounded-full text-sm font-semibold mb-3">Pedido #{order?.order_number}</span>
                    <p className="text-lg font-medium mb-1">Olá, {order?.customer_name}!</p>
                    <p className="text-2xl font-bold text-primary">{formatCurrency(order?.total || 0)}</p>
                </div>

                {/* Rating Form */}
                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                    <div className="text-center">
                        <label className="block text-lg font-medium mb-4">Como foi sua experiência?</label>
                        <StarRating rating={rating} size="lg" interactive onChange={setRating} />
                        <div className="flex justify-between text-xs text-text-muted mt-2"><span>Ruim</span><span>Normal</span><span>Excelente</span></div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium mb-2" htmlFor="comment">Deixe um comentário (opcional)</label>
                        <textarea id="comment" className="w-full px-4 py-3 bg-bg-tertiary border border-border rounded-lg resize-none focus:border-primary focus:outline-none transition-colors" placeholder="Conte-nos mais sobre sua experiência..." value={comment} onChange={(e) => setComment(e.target.value)} rows={3} />
                    </div>

                    {error && <p className="text-error text-sm text-center">{error}</p>}

                    <button type="submit" disabled={submitting || rating === 0} className={cn('w-full py-4 rounded-lg font-semibold text-white transition-all', rating === 0 ? 'bg-gray-400 cursor-not-allowed' : 'bg-primary hover:bg-primary-hover active:scale-[0.98]')}>{submitting ? 'Enviando...' : 'Enviar Avaliação'}</button>
                </form>
            </div>
        </div>
    );
}

'use client';

import React, { useState, useMemo } from 'react';
import { cn } from '@/lib/utils';
import {
    FiSearch,
    FiChevronUp,
    FiChevronDown,
    FiChevronLeft,
    FiChevronRight,
    FiMoreVertical,
    FiCheck
} from 'react-icons/fi';

export interface Column<T> {
    key: keyof T | string;
    header: string;
    sortable?: boolean;
    width?: string;
    render?: (value: unknown, row: T) => React.ReactNode;
}

export interface DataTableProps<T> {
    columns: Column<T>[];
    data: T[];
    keyField: keyof T;
    searchable?: boolean;
    searchPlaceholder?: string;
    selectable?: boolean;
    onRowClick?: (row: T) => void;
    onSelectionChange?: (selected: T[]) => void;
    actions?: (row: T) => React.ReactNode;
    pageSize?: number;
    loading?: boolean;
    emptyMessage?: string;
}

export default function DataTable<T extends object>({
    columns,
    data,
    keyField,
    searchable = true,
    searchPlaceholder = 'Buscar...',
    selectable = false,
    onRowClick,
    onSelectionChange,
    actions,
    pageSize = 10,
    loading = false,
    emptyMessage = 'Nenhum dado encontrado',
}: DataTableProps<T>) {
    const [search, setSearch] = useState('');
    const [sortKey, setSortKey] = useState<keyof T | string | null>(null);
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc');
    const [selected, setSelected] = useState<Set<unknown>>(new Set());
    const [currentPage, setCurrentPage] = useState(1);

    // Filter data by search
    const filteredData = useMemo(() => {
        if (!search.trim()) return data;
        const lowerSearch = search.toLowerCase();
        return data.filter((row) =>
            Object.values(row).some(
                (val) => String(val).toLowerCase().includes(lowerSearch)
            )
        );
    }, [data, search]);

    // Sort data
    const sortedData = useMemo(() => {
        if (!sortKey) return filteredData;
        return [...filteredData].sort((a, b) => {
            const aVal = a[sortKey as keyof T];
            const bVal = b[sortKey as keyof T];
            if (aVal === bVal) return 0;
            if (aVal === null || aVal === undefined) return 1;
            if (bVal === null || bVal === undefined) return -1;
            const comparison = aVal < bVal ? -1 : 1;
            return sortDir === 'asc' ? comparison : -comparison;
        });
    }, [filteredData, sortKey, sortDir]);

    // Paginate data
    const paginatedData = useMemo(() => {
        const start = (currentPage - 1) * pageSize;
        return sortedData.slice(start, start + pageSize);
    }, [sortedData, currentPage, pageSize]);

    const totalPages = Math.ceil(sortedData.length / pageSize);

    const handleSort = (key: keyof T | string) => {
        if (sortKey === key) {
            setSortDir(sortDir === 'asc' ? 'desc' : 'asc');
        } else {
            setSortKey(key);
            setSortDir('asc');
        }
    };

    const toggleSelectAll = () => {
        if (selected.size === paginatedData.length) {
            setSelected(new Set());
            onSelectionChange?.([]);
        } else {
            const newSelected = new Set(paginatedData.map((row) => row[keyField]));
            setSelected(newSelected);
            onSelectionChange?.(paginatedData);
        }
    };

    const toggleSelect = (row: T) => {
        const key = row[keyField];
        const newSelected = new Set(selected);
        if (newSelected.has(key)) {
            newSelected.delete(key);
        } else {
            newSelected.add(key);
        }
        setSelected(newSelected);
        onSelectionChange?.(data.filter((r) => newSelected.has(r[keyField])));
    };

    const getValue = (row: T, key: keyof T | string): unknown => {
        if (typeof key === 'string' && key.includes('.')) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            return key.split('.').reduce((obj: any, k: string) => obj?.[k], row as any);
        }
        return row[key as keyof T];
    };

    if (loading) {
        return (
            <div className="bg-gray-800/50 border border-gray-700 rounded-xl overflow-hidden">
                <div className="p-4 border-b border-gray-700">
                    <div className="h-10 bg-gray-700 rounded-lg animate-pulse w-72" />
                </div>
                <div className="divide-y divide-gray-700">
                    {Array.from({ length: 5 }).map((_, i) => (
                        <div key={i} className="p-4 flex gap-4">
                            {Array.from({ length: columns.length }).map((_, j) => (
                                <div key={j} className="h-5 bg-gray-700 rounded animate-pulse flex-1" />
                            ))}
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="bg-gray-800/50 border border-gray-700 rounded-xl overflow-hidden">
            {/* Search Bar */}
            {searchable && (
                <div className="p-4 border-b border-gray-700">
                    <div className="relative">
                        <FiSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                        <input
                            type="text"
                            value={search}
                            onChange={(e) => {
                                setSearch(e.target.value);
                                setCurrentPage(1);
                            }}
                            placeholder={searchPlaceholder}
                            className="w-full max-w-sm pl-10 pr-4 py-2.5 bg-gray-900 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-orange-500 focus:ring-1 focus:ring-orange-500"
                        />
                    </div>
                </div>
            )}

            {/* Table */}
            <div className="overflow-x-auto">
                <table className="w-full">
                    <thead>
                        <tr className="bg-gray-900/50">
                            {selectable && (
                                <th className="w-12 px-4 py-3">
                                    <button
                                        onClick={toggleSelectAll}
                                        className={cn(
                                            "w-5 h-5 rounded border flex items-center justify-center transition-colors",
                                            selected.size === paginatedData.length && paginatedData.length > 0
                                                ? "bg-orange-500 border-orange-500"
                                                : "border-gray-600 hover:border-gray-500"
                                        )}
                                    >
                                        {selected.size === paginatedData.length && paginatedData.length > 0 && (
                                            <FiCheck className="text-white" size={14} />
                                        )}
                                    </button>
                                </th>
                            )}
                            {columns.map((col) => (
                                <th
                                    key={String(col.key)}
                                    className={cn(
                                        "px-4 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider",
                                        col.sortable && "cursor-pointer hover:text-white select-none"
                                    )}
                                    style={{ width: col.width }}
                                    onClick={() => col.sortable && handleSort(col.key)}
                                >
                                    <div className="flex items-center gap-2">
                                        {col.header}
                                        {col.sortable && sortKey === col.key && (
                                            sortDir === 'asc' ? <FiChevronUp size={14} /> : <FiChevronDown size={14} />
                                        )}
                                    </div>
                                </th>
                            ))}
                            {actions && <th className="w-12 px-4 py-3" />}
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-700/50">
                        {paginatedData.length === 0 ? (
                            <tr>
                                <td
                                    colSpan={columns.length + (selectable ? 1 : 0) + (actions ? 1 : 0)}
                                    className="px-4 py-12 text-center text-gray-500"
                                >
                                    {emptyMessage}
                                </td>
                            </tr>
                        ) : (
                            paginatedData.map((row) => {
                                const rowKey = row[keyField] as string;
                                const isSelected = selected.has(rowKey);
                                return (
                                    <tr
                                        key={rowKey}
                                        onClick={() => onRowClick?.(row)}
                                        className={cn(
                                            "transition-colors",
                                            onRowClick && "cursor-pointer",
                                            isSelected ? "bg-orange-500/10" : "hover:bg-gray-700/30"
                                        )}
                                    >
                                        {selectable && (
                                            <td className="px-4 py-3">
                                                <button
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        toggleSelect(row);
                                                    }}
                                                    className={cn(
                                                        "w-5 h-5 rounded border flex items-center justify-center transition-colors",
                                                        isSelected
                                                            ? "bg-orange-500 border-orange-500"
                                                            : "border-gray-600 hover:border-gray-500"
                                                    )}
                                                >
                                                    {isSelected && <FiCheck className="text-white" size={14} />}
                                                </button>
                                            </td>
                                        )}
                                        {columns.map((col) => {
                                            const value = getValue(row, col.key);
                                            return (
                                                <td key={String(col.key)} className="px-4 py-3 text-sm text-gray-300">
                                                    {col.render ? col.render(value, row) : String(value ?? '-')}
                                                </td>
                                            );
                                        })}
                                        {actions && (
                                            <td className="px-4 py-3">
                                                <div className="flex justify-end">
                                                    {actions(row)}
                                                </div>
                                            </td>
                                        )}
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="p-4 border-t border-gray-700 flex items-center justify-between">
                    <span className="text-sm text-gray-500">
                        Mostrando {((currentPage - 1) * pageSize) + 1} a {Math.min(currentPage * pageSize, sortedData.length)} de {sortedData.length}
                    </span>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                            disabled={currentPage === 1}
                            className="p-2 rounded-lg bg-gray-700 text-gray-400 hover:text-white hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                        >
                            <FiChevronLeft size={18} />
                        </button>
                        <span className="px-4 py-2 text-sm text-gray-400">
                            {currentPage} / {totalPages}
                        </span>
                        <button
                            onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                            disabled={currentPage === totalPages}
                            className="p-2 rounded-lg bg-gray-700 text-gray-400 hover:text-white hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                        >
                            <FiChevronRight size={18} />
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, ReactNode } from 'react';
import { FiPlus, FiEdit2, FiTrash2, FiSearch, FiPercent, FiDollarSign, FiCopy, FiCheck } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';
import UpgradePrompt from '@/components/ui/UpgradePrompt';
import { useToast } from '@/components/ui/Toast';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { useCouponsCache } from '@/hooks/useDataCache';
import { saveCoupon, deleteCoupon } from '@/lib/dataAccess';
import { formatCurrency } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';
import type { CachedCoupon as Coupon } from '@/types/db';

export function CuponsTab() {
    const { user } = useAuth();
    const { plan, canAccess } = useSubscription();
    
    // Reactive local-first cache
    const { coupons: rawCoupons, loading } = useCouponsCache();
    
    const [searchTerm, setSearchTerm] = useState('');
    const [copiedId, setCopiedId] = useState<string | null>(null);
    const [showModal, setShowModal] = useState(false);
    const [editingCoupon, setEditingCoupon] = useState<Coupon | null>(null);
    const [formCode, setFormCode] = useState('');
    const [formDescription, setFormDescription] = useState('');
    const [formDiscountType, setFormDiscountType] = useState<'percentage' | 'fixed'>('percentage');
    const [formDiscountValue, setFormDiscountValue] = useState('');
    const [formMinOrderValue, setFormMinOrderValue] = useState('');
    const [formMaxDiscount, setFormMaxDiscount] = useState('');
    const [formUsageLimit, setFormUsageLimit] = useState('');
    const [formValidUntil, setFormValidUntil] = useState('');
    const [formFirstOrderOnly, setFormFirstOrderOnly] = useState(false);
    const toast = useToast();

    if (!canAccess?.('coupons')) {
        return <UpgradePrompt feature="Cupons de Desconto" requiredPlan="Profissional" currentPlan={plan} fullPage />;
    }

    const generateRandomCode = () => { 
        const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'; 
        let code = ''; 
        for (let i = 0; i < 8; i++) code += chars.charAt(Math.floor(Math.random() * chars.length)); 
        setFormCode(code); 
    };

    const openAddModal = () => { 
        setEditingCoupon(null); 
        setFormCode(''); 
        setFormDescription(''); 
        setFormDiscountType('percentage'); 
        setFormDiscountValue(''); 
        setFormMinOrderValue(''); 
        setFormMaxDiscount(''); 
        setFormUsageLimit(''); 
        setFormValidUntil(''); 
        setFormFirstOrderOnly(false); 
        setShowModal(true); 
    };

    const openEditModal = (coupon: Coupon) => { 
        setEditingCoupon(coupon); 
        setFormCode(coupon.code); 
        setFormDescription(coupon.description || ''); 
        setFormDiscountType(coupon.discount_type); 
        setFormDiscountValue(coupon.discount_value.toString()); 
        setFormMinOrderValue(coupon.min_order_value.toString()); 
        setFormMaxDiscount(coupon.max_discount?.toString() || ''); 
        setFormUsageLimit(coupon.usage_limit?.toString() || ''); 
        setFormValidUntil(coupon.valid_until ? coupon.valid_until.split('T')[0] : ''); 
        setFormFirstOrderOnly(coupon.first_order_only); 
        setShowModal(true); 
    };

    const handleSaveCoupon = async () => {
        if (!user || !formCode || !formDiscountValue) return;
        try {
            const couponData = { 
                user_id: user.id, 
                code: formCode.toUpperCase(), 
                description: formDescription || null, 
                discount_type: formDiscountType, 
                discount_value: parseFloat(formDiscountValue), 
                min_order_value: parseFloat(formMinOrderValue) || 0, 
                max_discount: formMaxDiscount ? parseFloat(formMaxDiscount) : null, 
                usage_limit: formUsageLimit ? parseInt(formUsageLimit) : null, 
                valid_until: formValidUntil ? new Date(formValidUntil).toISOString() : null, 
                first_order_only: formFirstOrderOnly,
                active: editingCoupon ? editingCoupon.active : true,
                usage_count: editingCoupon ? editingCoupon.usage_count : 0,
                ...(editingCoupon ? { id: editingCoupon.id } : {})
            };
            
            await saveCoupon(couponData);
            toast.success(editingCoupon ? 'Cupom atualizado!' : 'Cupom criado!');
            setShowModal(false); 
        } catch (error) { 
            console.error('Error saving coupon:', error); 
            toast.error('Erro ao salvar cupom'); 
        }
    };

    const handleDeleteCoupon = async (id: string) => { 
        if (!confirm('Tem certeza que deseja excluir este cupom?')) return; 
        try { 
            await deleteCoupon(id); 
            toast.success('Cupom excluído!'); 
        } catch (error) { 
            console.error('Error deleting coupon:', error); 
            toast.error('Erro ao excluir cupom'); 
        } 
    };

    const toggleCouponActive = async (coupon: Coupon) => { 
        try { 
            await saveCoupon({ ...coupon, active: !coupon.active }); 
            toast.success(!coupon.active ? 'Cupom ativado!' : 'Cupom desativado!'); 
        } catch (error) { 
            console.error('Error toggling coupon:', error); 
            toast.error('Erro ao alternar status do cupom');
        } 
    };

    const copyCode = (code: string, id: string) => { 
        navigator.clipboard.writeText(code); 
        setCopiedId(id); 
        toast.success('Código copiado!'); 
        setTimeout(() => setCopiedId(null), 2000); 
    };

    const formatDateShort = (date: string) => new Intl.DateTimeFormat('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' }).format(new Date(date));
    const isExpired = (coupon: Coupon) => coupon.valid_until ? new Date(coupon.valid_until) < new Date() : false;
    const isLimitReached = (coupon: Coupon) => coupon.usage_limit ? coupon.usage_count >= coupon.usage_limit : false;
    const getDiscountLabel = (coupon: Coupon) => coupon.discount_type === 'percentage' ? `${coupon.discount_value}%` : formatCurrency(coupon.discount_value);
    
    const filteredCoupons = React.useMemo(() => 
        (rawCoupons || []).filter(c => 
            c.code.toLowerCase().includes(searchTerm.toLowerCase()) || 
            c.description?.toLowerCase().includes(searchTerm.toLowerCase())
        ), [rawCoupons, searchTerm]);

    const activeCount = React.useMemo(() => (rawCoupons || []).filter(c => c.active).length, [rawCoupons]);
    const totalUsage = React.useMemo(() => (rawCoupons || []).reduce((sum, c) => sum + (c.usage_count || 0), 0), [rawCoupons]);

    return (
        <div className="max-w-[1200px] mx-auto">
            {/* Header */}
            <div className="flex items-start justify-between mb-6 gap-5 max-md:flex-col">
                <div><h1 className="text-[2rem] font-bold mb-2">Cupons de Desconto</h1><p className="text-text-secondary">Crie promoções e códigos de desconto</p></div>
                <Button leftIcon={<FiPlus />} onClick={openAddModal}>Novo Cupom</Button>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-3 gap-4 mb-6 max-md:grid-cols-1">
                <Card className="p-5! text-center"><span className="block text-2xl font-bold mb-1">{(rawCoupons || []).length}</span><span className="text-sm text-text-muted">Total de Cupons</span></Card>
                <Card className="p-5! text-center"><span className="block text-2xl font-bold mb-1">{activeCount}</span><span className="text-sm text-text-muted">Ativos</span></Card>
                <Card className="p-5! text-center"><span className="block text-2xl font-bold mb-1">{totalUsage}</span><span className="text-sm text-text-muted">Usos Totais</span></Card>
            </div>

            {/* Search */}
            <Card className="mb-6 p-4!"><Input placeholder="Buscar cupons..." leftIcon={<FiSearch />} value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} /></Card>

            {/* Coupons List */}
            <div className="flex flex-col gap-3">
                {loading ? [1, 2, 3].map(i => <div key={i} className="h-[100px] rounded-md bg-bg-tertiary animate-pulse" />) : filteredCoupons.length > 0 ? filteredCoupons.map((coupon) => (
                    <Card key={coupon.id} className={cn('p-5! transition-all duration-fast', (!coupon.active || isExpired(coupon) || isLimitReached(coupon)) && 'opacity-60')}>
                        <div className="flex items-start justify-between gap-4 max-md:flex-col">
                            <div className="flex items-center gap-4">
                                <div className="flex items-center gap-2">
                                    <span className="font-mono text-lg font-bold text-primary tracking-wide">{coupon.code}</span>
                                    <button className="p-1.5 bg-transparent border-none text-text-muted cursor-pointer transition-all duration-fast hover:text-primary" onClick={() => copyCode(coupon.code, coupon.id)}>{copiedId === coupon.id ? <FiCheck /> : <FiCopy />}</button>
                                </div>
                                <div className="flex items-center gap-1.5 px-3 py-1.5 bg-primary/15 rounded-full text-primary font-semibold">
                                    {coupon.discount_type === 'percentage' ? <FiPercent /> : <FiDollarSign />}
                                    <span>{getDiscountLabel(coupon)}</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-2 max-md:justify-end max-md:w-full">
                                <button className={cn('px-3 py-1.5 bg-bg-tertiary border border-border rounded-full text-text-secondary text-[0.8rem] cursor-pointer transition-all duration-fast', coupon.active && 'bg-accent/15 border-accent text-accent')} onClick={() => toggleCouponActive(coupon)}>{coupon.active ? 'Ativo' : 'Inativo'}</button>
                                <button className="w-9 h-9 flex items-center justify-center bg-bg-tertiary border border-border rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:border-border-light hover:text-text-primary" onClick={() => openEditModal(coupon)}><FiEdit2 /></button>
                                <button className="w-9 h-9 flex items-center justify-center bg-bg-tertiary border border-border rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:bg-error/10 hover:border-error hover:text-error" onClick={() => handleDeleteCoupon(coupon.id)}><FiTrash2 /></button>
                            </div>
                        </div>
                        <div className="mt-3">
                            {coupon.description && <p className="text-sm text-text-secondary mb-2">{coupon.description}</p>}
                            <div className="flex flex-wrap gap-2">
                                {coupon.min_order_value > 0 && <span className="px-2.5 py-1 bg-bg-tertiary rounded-full text-xs text-text-secondary">Mín: {formatCurrency(coupon.min_order_value)}</span>}
                                {coupon.usage_limit && <span className="px-2.5 py-1 bg-bg-tertiary rounded-full text-xs text-text-secondary">{coupon.usage_count}/{coupon.usage_limit} usos</span>}
                                {coupon.valid_until && <span className={cn('px-2.5 py-1 bg-bg-tertiary rounded-full text-xs text-text-secondary', isExpired(coupon) && 'text-error')}>Até {formatDateShort(coupon.valid_until)}</span>}
                                {coupon.first_order_only && <span className="px-2.5 py-1 bg-bg-tertiary rounded-full text-xs text-text-secondary">Primeira compra</span>}
                            </div>
                        </div>
                    </Card>
                )) : (
                    <div className="text-center py-15 px-5">
                        <FiPercent className="text-6xl text-text-muted mb-4 mx-auto" />
                        <h3 className="text-xl mb-2">Nenhum cupom cadastrado</h3>
                        <p className="text-text-secondary mb-5">Crie cupons de desconto para atrair mais clientes</p>
                        <Button leftIcon={<FiPlus />} onClick={openAddModal}>Criar Cupom</Button>
                    </div>
                )}
            </div>

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-1000 p-4" onClick={() => setShowModal(false)}>
                    <div className="bg-bg-card rounded-lg p-6 w-full max-w-[500px] max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
                        <h2 className="text-xl font-semibold mb-5">{editingCoupon ? 'Editar Cupom' : 'Novo Cupom'}</h2>
                        <div className="mb-4"><label className="block text-sm text-text-secondary mb-2">Código do Cupom</label><div className="flex gap-2"><Input value={formCode} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormCode(e.target.value.toUpperCase())} placeholder="Ex: PROMO10" /><Button variant="outline" onClick={generateRandomCode}>Gerar</Button></div></div>
                        <div className="mb-4"><label className="block text-sm text-text-secondary mb-2">Descrição (opcional)</label><Input value={formDescription} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormDescription(e.target.value)} placeholder="Ex: Desconto de inauguração" /></div>
                        <div className="grid grid-cols-2 gap-4 mb-4 max-md:grid-cols-1">
                            <div><label className="block text-sm text-text-secondary mb-2">Tipo de Desconto</label><select value={formDiscountType} onChange={(e) => setFormDiscountType(e.target.value as 'percentage' | 'fixed')} className="w-full px-4 py-3 bg-bg-tertiary border border-border rounded-md text-text-primary text-base cursor-pointer"><option value="percentage">Porcentagem (%)</option><option value="fixed">Valor Fixo (R$)</option></select></div>
                            <div><label className="block text-sm text-text-secondary mb-2">Valor do Desconto</label><Input type="number" step={formDiscountType === 'percentage' ? '1' : '0.01'} value={formDiscountValue} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormDiscountValue(e.target.value)} placeholder={formDiscountType === 'percentage' ? '10' : '5.00'} /></div>
                        </div>
                        <div className="grid grid-cols-2 gap-4 mb-4 max-md:grid-cols-1">
                            <div><label className="block text-sm text-text-secondary mb-2">Pedido Mínimo (R$)</label><Input type="number" step="0.01" value={formMinOrderValue} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormMinOrderValue(e.target.value)} placeholder="0.00" /></div>
                            {formDiscountType === 'percentage' && <div><label className="block text-sm text-text-secondary mb-2">Desconto Máximo (R$)</label><Input type="number" step="0.01" value={formMaxDiscount} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormMaxDiscount(e.target.value)} placeholder="Sem limite" /></div>}
                        </div>
                        <div className="grid grid-cols-2 gap-4 mb-4 max-md:grid-cols-1">
                            <div><label className="block text-sm text-text-secondary mb-2">Limite de Usos</label><Input type="number" value={formUsageLimit} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormUsageLimit(e.target.value)} placeholder="Ilimitado" /></div>
                            <div><label className="block text-sm text-text-secondary mb-2">Válido Até</label><Input type="date" value={formValidUntil} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormValidUntil(e.target.value)} /></div>
                        </div>
                        <div className="mb-4"><label className="flex items-center gap-2.5 cursor-pointer"><input type="checkbox" className="w-[18px] h-[18px] accent-primary" checked={formFirstOrderOnly} onChange={(e) => setFormFirstOrderOnly(e.target.checked)} />Válido apenas para primeira compra</label></div>
                        <div className="flex gap-3 justify-end mt-6"><Button variant="outline" onClick={() => setShowModal(false)}>Cancelar</Button><Button onClick={handleSaveCoupon}>{editingCoupon ? 'Salvar' : 'Criar Cupom'}</Button></div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { FiSearch, FiMessageCircle, FiFilter, FiUser, FiClock, FiShoppingBag } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/lib/supabase';
import { formatCurrency } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';
import { WhatsappSenderModal } from './WhatsappSenderModal';
import { useCustomersCache, useOrdersCache } from '@/hooks/useDataCache';

export interface CustomerCRM {
    id: string;
    phone: string;
    name: string;
    email: string | null;
    total_points: number;
    total_spent: number;
    total_orders: number;
    created_at: string | null;
    last_order_date?: string | null; // Pode ser mapeado via pedidos
}

export function CustomerListTab() {
    const { customers: rawCustomers, loading: loadingCustomers } = useCustomersCache();
    const { orders: rawOrders, loading: loadingOrders } = useOrdersCache();
    const [searchTerm, setSearchTerm] = useState('');
    const [filterInactive, setFilterInactive] = useState(false);
    const [selectedCustomerIds, setSelectedCustomerIds] = useState<Set<string>>(new Set());
    const [showWhatsappModal, setShowWhatsappModal] = useState(false);

    const loading = loadingCustomers && loadingOrders;

    const customers = React.useMemo(() => {
        const lastOrdersMap = new Map<string, string | null>();
        if (rawOrders) {
            rawOrders.forEach(order => {
                if (order.customer_phone && !lastOrdersMap.has(order.customer_phone)) {
                    lastOrdersMap.set(order.customer_phone, order.created_at);
                }
            });
        }

        return (rawCustomers || []).map(c => ({
            ...c,
            last_order_date: lastOrdersMap.get(c.phone) || c.created_at
        })).sort((a, b) => (b.total_spent || 0) - (a.total_spent || 0));
    }, [rawCustomers, rawOrders]);

    // Lógica de inatividade (mais de 30 dias)
    const isInactive = (dateStr?: string | null) => {
        if (!dateStr) return false;
        const now = new Date();
        const date = new Date(dateStr);
        const diffMs = now.getTime() - date.getTime();
        const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
        return diffDays > 30;
    };

    // Filter
    const filteredCustomers = React.useMemo(() => {
        let result = customers;
        if (searchTerm) {
            const query = searchTerm.toLowerCase();
            const digits = searchTerm.replace(/\D/g, '');
            result = result.filter(c =>
                c.name.toLowerCase().includes(query) ||
                (digits && c.phone.includes(digits))
            );
        }
        if (filterInactive) {
            result = result.filter(c => isInactive(c.last_order_date));
        }
        return result;
    }, [customers, searchTerm, filterInactive]);

    // Seleção
    const toggleSelectAll = () => {
        if (selectedCustomerIds.size === filteredCustomers.length && filteredCustomers.length > 0) {
            setSelectedCustomerIds(new Set());
        } else {
            setSelectedCustomerIds(new Set(filteredCustomers.map(c => c.id)));
        }
    };

    const toggleSelectCustomer = (id: string) => {
        const next = new Set(selectedCustomerIds);
        if (next.has(id)) next.delete(id);
        else next.add(id);
        setSelectedCustomerIds(next);
    };

    const selectedCustomersList = customers.filter(c => selectedCustomerIds.has(c.id));

    // Utils visuais
    const formatDate = (dateStr?: string | null) => {
        if (!dateStr) return 'Nunca';
        return new Intl.DateTimeFormat('pt-BR', { day: '2-digit', month: 'short', year: 'numeric' }).format(new Date(dateStr));
    };

    return (
        <div className="flex flex-col gap-6">
            <Card className="flex items-center justify-between gap-4 flex-wrap p-4!">
                <div className="flex items-start sm:items-center flex-col sm:flex-row gap-3 w-full lg:w-auto flex-1">
                    <Input
                        placeholder="Buscar por nome ou telefone..."
                        leftIcon={<FiSearch />}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="flex-1 w-full sm:w-auto"
                    />
                    <button
                        className={cn(
                            "flex items-center gap-2 px-4 py-2 bg-bg-tertiary border border-border rounded-md text-sm font-medium transition-all",
                            filterInactive && "bg-accent/10 border-accent text-accent"
                        )}
                        onClick={() => setFilterInactive(!filterInactive)}
                    >
                        <FiFilter /> Inativos (+30 dias)
                    </button>
                </div>
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between sm:justify-start gap-3 w-full lg:w-auto">
                    <span className="text-sm text-text-muted text-center sm:text-left">
                        {selectedCustomerIds.size} selecionado(s)
                    </span>
                    <Button
                        leftIcon={<FiMessageCircle />}
                        variant={selectedCustomerIds.size > 0 ? "primary" : "outline"}
                        disabled={selectedCustomerIds.size === 0}
                        onClick={() => setShowWhatsappModal(true)}
                        className="w-full sm:w-auto"
                    >
                        Disparar WhatsApp
                    </Button>
                </div>
            </Card>

            <Card className="overflow-hidden p-0!">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-bg-tertiary border-b border-border">
                                <th className="p-4 w-[50px] whitespace-nowrap">
                                    <input
                                        type="checkbox"
                                        className="w-[18px] h-[18px] cursor-pointer accent-primary"
                                        checked={selectedCustomerIds.size > 0 && selectedCustomerIds.size === filteredCustomers.length}
                                        onChange={toggleSelectAll}
                                    />
                                </th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap">Cliente</th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap">Telefone</th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap hidden sm:table-cell">Última Compra</th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap hidden md:table-cell">Total Pedidos</th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap hidden sm:table-cell">Gastos</th>
                                <th className="p-4 text-center text-sm font-semibold text-text-secondary whitespace-nowrap">Status</th>
                            </tr>
                        </thead>
                        <tbody>
                            {loading ? (
                                <tr>
                                    <td colSpan={7} className="p-8 text-center text-text-muted">Carregando clientes...</td>
                                </tr>
                            ) : filteredCustomers.length === 0 ? (
                                <tr>
                                    <td colSpan={7} className="p-8 text-center text-text-muted">Nenhum cliente encontrado.</td>
                                </tr>
                            ) : (
                                filteredCustomers.map(customer => {
                                    const inactive = isInactive(customer.last_order_date);
                                    return (
                                        <tr key={customer.id} className={cn(
                                            "border-b border-border hover:bg-bg-tertiary/50 transition-colors",
                                            selectedCustomerIds.has(customer.id) && "bg-primary/5"
                                        )}>
                                            <td className="p-4 whitespace-nowrap">
                                                <input
                                                    type="checkbox"
                                                    className="w-[18px] h-[18px] cursor-pointer accent-primary"
                                                    checked={selectedCustomerIds.has(customer.id)}
                                                    onChange={() => toggleSelectCustomer(customer.id)}
                                                />
                                            </td>
                                            <td className="p-4 whitespace-nowrap">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-8 h-8 rounded-full bg-border flex items-center justify-center text-text-secondary shrink-0">
                                                        <FiUser />
                                                    </div>
                                                    <span className="font-medium text-text-primary">{customer.name}</span>
                                                </div>
                                            </td>
                                            <td className="p-4 text-text-secondary whitespace-nowrap">{customer.phone}</td>
                                            <td className="p-4 text-text-secondary whitespace-nowrap hidden sm:table-cell">
                                                <div className="flex items-center gap-2">
                                                    <FiClock className={inactive ? "text-error" : "text-text-muted"} />
                                                    <span className={inactive ? "text-error" : ""}>{formatDate(customer.last_order_date)}</span>
                                                </div>
                                            </td>
                                            <td className="p-4 text-text-secondary whitespace-nowrap hidden md:table-cell">
                                                <div className="flex items-center gap-2">
                                                    <FiShoppingBag className="text-primary hidden md:block" /> {customer.total_orders || 0}
                                                </div>
                                            </td>
                                            <td className="p-4 font-semibold text-[#27ae60] whitespace-nowrap hidden sm:table-cell">
                                                {formatCurrency(customer.total_spent || 0)}
                                            </td>
                                            <td className="p-4 text-center whitespace-nowrap">
                                                {inactive ? (
                                                    <span className="px-2 py-1 bg-error/10 text-error rounded-full text-xs font-medium">Inativo</span>
                                                ) : (
                                                    <span className="px-2 py-1 bg-[#27ae60]/10 text-[#27ae60] rounded-full text-xs font-medium">Ativo</span>
                                                )}
                                            </td>
                                        </tr>
                                    )
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </Card>

            {/* Modal de Disparo (implementado em outro arquivo para organizar) */}
            {showWhatsappModal && (
                <WhatsappSenderModal
                    recipients={selectedCustomersList}
                    onClose={() => setShowWhatsappModal(false)}
                />
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { FiGift, FiUsers, FiPlus, FiEdit2, FiTrash2, FiSearch, FiStar, FiSettings, FiTrendingUp, FiToggleLeft, FiToggleRight, FiTag, FiShoppingBag, FiDollarSign } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';
import UpgradePrompt from '@/components/ui/UpgradePrompt';
import { useToast } from '@/components/ui/Toast';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { db } from '@/lib/db';
import { cn } from '@/lib/utils';
import { 
    useCustomersCache, 
    useLoyaltyRewardsCache, 
    useLoyaltySettingsCache, 
    useAppSettingsCache 
} from '@/hooks/useDataCache';
import { 
    saveLoyaltyReward, 
    deleteLoyaltyReward, 
    saveLoyaltySettings, 
    saveAppSettings 
} from '@/lib/dataAccess';

import type { 
    CachedClient as Customer, 
    CachedLoyaltyReward as LoyaltyReward, 
    CachedLoyaltySettings as LoyaltySettings, 
    CachedAppSetting as AppSettings 
} from '@/types/db';

type TabType = 'customers' | 'rewards' | 'settings';

export function FidelidadeTab() {
    const { user } = useAuth();
    const { plan, canAccess } = useSubscription();
    
    // Use the reactive cache hooks
    const { customers: rawCustomers, loading: loadingCustomers } = useCustomersCache();
    const { rewards: rawRewards, loading: loadingRewards } = useLoyaltyRewardsCache();
    const { settings: rawSettings, loading: loadingSettings } = useLoyaltySettingsCache();
    const { settings: rawAppSettings, loading: loadingAppSettings } = useAppSettingsCache();

    const [activeTab, setActiveTab] = useState<TabType>('customers');
    const [searchTerm, setSearchTerm] = useState('');
    const [showRewardModal, setShowRewardModal] = useState(false);
    const [editingReward, setEditingReward] = useState<LoyaltyReward | null>(null);
    const [rewardForm, setRewardForm] = useState({ 
        name: '', 
        description: '', 
        points_cost: 100, 
        reward_type: 'discount_percent' as LoyaltyReward['reward_type'], 
        reward_value: 10, 
        min_order_value: 0 
    });
    
    const toast = useToast();

    const formatCurrency = (value: number) => {
        return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);
    };

    const loading = loadingCustomers || loadingRewards || loadingSettings || loadingAppSettings;

    const toggleLoyalty = async () => { 
        if (!rawAppSettings || !user) return; 
        try {
            const newValue = !rawAppSettings.loyalty_enabled; 
            // All dataAccess write functions now take a single data object
            await saveAppSettings({ ...rawAppSettings, loyalty_enabled: newValue, user_id: user.id });
            toast.success(newValue ? 'Fidelidade ativada!' : 'Fidelidade desativada!');
        } catch (err) {
            console.error('Error toggling loyalty:', err);
            toast.error('Erro ao salvar configuração');
        }
    };

    const toggleCoupons = async () => { 
        if (!rawAppSettings || !user) return; 
        try {
            const newValue = !rawAppSettings.coupons_enabled; 
            await saveAppSettings({ ...rawAppSettings, coupons_enabled: newValue, user_id: user.id });
            toast.success(newValue ? 'Cupons ativados!' : 'Cupons desativados!');
        } catch (err) {
            console.error('Error toggling coupons:', err);
            toast.error('Erro ao salvar configuração');
        }
    };

    const handleSaveReward = async () => { 
        if (!user) return; 
        try {
            const rewardData = { 
                user_id: user.id, 
                name: rewardForm.name, 
                description: rewardForm.description || null, 
                points_cost: rewardForm.points_cost, 
                reward_type: rewardForm.reward_type, 
                reward_value: rewardForm.reward_value, 
                min_order_value: rewardForm.min_order_value, 
                is_active: true,
                ...(editingReward ? { id: editingReward.id } : {})
            }; 
            await saveLoyaltyReward(rewardData);
            toast.success(editingReward ? 'Recompensa atualizada!' : 'Recompensa criada!'); 
            setShowRewardModal(false); 
            setEditingReward(null); 
            resetRewardForm(); 
        } catch (err) {
            console.error('Error saving reward:', err);
            toast.error('Erro ao salvar recompensa');
        }
    };

    const handleDeleteReward = async (id: string) => { 
        if (!confirm('Excluir esta recompensa?')) return; 
        try {
            await deleteLoyaltyReward(id);
            toast.success('Recompensa excluída!'); 
        } catch (err) {
            console.error('Error deleting reward:', err);
            toast.error('Erro ao excluir recompensa');
        }
    };

    const handleSaveSettings = async () => { 
        if (!user || !rawSettings) return; 
        try {
            await saveLoyaltySettings({ ...rawSettings, user_id: user.id });
            toast.success('Configurações salvas!'); 
        } catch (err) {
            console.error('Error saving settings:', err);
            toast.error('Erro ao salvar configurações');
        }
    };

    const resetRewardForm = () => setRewardForm({ name: '', description: '', points_cost: 100, reward_type: 'discount_percent', reward_value: 10, min_order_value: 0 });
    const openEditReward = (reward: LoyaltyReward) => { setEditingReward(reward); setRewardForm({ name: reward.name, description: reward.description || '', points_cost: reward.points_cost, reward_type: reward.reward_type, reward_value: reward.reward_value || 0, min_order_value: reward.min_order_value }); setShowRewardModal(true); };

    const getTierIcon = (points: number) => {
        if (!rawSettings) return '🥉';
        if (points >= rawSettings.tier_platinum_min) return '💎';
        if (points >= rawSettings.tier_gold_min) return '🥇';
        if (points >= rawSettings.tier_silver_min) return '🥈';
        return '🥉';
    };

    const getTierColor = (points: number) => {
        if (!rawSettings) return '#d97706';
        if (points >= rawSettings.tier_platinum_min) return '#a855f7';
        if (points >= rawSettings.tier_gold_min) return '#f59e0b';
        if (points >= rawSettings.tier_silver_min) return '#94a3b8';
        return '#d97706';
    };

    const filteredCustomers = React.useMemo(() => (rawCustomers || []).filter(c => {
        if ((c.total_orders || 0) === 0) return false;
        const searchLower = searchTerm.toLowerCase();
        const searchDigits = searchTerm.replace(/\D/g, '');
        return c.name.toLowerCase().includes(searchLower) || c.phone.includes(searchDigits);
    }).sort((a, b) => (b.total_points || 0) - (a.total_points || 0)), [rawCustomers, searchTerm]);

    const stats = React.useMemo(() => ({
        totalCustomers: filteredCustomers.length,
        totalPoints: filteredCustomers.reduce((sum, c) => sum + (c.total_points || 0), 0),
        avgPoints: filteredCustomers.length ? Math.round(filteredCustomers.reduce((sum, c) => sum + (c.total_points || 0), 0) / filteredCustomers.length) : 0,
        totalSavings: 0 // Default until we have this field in Dexie
    }), [filteredCustomers]);

    if (!canAccess?.('loyalty')) return <UpgradePrompt feature="Programa de Fidelidade" requiredPlan="Avançado" currentPlan={plan} fullPage />;

    if (rawAppSettings && !rawAppSettings.loyalty_enabled) {
        return (
            <div className="max-w-[1200px] mx-auto">
                <div className="flex items-start justify-between mb-6"><div><h1 className="text-[2rem] font-bold mb-2">Programa de Fidelidade</h1><p className="text-text-secondary">Gerencie seus clientes e recompensas</p></div></div>
                <Card className="text-center py-12"><FiToggleLeft className="text-5xl mb-4 text-text-muted mx-auto" /><h2 className="text-xl font-semibold mb-2">Programa de Fidelidade Desativado</h2><p className="text-text-secondary mb-5">O programa de fidelidade está desativado. Ative-o para visualizar clientes e gerenciar recompensas.</p><Button onClick={toggleLoyalty} leftIcon={<FiToggleRight />}>Ativar Fidelidade</Button></Card>
            </div>
        );
    }

    return (
        <div className="max-w-[1200px] mx-auto">
            {/* Header */}
            <div className="flex items-start justify-between gap-5 mb-6 flex-wrap">
                <div><h1 className="text-[2rem] font-bold mb-2">Programa de Fidelidade</h1><p className="text-text-secondary">Gerencie seus clientes e recompensas</p></div>
                <div className="flex gap-2">
                    <button className={cn('flex items-center gap-2 px-4 py-2 bg-bg-tertiary border border-border rounded-md text-sm font-medium cursor-pointer transition-all duration-fast', rawAppSettings?.loyalty_enabled && 'bg-accent/10 border-accent text-accent')} onClick={toggleLoyalty}>{rawAppSettings?.loyalty_enabled ? <FiToggleRight /> : <FiToggleLeft />} Fidelidade</button>
                    <button className={cn('flex items-center gap-2 px-4 py-2 bg-bg-tertiary border border-border rounded-md text-sm font-medium cursor-pointer transition-all duration-fast', rawAppSettings?.coupons_enabled && 'bg-accent/10 border-accent text-accent')} onClick={toggleCoupons}>{rawAppSettings?.coupons_enabled ? <FiToggleRight /> : <FiToggleLeft />} Cupons</button>
                </div>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-4 gap-4 mb-6 max-md:grid-cols-2 max-[480px]:grid-cols-1">
                <Card className="flex items-center gap-4 p-5!"><FiUsers className="text-2xl text-primary" /><div className="flex flex-col"><span className="text-xl font-bold">{stats.totalCustomers}</span><span className="text-[0.8125rem] text-text-muted">Clientes</span></div></Card>
                <Card className="flex items-center gap-4 p-5!"><FiStar className="text-2xl text-[#f59e0b]" /><div className="flex flex-col"><span className="text-xl font-bold">{stats.totalPoints.toLocaleString()}</span><span className="text-[0.8125rem] text-text-muted">Pontos Totais</span></div></Card>
                <Card className="flex items-center gap-4 p-5!"><FiTrendingUp className="text-2xl text-[#10b981]" /><div className="flex flex-col"><span className="text-xl font-bold">{stats.avgPoints}</span><span className="text-[0.8125rem] text-text-muted">Média por Cliente</span></div></Card>
                <Card className="flex items-center gap-4 p-5!"><FiTag className="text-2xl text-[#8b5cf6]" /><div className="flex flex-col"><span className="text-xl font-bold">{formatCurrency(stats.totalSavings)}</span><span className="text-[0.8125rem] text-text-muted">Economias em Cupons</span></div></Card>
            </div>

            {/* Tabs */}
            <div className="flex gap-2 mb-6 border-b border-border pb-4">
                {[{ value: 'customers' as TabType, label: 'Clientes', icon: <FiUsers /> }, { value: 'rewards' as TabType, label: 'Recompensas', icon: <FiGift /> }, { value: 'settings' as TabType, label: 'Configurações', icon: <FiSettings /> }].map(tab => (
                    <button key={tab.value} className={cn('flex items-center gap-2 px-5 py-2.5 bg-transparent border border-border rounded-md text-text-secondary text-sm font-medium cursor-pointer transition-all duration-fast hover:bg-bg-tertiary', activeTab === tab.value && 'bg-primary border-primary text-white')} onClick={() => setActiveTab(tab.value)}>{tab.icon} {tab.label}</button>
                ))}
            </div>

            {/* Customers Tab */}
            {activeTab === 'customers' && (
                <Card>
                    <div className="flex items-center gap-2 mb-4 px-4 py-2 bg-bg-tertiary rounded-md"><FiSearch className="text-text-muted" /><input type="text" className="flex-1 bg-transparent border-none outline-none text-text-primary" placeholder="Buscar por nome ou telefone..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} /></div>
                    {loading ? <div className="p-12 text-center text-text-secondary">Carregando...</div> : filteredCustomers.length === 0 ? (
                        <div className="flex flex-col items-center p-12 text-center text-text-muted"><span className="text-5xl mb-4">👥</span><h3 className="text-lg font-semibold text-text-secondary mb-2">Nenhum cliente cadastrado</h3><p>Os clientes aparecerão aqui quando fizerem pedidos</p></div>
                    ) : (
                        <div className="flex flex-col">
                            {filteredCustomers.map((customer) => (
                                <div key={customer.id} className="flex items-center justify-between gap-4 p-4 border-b border-border last:border-b-0 max-md:flex-col max-md:items-start">
                                    <div className="flex items-center gap-3">
                                        <span className="w-10 h-10 flex items-center justify-center rounded-full text-lg" style={{ background: getTierColor(customer.total_points || 0) }}>{getTierIcon(customer.total_points || 0)}</span>
                                        <div className="flex flex-col"><span className="font-medium">{customer.name}</span><span className="text-sm text-text-muted">{customer.phone}</span></div>
                                    </div>
                                    <div className="flex items-center gap-6 flex-wrap max-md:gap-4">
                                        <div className="flex items-center gap-1 text-sm"><FiStar className="text-[#f59e0b]" /><span className="font-semibold">{customer.total_points || 0}</span><span className="text-text-muted">pts</span></div>
                                        <div className="flex items-center gap-1 text-sm"><FiShoppingBag className="text-primary" /><span className="font-semibold">{customer.total_orders || 0}</span><span className="text-text-muted">ped</span></div>
                                        <div className="flex items-center gap-1 text-sm"><FiDollarSign className="text-[#27ae60]" /><span className="font-semibold">{formatCurrency(customer.total_spent || 0)}</span></div>
                                        <div className="flex items-center gap-1 text-sm"><FiTag className="text-[#8b5cf6]" /><span className="font-semibold">0</span><span className="text-text-muted">cup</span></div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </Card>
            )}

            {/* Rewards Tab */}
            {activeTab === 'rewards' && (
                <Card>
                    <div className="flex justify-between items-center mb-6 pb-4 border-b border-border"><h2 className="text-lg font-semibold">Recompensas Disponíveis</h2><Button leftIcon={<FiPlus />} onClick={() => { resetRewardForm(); setEditingReward(null); setShowRewardModal(true); }}>Nova Recompensa</Button></div>
                    {(rawRewards || []).length === 0 ? (
                        <div className="flex flex-col items-center p-12 text-center text-text-muted"><span className="text-5xl mb-4">🎁</span><h3 className="text-lg font-semibold text-text-secondary mb-2">Nenhuma recompensa cadastrada</h3><p>Crie recompensas para seus clientes resgatarem</p></div>
                    ) : (
                        <div className="flex flex-col gap-3">
                            {(rawRewards || []).map((reward) => (
                                <div key={reward.id} className="flex items-center justify-between gap-4 p-4 bg-bg-tertiary rounded-md">
                                    <div className="flex items-center gap-4"><span className="text-3xl">🎁</span><div><h3 className="font-medium">{reward.name}</h3>{reward.description && <p className="text-sm text-text-muted">{reward.description}</p>}<div className="flex items-center gap-3 mt-1"><span className="flex items-center gap-1 text-xs text-primary font-medium"><FiStar /> {reward.points_cost} pts</span><span className="text-xs text-text-secondary">{reward.reward_type === 'discount_percent' && `${reward.reward_value}% off`}{reward.reward_type === 'discount_fixed' && `${formatCurrency(reward.reward_value || 0)} off`}{reward.reward_type === 'free_delivery' && 'Frete Grátis'}{reward.reward_type === 'free_product' && 'Produto Grátis'}</span></div></div></div>
                                    <div className="flex gap-2"><button className="p-2 bg-transparent border border-border rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:text-text-primary" onClick={() => openEditReward(reward)}><FiEdit2 /></button><button className="p-2 bg-transparent border border-border rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:text-error hover:border-error" onClick={() => handleDeleteReward(reward.id)}><FiTrash2 /></button></div>
                                </div>
                            ))}
                        </div>
                    )}
                </Card>
            )}

            {/* Settings Tab */}
            {activeTab === 'settings' && rawSettings && (
                <Card>
                    <h2 className="text-lg font-semibold mb-6 pb-4 border-b border-border">Configurações do Programa</h2>
                    <div className="grid grid-cols-3 gap-4 mb-6 max-md:grid-cols-1">
                        <div><label className="block text-sm text-text-secondary mb-2">Pontos por R$ 1,00 gasto</label><Input type="number" value={rawSettings.points_per_real} onChange={(e) => {
                            import('@/lib/db').then(() => {
                                db.loyalty_settings.update(rawSettings.id, { points_per_real: parseFloat(e.target.value) || 0 });
                            });
                        }} min={0} step={0.1} /></div>
                        <div><label className="block text-sm text-text-secondary mb-2">Mínimo de pontos para resgatar</label><Input type="number" value={rawSettings.min_points_to_redeem} onChange={(e) => {
                            import('@/lib/db').then(() => {
                                db.loyalty_settings.update(rawSettings.id, { min_points_to_redeem: parseInt(e.target.value) || 0 });
                            });
                        }} min={0} /></div>
                        <div><label className="block text-sm text-text-secondary mb-2">Expiração de pontos (dias)</label><Input type="number" value={rawSettings.points_expiry_days} onChange={(e) => {
                            import('@/lib/db').then(() => {
                                db.loyalty_settings.update(rawSettings.id, { points_expiry_days: parseInt(e.target.value) || 365 });
                            });
                        }} min={30} /></div>
                    </div>
                    <h3 className="text-base font-medium mb-4">Níveis de Fidelidade</h3>
                    <div className="grid grid-cols-4 gap-4 mb-6 max-md:grid-cols-2">
                        <div className="p-4 bg-bg-tertiary rounded-md text-center"><span className="text-2xl">🥉</span><div className="text-sm font-medium mt-1">Bronze</div><div className="text-xs text-text-muted">0 - {rawSettings.tier_silver_min - 1} pts</div><div className="text-xs text-text-muted">1x pontos</div></div>
                        
                        <div className="p-4 bg-bg-tertiary rounded-md text-center">
                            <span className="text-2xl">🥈</span>
                            <div className="text-sm font-medium mt-1">Silver</div>
                            <Input type="number" className="mt-1 text-center text-sm" value={rawSettings.tier_silver_min} onChange={(e) => {
                                import('@/lib/db').then(() => {
                                    db.loyalty_settings.update(rawSettings.id, { tier_silver_min: parseInt(e.target.value) || 0 });
                                });
                            }} />
                            <div className="text-xs text-text-muted">{rawSettings.silver_multiplier}x pts</div>
                        </div>

                        <div className="p-4 bg-bg-tertiary rounded-md text-center">
                            <span className="text-2xl">🥇</span>
                            <div className="text-sm font-medium mt-1">Gold</div>
                            <Input type="number" className="mt-1 text-center text-sm" value={rawSettings.tier_gold_min} onChange={(e) => {
                                import('@/lib/db').then(() => {
                                    db.loyalty_settings.update(rawSettings.id, { tier_gold_min: parseInt(e.target.value) || 0 });
                                });
                            }} />
                            <div className="text-xs text-text-muted">{rawSettings.gold_multiplier}x pts</div>
                        </div>

                        <div className="p-4 bg-bg-tertiary rounded-md text-center">
                            <span className="text-2xl">💎</span>
                            <div className="text-sm font-medium mt-1">Platinum</div>
                            <Input type="number" className="mt-1 text-center text-sm" value={rawSettings.tier_platinum_min} onChange={(e) => {
                                import('@/lib/db').then(() => {
                                    db.loyalty_settings.update(rawSettings.id, { tier_platinum_min: parseInt(e.target.value) || 0 });
                                });
                            }} />
                            <div className="text-xs text-text-muted">{rawSettings.platinum_multiplier}x pts</div>
                        </div>
                    </div>
                    <div className="flex justify-end"><Button onClick={handleSaveSettings}>Salvar Configurações</Button></div>
                </Card>
            )}

            {/* Reward Modal */}
            {showRewardModal && (
                <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-1000 p-4" onClick={() => setShowRewardModal(false)}>
                    <div className="bg-bg-card border border-border rounded-lg p-6 w-full max-w-[500px] max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
                        <h2 className="text-xl font-semibold mb-6">{editingReward ? 'Editar Recompensa' : 'Nova Recompensa'}</h2>
                        <div className="mb-4"><label className="block text-sm text-text-secondary mb-2">Nome da Recompensa</label><Input value={rewardForm.name} onChange={(e) => setRewardForm({ ...rewardForm, name: e.target.value })} placeholder="Ex: 10% de desconto" /></div>
                        <div className="mb-4"><label className="block text-sm text-text-secondary mb-2">Descrição (opcional)</label><Input value={rewardForm.description} onChange={(e) => setRewardForm({ ...rewardForm, description: e.target.value })} placeholder="Descrição da recompensa" /></div>
                        <div className="grid grid-cols-2 gap-4 mb-4">
                            <div><label className="block text-sm text-text-secondary mb-2">Custo em Pontos</label><Input type="number" value={rewardForm.points_cost} onChange={(e) => setRewardForm({ ...rewardForm, points_cost: parseInt(e.target.value) || 0 })} min={1} /></div>
                            <div><label className="block text-sm text-text-secondary mb-2">Pedido Mínimo</label><Input type="number" value={rewardForm.min_order_value} onChange={(e) => setRewardForm({ ...rewardForm, min_order_value: parseFloat(e.target.value) || 0 })} min={0} step={0.01} /></div>
                        </div>
                        <div className="mb-4"><label className="block text-sm text-text-secondary mb-2">Tipo de Recompensa</label><select value={rewardForm.reward_type} onChange={(e) => setRewardForm({ ...rewardForm, reward_type: e.target.value as LoyaltyReward['reward_type'] })} className="w-full px-4 py-3 bg-bg-tertiary border border-border rounded-md text-text-primary"><option value="discount_percent">Desconto Percentual</option><option value="discount_fixed">Desconto Fixo (R$)</option><option value="free_delivery">Entrega Grátis</option><option value="free_product">Produto Grátis</option></select></div>
                        {(rewardForm.reward_type === 'discount_percent' || rewardForm.reward_type === 'discount_fixed') && <div className="mb-4"><label className="block text-sm text-text-secondary mb-2">{rewardForm.reward_type === 'discount_percent' ? 'Porcentagem de Desconto' : 'Valor do Desconto (R$)'}</label><Input type="number" value={rewardForm.reward_value} onChange={(e) => setRewardForm({ ...rewardForm, reward_value: parseFloat(e.target.value) || 0 })} min={0} step={rewardForm.reward_type === 'discount_percent' ? 1 : 0.01} /></div>}
                        <div className="flex gap-3 justify-end mt-6 pt-4 border-t border-border"><Button variant="ghost" onClick={() => setShowRewardModal(false)}>Cancelar</Button><Button onClick={handleSaveReward}>{editingReward ? 'Salvar' : 'Criar Recompensa'}</Button></div>
                    </div>
                </div>
            )}
        </div>
    );
}

