'use client';

import React, { useState, useEffect } from 'react';
import { FiCopy, FiCheck, FiRefreshCw } from 'react-icons/fi';
import Image from 'next/image';
import { generatePixQRCode, generatePixCode, PixPayload } from '@/lib/pix';
import { formatCurrency } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';

interface PixQRCodeProps {
    pixKey: string;
    pixKeyType: PixPayload['pixKeyType'];
    merchantName: string;
    merchantCity: string;
    amount: number;
    orderId?: string | number;
    onPaymentConfirmed?: () => void;
}

export default function PixQRCode({
    pixKey,
    pixKeyType,
    merchantName,
    merchantCity,
    amount,
    orderId,
    onPaymentConfirmed
}: PixQRCodeProps) {
    const [qrCodeUrl, setQrCodeUrl] = useState<string>('');
    const [pixCode, setPixCode] = useState<string>('');
    const [copied, setCopied] = useState(false);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const payload: PixPayload = {
        pixKey,
        pixKeyType,
        merchantName,
        merchantCity,
        amount,
        txId: orderId ? `PED${orderId}` : undefined
    };

    useEffect(() => {
        generateQRCode();
    }, [pixKey, amount, orderId]);

    const generateQRCode = async () => {
        if (!pixKey) {
            setError('Chave PIX não configurada');
            setLoading(false);
            return;
        }

        setLoading(true);
        setError(null);

        try {
            const code = generatePixCode(payload);
            setPixCode(code);

            const qrUrl = await generatePixQRCode(payload);
            setQrCodeUrl(qrUrl);
        } catch (err) {
            setError('Erro ao gerar QR Code');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const copyToClipboard = async () => {
        try {
            await navigator.clipboard.writeText(pixCode);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        } catch (err) {
            console.error('Failed to copy:', err);
        }
    };



    if (error) {
        return (
