                                copied && 'bg-accent'
                            )}
                            onClick={copyToClipboard}
                        >
                            {copied ? (
                                <>
                                    <FiCheck /> Copiado!
                                </>
                            ) : (
                                <>
                                    <FiCopy /> Copiar código
