'use client';

import React, { useCallback } from 'react';
import { FiBell, FiBellOff } from 'react-icons/fi';
import { usePushNotifications } from '@/hooks/usePushNotifications';
import { useAuth } from '@/contexts/AuthContext';
import toast from 'react-hot-toast';
import { cn } from '@/lib/utils';

interface PushNotificationPromptProps {
    collapsed?: boolean;
}

export function PushNotificationPrompt({ collapsed = false }: PushNotificationPromptProps) {
    const { isSupported, isSubscribed, loading, subscribe, unsubscribe } = usePushNotifications();
    const { user } = useAuth();

    const handleToggle = useCallback(async () => {
        if (loading) return;

        if (isSubscribed) {
            const success = await unsubscribe();
            if (success) {
                toast.success('Notificações desativadas.');
            } else {
                toast.error('Erro ao desativar notificações.');
            }
        } else {
            const success = await subscribe();
            if (success) {
                toast.success('🔔 Notificações ativadas com sucesso!');
                // Enviar notificação de teste automaticamente ao ativar
                if (user?.id) {
                    setTimeout(async () => {
                        try {
                            const res = await fetch(`/api/push/test?userId=${user.id}`);
                            const data = await res.json();
                            console.log('[Push] Teste enviado:', data);
                            if (data.sent === 0) {
                                toast('Nenhuma subscription encontrada. Tente recarregar a página.', { icon: '⚠️' });
                            }
                        } catch (e) {
                            console.error('[Push] Erro no teste:', e);
                        }
                    }, 1500);
                }
            } else {
                if (typeof Notification !== 'undefined' && Notification.permission === 'denied') {
                    toast.error('Permissão negada. Ative nas configurações do navegador.');
                } else {
                    toast.error('Não foi possível ativar as notificações.');
                }
            }
        }
    }, [loading, isSubscribed, subscribe, unsubscribe, user?.id]);

    const handleTest = useCallback(async () => {
        if (!user?.id) {
            toast.error('Usuário não autenticado.');
            return;
        }
        try {
            toast.loading('Enviando teste...', { id: 'push-test' });
            const res = await fetch(`/api/push/test?userId=${user.id}`);
            const data = await res.json();
            console.log('[Push Test] Resposta:', data);

            if (data.sent > 0) {
                toast.success(`Notificação enviada! (${data.sent} dispositivo(s))`, { id: 'push-test' });
            } else if (data.failed > 0) {
                toast.error(`Falha ao enviar. ${data.cleaned} subscriptions expiradas removidas.`, { id: 'push-test' });
            } else {
                toast.error('Nenhuma subscription encontrada. Desative e ative novamente.', { id: 'push-test' });
            }
        } catch (e) {
            console.error('[Push Test] Erro:', e);
            toast.error('Erro ao enviar teste.', { id: 'push-test' });
        }
    }, [user?.id]);

    // Não renderiza se o navegador não suporta push notifications
    if (!isSupported) return null;

    return (
        <div className="flex flex-col gap-0.5">
            <button
                onClick={handleToggle}
                disabled={loading}
                title={isSubscribed ? 'Desativar notificações' : 'Ativar notificações push'}
                className={cn(
                    'relative flex items-center gap-3 px-4 py-3 rounded-xl text-text-secondary no-underline transition-colors duration-fast cursor-pointer border-none bg-transparent w-full text-[0.9375rem]',
                    'hover:bg-bg-tertiary hover:text-text-primary',
                    isSubscribed && 'text-primary',
                    loading && 'opacity-50 cursor-not-allowed',
                    collapsed && 'justify-center px-3.5'
                )}
            >
                {isSubscribed ? (
                    <FiBell className="text-xl shrink-0" />
                ) : (
                    <FiBellOff className="text-xl shrink-0" />
                )}
                {!collapsed && (
                    <span className="whitespace-nowrap overflow-hidden">
                        {loading ? 'Processando...' : isSubscribed ? 'Notificações' : 'Ativar Alertas'}
                    </span>
                )}
                {/* Indicador de status */}
                {isSubscribed && !collapsed && (
                    <span className="ml-auto w-2 h-2 rounded-full bg-green-500 shrink-0" />
                )}
            </button>

            {/* Botão de teste - aparece apenas quando inscrito */}
            {isSubscribed && !collapsed && (
                <button
                    onClick={handleTest}
                    className="flex items-center gap-2 px-4 py-1.5 ml-2 rounded-lg text-xs text-text-muted hover:text-text-primary hover:bg-bg-tertiary transition-colors border-none bg-transparent cursor-pointer"
                    title="Enviar notificação de teste"
                >
                    <span>🧪</span>
                    <span>Testar notificação</span>
                </button>
            )}
        </div>
    );
}

import React from 'react';
import { Document, Page, Text, View, StyleSheet, Font } from '@react-pdf/renderer';

// Interface defining the structure of the report data
export interface ReportData {
    businessName?: string;
    periodoSelecionado: string;
    secoes: {
        titulo: string;
        tipo: 'kpi' | 'tabela' | 'lista';
        dados: any[];
        colunas?: { header: string; key: string; width?: string }[];
    }[];
    comparacao?: {
        periodo: string;
        dados: any;
    };
}

// Dark Theme - Polished
const theme = {
    colors: {
        background: '#0F1115',
        text: '#FFFFFF',
        secondary: '#A1A1AA',
        accent: '#FF6600', // Preserved for brand touch
        border: '#27272A',
        surface: '#18181B', // Slightly lighter for headers?
    },
    spacing: {
        sm: 10,
        md: 20,
        lg: 40,
    },
    fonts: {
        bold: 'Helvetica-Bold',
        regular: 'Helvetica',
        italic: 'Helvetica-Oblique',
    },
};

const styles = StyleSheet.create({
    page: {
        flexDirection: 'column',
        backgroundColor: theme.colors.background,
        padding: theme.spacing.lg,
        fontFamily: theme.fonts.regular,
        fontSize: 11,
        color: theme.colors.text,
        lineHeight: 1.5,
    },
    // Brand Line
    brandLine: {
        height: 4,
        backgroundColor: theme.colors.accent,
        marginBottom: 30,
        width: 60,
    },
    // Header
    headerRow: {
        flexDirection: 'row',
        justifyContent: 'flex-start', // Changed from space-between
        alignItems: 'center',
        marginBottom: 30, // Reduced margin
        height: 'auto', // Auto height instead of fixed 100
        borderBottomWidth: 1,
        borderBottomColor: theme.colors.border,
        paddingBottom: 20,
    },
    headerContent: {
        flexDirection: 'column',
    },
    h1: {
        fontSize: 22, // Larger
        fontFamily: theme.fonts.bold,
        textTransform: 'uppercase',
        color: theme.colors.text,
        marginBottom: 8,
        letterSpacing: 0.5,
    },
    subtitle: {
        fontSize: 12,
        fontFamily: theme.fonts.regular,
        color: theme.colors.secondary,
        textTransform: 'uppercase'
    },

    // Sections
    section: {
        marginBottom: 35,
    },
    sectionTitle: {
        fontSize: 13,
        fontFamily: theme.fonts.bold,
        color: theme.colors.accent, // Accent color for section headers
        marginBottom: 15,
        textTransform: 'uppercase',
        letterSpacing: 1,
    },

    // Metric Rows
    metricRow: {
        flexDirection: 'row',
        justifyContent: 'space-between',
        alignItems: 'center',
        paddingVertical: 10,
        borderBottomWidth: 1,
        borderBottomColor: theme.colors.border,
    },
    metricLabel: {
        fontSize: 11,
        color: theme.colors.secondary,
    },
    metricValue: {
        fontSize: 11,
        fontFamily: theme.fonts.bold,
        color: theme.colors.text,
    },

    // Table Header
    tableHeader: {
        flexDirection: 'row',
        justifyContent: 'space-between',
        paddingBottom: 8,
        borderBottomWidth: 1,
        borderBottomColor: theme.colors.border,
        marginBottom: 0,
    },
    tableHeaderLabel: {
        fontSize: 10,
        fontFamily: theme.fonts.bold,
        color: theme.colors.secondary,
        textTransform: 'uppercase',
    },

    // Lists
    listItem: {
        flexDirection: 'row',
        marginBottom: 8,
        alignItems: 'center',
    },
    bullet: {
        width: 4,
        height: 4,
        backgroundColor: theme.colors.accent, // Orange bullet
        borderRadius: 2,
        marginRight: 10,
    },
    listText: {
        fontSize: 11,
        color: theme.colors.text,
    },
});

const MetricRows = ({ data }: { data: any[] }) => (
    <View>
        <View style={styles.tableHeader}>
            <Text style={styles.tableHeaderLabel}>Métrica</Text>
            <Text style={styles.tableHeaderLabel}>Valor</Text>
        </View>

        {data.map((item, index) => (
            <View key={index} style={styles.metricRow}>
                <Text style={styles.metricLabel}>{item.label || item.produto || 'Item'}</Text>
                <Text style={styles.metricValue}>{item.value || item.total || '-'}</Text>
            </View>
        ))}
    </View>
);

const GenericTable = ({ data, columns }: { data: any[]; columns?: any[] }) => {
    const cols = columns || (data.length > 0 ? Object.keys(data[0]).map(key => ({ header: key, key })) : []);

    return (
        <View>
            <View style={styles.tableHeader}>
                {cols.map((col, i) => (
                    <Text key={i} style={[styles.tableHeaderLabel, col.width ? { flexBasis: col.width } : { flex: 1, textAlign: i === cols.length - 1 ? 'right' : 'left' }]}>
                        {col.header}
                    </Text>
                ))}
            </View>
            {data.map((row, rowIndex) => (
                <View key={rowIndex} style={styles.metricRow}>
                    {cols.map((col, colIndex) => (
                        <Text key={colIndex} style={[
                            colIndex === 0 ? styles.metricLabel : styles.metricValue,
                            col.width ? { flexBasis: col.width } : { flex: 1, textAlign: colIndex === cols.length - 1 ? 'right' : 'left' }
                        ]}>
                            {String(row[col.key] || '')}
                        </Text>
                    ))}
                </View>
            ))}
        </View>
    );
};

const BulletList = ({ data }: { data: any[] }) => (
    <View>
        {data.map((item, index) => (
            <View key={index} style={styles.listItem}>
                <View style={styles.bullet} />
                <Text style={styles.listText}>
                    {typeof item === 'string' ? item : (item.label ? `${item.label}: ${item.value}` : JSON.stringify(item))}
                </Text>
            </View>
        ))}
    </View>
);

const RelatorioPDFCompleto: React.FC<{ reportData: ReportData }> = ({ reportData }) => {
    return (
        <Document>
            <Page size="A4" style={styles.page}>

                {/* Decorative Brand Line */}
                <View style={styles.brandLine} />

                {/* Header Block with Logo */}
                <View style={styles.headerRow}>
                    <View style={styles.headerContent}>
                        <Text style={styles.h1}>RELATÓRIO MENSAL</Text>
                        <Text style={styles.subtitle}>
                            {reportData.businessName || 'SEU NEGÓCIO'} • {reportData.periodoSelecionado.replace('Este Mês (', '').replace(')', '')}
                        </Text>
                    </View>
                </View>

                {/* Dynamic Content */}
                {reportData.secoes.map((secao, index) => (
                    <View key={index} style={styles.section}>

                        {secao.titulo && <Text style={styles.sectionTitle}>{secao.titulo}</Text>}

                        {secao.tipo === 'kpi' && <MetricRows data={secao.dados} />}
                        {secao.tipo === 'tabela' && <GenericTable data={secao.dados} columns={secao.colunas} />}
                        {secao.tipo === 'lista' && <BulletList data={secao.dados} />}

                    </View>
                ))}

                {/* Footer */}
                <View style={{ position: 'absolute', bottom: 30, left: 40, right: 40, borderTopWidth: 1, borderTopColor: '#27272A', paddingTop: 10, flexDirection: 'row', justifyContent: 'space-between' }} fixed>
                    <Text style={{ fontSize: 9, color: '#555' }}>
                        Gerado em {new Date().toLocaleDateString('pt-BR')} por {reportData.businessName}
                    </Text>
                    <Text style={{ fontSize: 9, color: '#555' }} render={({ pageNumber, totalPages }) => (
                        `${pageNumber} / ${totalPages}`
                    )} />
                </View>

            </Page>
        </Document>
    );
};

export default RelatorioPDFCompleto;

