'use client';

import React, { createContext, useContext, useEffect, useState, ReactNode, useCallback, useMemo } from 'react';
import { useRouter } from 'next/navigation';

interface Shortcut {
    key: string;
    ctrl?: boolean;
    alt?: boolean;
    shift?: boolean;
    description: string;
    action: () => void;
    scope?: 'global' | 'page';
}

interface KeyboardShortcutsContextType {
    shortcuts: Shortcut[];
    registerShortcut: (shortcut: Shortcut) => void;
    unregisterShortcut: (key: string, ctrl?: boolean, alt?: boolean, shift?: boolean) => void;
    showHelp: boolean;
    setShowHelp: (show: boolean) => void;
}

const KeyboardShortcutsContext = createContext<KeyboardShortcutsContextType | undefined>(undefined);

export function KeyboardShortcutsProvider({ children }: { children: ReactNode }) {
    const router = useRouter();
    const [shortcuts, setShortcuts] = useState<Shortcut[]>([]);
    const [showHelp, setShowHelp] = useState(false);

    // Build global shortcuts with router actions
    useEffect(() => {
        const baseShortcuts: Shortcut[] = [
            { key: 'h', alt: true, description: 'Ir para Dashboard', action: () => router.push('/dashboard'), scope: 'global' },
            { key: 'p', alt: true, description: 'Ir para Pedidos', action: () => router.push('/pedidos'), scope: 'global' },
            { key: 'g', alt: true, description: 'Ir para Produtos', action: () => router.push('/produtos'), scope: 'global' },
            { key: 'a', alt: true, description: 'Ir para Adicionais', action: () => router.push('/adicionais'), scope: 'global' },
            { key: 't', alt: true, description: 'Ir para Categorias', action: () => router.push('/categorias'), scope: 'global' },
            { key: 'c', alt: true, description: 'Ir para Cozinha', action: () => router.push('/cozinha'), scope: 'global' },
            { key: 'd', alt: true, description: 'Ir para Entregas', action: () => router.push('/entregas'), scope: 'global' },
            { key: 'e', alt: true, description: 'Ir para Estoque', action: () => router.push('/estoque'), scope: 'global' },
            { key: 'u', alt: true, description: 'Ir para Cupons', action: () => router.push('/cupons'), scope: 'global' },
            { key: 'f', alt: true, description: 'Ir para Fidelidade', action: () => router.push('/fidelidade'), scope: 'global' },
            { key: 'x', alt: true, description: 'Ir para Caixa', action: () => router.push('/caixa'), scope: 'global' },
            { key: 'b', alt: true, description: 'Ir para Contas', action: () => router.push('/contas'), scope: 'global' },
            { key: 'm', alt: true, description: 'Ir para Fluxo de Caixa', action: () => router.push('/fluxo-caixa'), scope: 'global' },
            { key: 's', alt: true, description: 'Ir para Funcionários', action: () => router.push('/funcionarios'), scope: 'global' },
            { key: 'r', alt: true, description: 'Ir para Relatórios', action: () => router.push('/relatorios'), scope: 'global' },
            { key: 'i', alt: true, description: 'Ir para Histórico', action: () => router.push('/historico'), scope: 'global' },
            { key: 'q', alt: true, description: 'Ir para Assinatura', action: () => router.push('/assinatura'), scope: 'global' },
            { key: ',', alt: true, description: 'Ir para Configurações', action: () => router.push('/configuracoes'), scope: 'global' },
            { key: 'n', alt: true, description: 'Novo Pedido', action: () => router.push('/pedidos/novo'), scope: 'global' },
            { key: '/', ctrl: true, description: 'Mostrar Atalhos', action: () => setShowHelp(prev => !prev), scope: 'global' },
            { key: 'Escape', description: 'Fechar Modal/Menu', action: () => setShowHelp(false), scope: 'global' },
        ];
        setShortcuts(baseShortcuts);
    }, [router]);

    const registerShortcut = useCallback((shortcut: Shortcut) => {
        setShortcuts(prev => {
            // Remove existing shortcut with same key combination
            const filtered = prev.filter(s =>
                !(s.key === shortcut.key && s.ctrl === shortcut.ctrl && s.alt === shortcut.alt && s.shift === shortcut.shift)
            );
            return [...filtered, shortcut];
        });
    }, []);

    const unregisterShortcut = useCallback((key: string, ctrl?: boolean, alt?: boolean, shift?: boolean) => {
        setShortcuts(prev =>
            prev.filter(s => !(s.key === key && s.ctrl === ctrl && s.alt === alt && s.shift === shift))
        );
    }, []);

    // Create a Map for O(1) shortcut lookup instead of O(n) find
    const shortcutMap = useMemo(() => {
        const map = new Map<string, Shortcut>();
        shortcuts.forEach(s => {
            // Create composite key: "key-ctrl-alt-shift"
            const compositeKey = `${s.key.toLowerCase()}-${!!s.ctrl}-${!!s.alt}-${!!s.shift}`;
            map.set(compositeKey, s);
        });
        return map;
    }, [shortcuts]);

    // Handle keyboard events - O(1) lookup
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            // Don't trigger shortcuts when typing in inputs
            const target = e.target as HTMLElement;
            if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) {
                // Allow Escape to still work
                if (e.key !== 'Escape') return;
            }

            // O(1) lookup using Map with composite key
            const compositeKey = `${e.key.toLowerCase()}-${e.ctrlKey || e.metaKey}-${e.altKey}-${e.shiftKey}`;
            const matchingShortcut = shortcutMap.get(compositeKey);

            if (matchingShortcut) {
                e.preventDefault();
                matchingShortcut.action();
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [shortcutMap]);

    return (
        <KeyboardShortcutsContext.Provider value={{
            shortcuts,
            registerShortcut,
            unregisterShortcut,
            showHelp,
            setShowHelp
        }}>
            {children}
            {showHelp && <ShortcutsHelp onClose={() => setShowHelp(false)} shortcuts={shortcuts} />}
        </KeyboardShortcutsContext.Provider>
    );
}

// Shortcuts Help Modal
function ShortcutsHelp({ onClose, shortcuts }: { onClose: () => void; shortcuts: Shortcut[] }) {
    const globalShortcuts = shortcuts.filter(s => s.scope === 'global');
    const pageShortcuts = shortcuts.filter(s => s.scope === 'page');

    const formatKey = (shortcut: Shortcut) => {
        const keys = [];
        if (shortcut.ctrl) keys.push('Ctrl');
        if (shortcut.alt) keys.push('Alt');
        if (shortcut.shift) keys.push('Shift');
        keys.push(shortcut.key === ' ' ? 'Space' : shortcut.key.toUpperCase());
        return keys.join(' + ');
    };

    return (
        <div className="shortcuts-overlay" onClick={onClose}>
            <div className="shortcuts-modal" onClick={e => e.stopPropagation()}>
                <h2>⌨️ Atalhos de Teclado</h2>

                <div className="shortcuts-section">
                    <h3>Navegação Global</h3>
                    <div className="shortcuts-list">
                        {globalShortcuts.map((s, i) => (
                            <div key={i} className="shortcut-item">
                                <kbd>{formatKey(s)}</kbd>
                                <span>{s.description}</span>
                            </div>
                        ))}
                    </div>
                </div>

                {pageShortcuts.length > 0 && (
                    <div className="shortcuts-section">
                        <h3>Atalhos da Página</h3>
                        <div className="shortcuts-list">
                            {pageShortcuts.map((s, i) => (
                                <div key={i} className="shortcut-item">
                                    <kbd>{formatKey(s)}</kbd>
                                    <span>{s.description}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                <div className="shortcuts-footer">
                    <span>Pressione <kbd>Ctrl + /</kbd> para mostrar/esconder</span>
                    <button onClick={onClose}>Fechar</button>
                </div>
            </div>

            <style jsx>{`
                .shortcuts-overlay {
                    position: fixed;
                    top: 0;
                    left: 0;
                    right: 0;
                    bottom: 0;
                    background: rgba(0, 0, 0, 0.7);
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    z-index: 10000;
                    backdrop-filter: blur(4px);
                }

                .shortcuts-modal {
                    background: var(--bg-card);
                    border: 1px solid var(--border-color);
                    border-radius: var(--radius-lg);
                    padding: 24px;
                    max-width: 500px;
                    width: 90%;
                    max-height: 80vh;
                    overflow-y: auto;
                    animation: slideIn 0.2s ease;
                }

                @keyframes slideIn {
                    from {
                        opacity: 0;
                        transform: translateY(-20px);
                    }
                    to {
                        opacity: 1;
                        transform: translateY(0);
                    }
                }

                h2 {
                    font-size: 1.25rem;
                    font-weight: 600;
                    margin: 0 0 20px 0;
                    color: var(--text-primary);
                }

                .shortcuts-section {
                    margin-bottom: 20px;
                }

                h3 {
                    font-size: 0.8125rem;
                    font-weight: 600;
                    color: var(--text-secondary);
                    text-transform: uppercase;
                    letter-spacing: 0.5px;
                    margin: 0 0 12px 0;
                }

                .shortcuts-list {
                    display: flex;
                    flex-direction: column;
                    gap: 8px;
                }

                .shortcut-item {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    padding: 8px 12px;
                    background: var(--bg-tertiary);
                    border-radius: var(--radius-sm);
                }

                .shortcut-item span {
                    color: var(--text-primary);
                    font-size: 0.875rem;
                }

                kbd {
                    display: inline-flex;
                    align-items: center;
                    gap: 4px;
                    padding: 4px 8px;
                    background: var(--bg-secondary);
                    border: 1px solid var(--border-color);
                    border-radius: 4px;
                    font-family: monospace;
                    font-size: 0.75rem;
                    font-weight: 600;
                    color: var(--primary);
                    min-width: 24px;
                    justify-content: center;
                }

                .shortcuts-footer {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    padding-top: 16px;
                    border-top: 1px solid var(--border-color);
                    margin-top: 8px;
                }

                .shortcuts-footer span {
                    font-size: 0.8125rem;
                    color: var(--text-muted);
                }

                .shortcuts-footer kbd {
                    font-size: 0.6875rem;
                    padding: 2px 6px;
                }

                .shortcuts-footer button {
                    padding: 8px 16px;
                    background: var(--primary);
                    color: white;
                    border: none;
                    border-radius: var(--radius-md);
                    font-size: 0.875rem;
                    font-weight: 500;
                    cursor: pointer;
                    transition: opacity 0.2s;
                }

                .shortcuts-footer button:hover {
                    opacity: 0.9;
                }
            `}</style>
        </div>
    );
}

export function useKeyboardShortcuts() {
    const context = useContext(KeyboardShortcutsContext);
    if (context === undefined) {
        throw new Error('useKeyboardShortcuts must be used within a KeyboardShortcutsProvider');
    }
    return context;
}

// Hook to register page-specific shortcuts
export function usePageShortcut(shortcut: Omit<Shortcut, 'scope'>) {
    const { registerShortcut, unregisterShortcut } = useKeyboardShortcuts();

    useEffect(() => {
        registerShortcut({ ...shortcut, scope: 'page' });
        return () => unregisterShortcut(shortcut.key, shortcut.ctrl, shortcut.alt, shortcut.shift);
    }, [shortcut, registerShortcut, unregisterShortcut]);
}

'use client';

import React, { createContext, useContext, useEffect, useCallback, ReactNode } from 'react';
import { initOfflineDB, onNetworkChange, isOnline, getPendingActions, checkConnectivity } from '@/lib/offlineStorage';
import { syncPendingActions, cacheDataForOffline, updateLastSync } from '@/lib/offlineSync';
import { useStorageStore, type StorageMode } from '@/stores/useStorageStore';
import { useAuth } from './AuthContext';
import toast from 'react-hot-toast';

export type { StorageMode };

interface OfflineContextType {
    hardwareOnline: boolean;     // Se o dispositivo tem internet física
    storageMode: StorageMode;    // Se o usuário escolheu forçar local
    setStorageMode: (mode: StorageMode) => void;
    isEffectivelyOnline: boolean; // hardwareOnline === true e storageMode === 'cloud'

    pendingCount: number;
    syncing: boolean;
    lastSync: string | null;
    syncNow: () => Promise<void>;
    refreshCache: () => Promise<void>;
}

const OfflineContext = createContext<OfflineContextType | undefined>(undefined);

export function OfflineProvider({ children }: { children: ReactNode }) {
    const { user } = useAuth();

    // ─── Estado vindo do Zustand ─────────────────────
    const hardwareOnline = useStorageStore((s) => s.hardwareOnline);
    const storageMode = useStorageStore((s) => s.storageMode);
    const pendingCount = useStorageStore((s) => s.pendingChangesCount);
    const syncing = useStorageStore((s) => s.syncing);
    const lastSync = useStorageStore((s) => s.lastSyncedAt);

    const setStorageMode = useStorageStore((s) => s.setStorageMode);
    const setHardwareOnline = useStorageStore((s) => s.setHardwareOnline);
    const setSyncing = useStorageStore((s) => s.setSyncing);

    const isEffectivelyOnline = hardwareOnline && storageMode === 'cloud';

    const updatePendingCount = useCallback(async () => {
        try {
            const actions = await getPendingActions();
            useStorageStore.setState({ pendingChangesCount: actions.length });
        } catch {
            // Silently fail if DB not ready
        }
    }, []);

    const syncNow = useCallback(async () => {
        // Só sync se houver internet de fato
        if (!hardwareOnline || syncing) return;

        setSyncing(true);
        try {
            const result = await syncPendingActions();
            if (result.synced > 0) {
                updateLastSync();
                toast.success(`${result.synced} itens sincronizados com a nuvem!`);
            }
            if (result.failed > 0) {
                toast.error(`Falha ao sincronizar ${result.failed} itens.`);
            }

            await updatePendingCount();

            // Note: cacheDataForOffline has its own 5-min cooldown guard,
            // so calling it here won't cause redundant fetches
        } catch (error) {
            console.error('[Offline] Sync failed:', error);
            toast.error('Erro ao sincronizar com servidor.');
        }
        setSyncing(false);
    }, [hardwareOnline, syncing, user, isEffectivelyOnline, updatePendingCount, setSyncing]);

    const refreshCache = useCallback(async () => {
        if (!isEffectivelyOnline || !user) return;
        await cacheDataForOffline(user.id);
    }, [isEffectivelyOnline, user]);

    // Initialize IndexedDB and check status
    useEffect(() => {
        const init = async () => {
            try {
                await initOfflineDB();
            } catch {
                // DB init may fail on very first SSR render attempt
            }
            // Use robust async check
            const isOnlineNow = await checkConnectivity();
            setHardwareOnline(isOnlineNow);
            await updatePendingCount();

            // Restore lastSync from localStorage for backward compat
            if (typeof window !== 'undefined') {
                const saved = localStorage.getItem('lastSync');
                if (saved && !lastSync) {
                    useStorageStore.getState().setLastSyncedAt(saved);
                }
            }
        };
        init();
    }, [updatePendingCount, setHardwareOnline, lastSync]);

    // Listen for online/offline events
    useEffect(() => {
        const unsubscribe = onNetworkChange(async (isOnlineNow) => {
            setHardwareOnline(isOnlineNow);
            if (isOnlineNow && storageMode === 'cloud' && user) {
                // Auto-sync when coming back online in cloud mode
                await syncNow();
            }
        });
        return unsubscribe;
    }, [user, syncNow, storageMode, setHardwareOnline]);

    // Cache data when user logs in and is online
    useEffect(() => {
        if (user && isEffectivelyOnline) {
            cacheDataForOffline(user.id);
        }
    }, [user, isEffectivelyOnline]);

    return (
        <OfflineContext.Provider value={{
            hardwareOnline,
            storageMode,
            setStorageMode,
            isEffectivelyOnline,
            pendingCount,
            syncing,
            lastSync,
            syncNow,
            refreshCache
        }}>
            {children}
        </OfflineContext.Provider>
    );
}

export function useOffline() {
    const context = useContext(OfflineContext);
    if (!context) {
        throw new Error('useOffline must be used within OfflineProvider');
    }
    return context;
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { getFingerprint, generateFingerprint, FingerprintData } from '@/lib/fingerprint';

interface UseFingerprint {
    fingerprint: string | null;
    loading: boolean;
    error: string | null;
    fullData: FingerprintData | null;
    refresh: () => Promise<void>;
}

/**
 * Hook para coleta de fingerprint do navegador
 * Usado para prevenção de fraude no sistema de trial
 */
export function useFingerprint(): UseFingerprint {
    const [fingerprint, setFingerprint] = useState<string | null>(null);
    const [fullData, setFullData] = useState<FingerprintData | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const collectFingerprint = useCallback(async () => {
        try {
            setLoading(true);
            setError(null);

            // Coleta fingerprint completo
            const data = await generateFingerprint();
            setFingerprint(data.hash);
            setFullData(data);
        } catch (err) {
            console.error('[Fingerprint] Error collecting:', err);
            setError('Erro ao coletar informações do dispositivo');
            // Gera fallback básico
            setFingerprint(`fallback-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        collectFingerprint();
    }, [collectFingerprint]);

    const refresh = useCallback(async () => {
        await collectFingerprint();
    }, [collectFingerprint]);

    return {
        fingerprint,
        loading,
        error,
        fullData,
        refresh,
    };
}

export default useFingerprint;
